-- Poems batch 141
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b8bbcc38-7ded-4896-beac-67ccd4fba2af','風回二絕句  其二','項安世','宋','宋诗','song-poetry','','[]','纜作野叉浮水面，矴如狸爪下船頭。',32,'全唐诗/poet.song.147000.json','["纜作野叉浮水面，矴如狸爪下船頭。", "長年笑語歸船去，卧聽顛風更不愁。"]'),
('cc042bbc-8298-4b02-973b-d4b303242e4f','二十七日衡陽義宰以奚奴墨梅侑客','項安世','宋','宋诗','song-poetry','','[]','鐵石心腸宋廣平，賦含脂粉太多情。',32,'全唐诗/poet.song.147000.json','["鐵石心腸宋廣平，賦含脂粉太多情。", "固應却有柔荑手，淡拂橫枝徹骨清。"]'),
('3df200e2-4012-498d-8af7-85789dd300af','晚自嶽麓歸','項安世','宋','宋诗','song-poetry','','[]','千張綠錦變明青，嶽麓峰前暝靄生。',32,'全唐诗/poet.song.147000.json','["千張綠錦變明青，嶽麓峰前暝靄生。", "萬頃玻璃成瑪瑙，瀟湘江上夕陽明。"]'),
('e6164c23-2cd7-453a-a527-68113fcd3e15','送都大茶馬入覲八絕句  其一','項安世','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','六月長江白水秋，夜寒銀漢入江流。',32,'全唐诗/poet.song.147000.json','["六月長江白水秋，夜寒銀漢入江流。", "台星直下穿雲夢，知是西來使者舟。"]'),
('796e324c-dcec-4e70-9cd4-9e4fe6803bf5','送都大茶馬入覲八絕句  其二','項安世','宋','宋诗','song-poetry','','[]','使者東南甲第開，日邊雲氣近蓬萊。',32,'全唐诗/poet.song.147000.json','["使者東南甲第開，日邊雲氣近蓬萊。", "要令二□知名字，故遣窮邊萬里回。"]'),
('c1c793ee-59a9-4d46-a684-4d16c0f3d3f8','送都大茶馬入覲八絕句  其三','項安世','宋','宋诗','song-poetry','','[]','橫絕乾坤作四封，秦川馬驛與天通。',32,'全唐诗/poet.song.147000.json','["橫絕乾坤作四封，秦川馬驛與天通。", "北關門到菖蒲海，盡在軺車玉節中。"]'),
('14482748-3ef1-4762-af45-131279dadd7e','送都大茶馬入覲八絕句  其四','項安世','宋','宋诗','song-poetry','','[]','巴滇綠駿足如風，西域天駒骨似龍。',31,'全唐诗/poet.song.147000.json','["巴滇綠駿足如風，西域天駒骨似龍。", "日日馬綱來不斷，君王心已在除。"]'),
('edc30754-651d-48d6-b306-263a49071a8f','送都大茶馬入覲八絕句  其五','項安世','宋','宋诗','song-poetry','','[]','北人從古笑南方，只有樓舩解把江。',32,'全唐诗/poet.song.147000.json','["北人從古笑南方，只有樓舩解把江。", "今日因公致天馬，□□聞說已心降。"]'),
('bed59ad8-0acf-4a73-bd4b-c6217e6df0a7','送都大茶馬入覲八絕句  其六','項安世','宋','宋诗','song-poetry','','[]','蜀道三千鬢髮新，九重興念玉關人。',32,'全唐诗/poet.song.147000.json','["蜀道三千鬢髮新，九重興念玉關人。", "芝函寶蹟從天下，喚取歸來作近臣。"]'),
('e9b96762-232e-403e-8e88-486f9867fa6a','送都大茶馬入覲八絕句  其七','項安世','宋','宋诗','song-poetry','','[]','翩翩不下楚江鷗，水宿風餐得自由。',32,'全唐诗/poet.song.147000.json','["翩翩不下楚江鷗，水宿風餐得自由。", "聞道鸞凰上霄漢，亦知驚起却回頭。"]'),
('72336189-1238-4111-81e2-0eef69c83d6a','送都大茶馬入覲八絕句  其八','項安世','宋','宋诗','song-poetry','','[]','何世真無千里馬，如今始得九方歅。',32,'全唐诗/poet.song.147000.json','["何世真無千里馬，如今始得九方歅。", "何如牝牡驪黄外，更相權奇磊落人。"]'),
('76d3c109-71ce-4dda-aa6c-553e2c87f363','入鄂州','項安世','宋','宋诗','song-poetry','','[]','重來嘖嘖兩街人，慚愧無功及吏民。',32,'全唐诗/poet.song.147000.json','["重來嘖嘖兩街人，慚愧無功及吏民。", "正是去年平賊後，椎牛釃酒滿春城。"]'),
('a3e2afed-f57f-44de-9acb-31f7fb01b12e','次韻答荆南王君行見寄七首  其一','項安世','宋','宋诗','song-poetry','','[]','熟知宦海波如席，不礙滄洲白鳥雙。',32,'全唐诗/poet.song.147000.json','["熟知宦海波如席，不礙滄洲白鳥雙。", "詩來正與我意合，一笑澹然明六窗。"]'),
('6ef5d0cc-a1fe-4203-9aa4-313393664a8d','次韻答荆南王君行見寄七首  其二','項安世','宋','宋诗','song-poetry','','[]','主家一妾三千當，教我育我如恐傷。',32,'全唐诗/poet.song.147000.json','["主家一妾三千當，教我育我如恐傷。", "如今弃妾歸南陽，使我一葦凌蒼茫。"]'),
('e0d6a092-1973-4e63-9001-95dcb36f0206','次韻答荆南王君行見寄七首  其三','項安世','宋','宋诗','song-poetry','','[]','我來不飲粵山酒，三百五十九日齋。',32,'全唐诗/poet.song.147000.json','["我來不飲粵山酒，三百五十九日齋。", "先生付我一大事，正恐乘醉著青鞋。"]'),
('614bd0e0-d0c4-47e6-a8fb-2e05a6b40bb4','次韻答荆南王君行見寄七首  其四','項安世','宋','宋诗','song-poetry','','[]','開緘忽見王安豐，手閲七言詩一通。',32,'全唐诗/poet.song.147000.json','["開緘忽見王安豐，手閲七言詩一通。", "端能道人意中事，千載之下有國風。"]'),
('501c6686-2f23-4fa3-81aa-74f49f943555','次韻答荆南王君行見寄七首  其五','項安世','宋','宋诗','song-poetry','','[]','美人讀易見三聖，恍惚不墮老與關。',32,'全唐诗/poet.song.147000.json','["美人讀易見三聖，恍惚不墮老與關。", "菰蒲中士有如此，使我日日望龍山。"]'),
('e22a685f-d03f-4096-873a-729885c9a41b','次韻答荆南王君行見寄七首  其六','項安世','宋','宋诗','song-poetry','','[]','太守風味今寒儒，惠我佳句春華敷。',32,'全唐诗/poet.song.147000.json','["太守風味今寒儒，惠我佳句春華敷。", "越中溪山猶可似，太守好事天下無。"]'),
('d3f11ed0-6599-4eb5-8a45-8932b89772e6','次韻答荆南王君行見寄七首  其七','項安世','宋','宋诗','song-poetry','','[]','錦城雖好劣吾廬，作吏不如歸讀書。',32,'全唐诗/poet.song.147000.json','["錦城雖好劣吾廬，作吏不如歸讀書。", "千羨萬羨王隠居，有田可耕湖可漁。"]'),
('2a86061c-f0ed-493f-8c97-7b992a34726a','雪後日出三絕句  其一','項安世','宋','宋诗','song-poetry','','[]','驅車清曉入瑶林，玉色珠光冷不禁。',32,'全唐诗/poet.song.147000.json','["驅車清曉入瑶林，玉色珠光冷不禁。", "天意向人相暖熱，雲頭初日萬黄金。"]'),
('486cec06-2aaa-4c34-9488-f66cbd154932','雪後日出三絕句  其二','項安世','宋','宋诗','song-poetry','','[]','勾芒設色滿邱園，著粉施朱總可憐。',32,'全唐诗/poet.song.147000.json','["勾芒設色滿邱園，著粉施朱總可憐。", "未抵天公真畫手，金光明裏玉山川。"]'),
('bc356f7a-37e9-479d-bdca-fd08d71aa6fa','雪後日出三絕句  其三','項安世','宋','宋诗','song-poetry','','[]','六日陰寒一夜成，夢回秋月照窗明。',32,'全唐诗/poet.song.147000.json','["六日陰寒一夜成，夢回秋月照窗明。", "開門一雪深三尺，展盡寒威便放晴。"]'),
('4cf21bbb-a0e5-40b9-9a02-578b9a71abaa','上元雷雪','項安世','宋','宋诗','song-poetry','','[]','巫峽蒼江一夜雷，南雲北夢萬花開。',32,'全唐诗/poet.song.147000.json','["巫峽蒼江一夜雷，南雲北夢萬花開。", "天作自作燒燈會，不放金蓮放玉梅。"]'),
('5af19772-c6b8-4010-b4fb-ea97ee050822','道山梅開最遲作四絕句  其一','項安世','宋','宋诗','song-poetry','','[]','曉窗依約見凝脂，爭挽南枝問別離。',32,'全唐诗/poet.song.147000.json','["曉窗依約見凝脂，爭挽南枝問別離。", "幸有今年春較早，避人何事却開遲。"]'),
('b4f4772f-5d70-41d3-b34d-9b8fb7024ae1','道山梅開最遲作四絕句  其二','項安世','宋','宋诗','song-poetry','','[]','走下青泥濕素綦，竹籬苔徑有橫枝。',32,'全唐诗/poet.song.147000.json','["走下青泥濕素綦，竹籬苔徑有橫枝。", "疎花數點凄凉甚，已甚櫻桃似雪時。"]'),
('0ab15bcc-8cd8-4412-8c04-8c4742c5870b','道山梅開最遲作四絕句  其三','項安世','宋','宋诗','song-poetry','','[]','一年人事幾推移，只倚梅花似舊時。',32,'全唐诗/poet.song.147000.json','["一年人事幾推移，只倚梅花似舊時。", "起懶妝遲花亦老，却教青鬢不成絲。"]'),
('e47fbc2b-b3ed-4112-a46a-4b358bc663a3','道山梅開最遲作四絕句  其四','項安世','宋','宋诗','song-poetry','','[]','避妬含羞作態遲，等閒虛度上春時。',32,'全唐诗/poet.song.147000.json','["避妬含羞作態遲，等閒虛度上春時。", "東風已到垂楊樹，倚頼清香欲告誰。"]'),
('39e5fc6f-fd30-4ed5-9ebb-2e7109d7d5b5','二月十七日辭郢州值襄陽人至','項安世','宋','宋诗','song-poetry','','[]','謾說離家已半年，春風吹草綠如烟。',32,'全唐诗/poet.song.147000.json','["謾說離家已半年，春風吹草綠如烟。", "馬軍恰與征人會，此出那知不繫天。"]'),
('f0ce3c40-9a64-49ac-86fb-0c7d20005639','西渡亭別羅郢州','項安世','宋','宋诗','song-poetry','','[]','十七年間四別離，江南江北幾驅馳。',32,'全唐诗/poet.song.147000.json','["十七年間四別離，江南江北幾驅馳。", "相逢轉覺工夫密，不作尋常血氣衰。"]'),
('548b6316-c933-4c92-84bf-95dda35482be','次韻吳少保春日四首  其一','項安世','宋','宋诗','song-poetry','','[]','正從濠上看鯈魚，忽向宮中佩虎符。',32,'全唐诗/poet.song.147000.json','["正從濠上看鯈魚，忽向宮中佩虎符。", "出處自殊心自一，依前魚樂滿江湖。"]'),
('e23a8658-5db1-4749-a7c1-580267260393','次韻吳少保春日四首  其二','項安世','宋','宋诗','song-poetry','','[]','春晝遲時思不遲，筆飛成陣墨成池。',32,'全唐诗/poet.song.147000.json','["春晝遲時思不遲，筆飛成陣墨成池。", "不書虎卧龍跳字，即賦鯨魚翡翠詩。"]'),
('7a7dad24-9170-47ca-a68f-90624b20f3d8','次韻吳少保春日四首  其三','項安世','宋','宋诗','song-poetry','','[]','米家書畫最難忘，喚起眉間大宅陽。',32,'全唐诗/poet.song.147000.json','["米家書畫最難忘，喚起眉間大宅陽。", "酒病春愁都洗盡，貼黄小字薦賢章。"]'),
('8f2d43ae-9098-4d01-abfa-1e4765370828','次韻吳少保春日四首  其四','項安世','宋','宋诗','song-poetry','','[]','彈壓江湖景有歸，指麾物象思無違。',32,'全唐诗/poet.song.147000.json','["彈壓江湖景有歸，指麾物象思無違。", "不周風頂飛欄上，撫掌人間得失微。"]'),
('977344f4-56a0-4b28-baed-a9a66d66f629','賀范安撫上事十絕  其一','項安世','宋','宋诗','song-poetry','','[]','前肩蘇叟後陪朱，父子經筵世已無。',32,'全唐诗/poet.song.147000.json','["前肩蘇叟後陪朱，父子經筵世已無。", "誰見諸孫同盛事，槐龍陰下六絲絇。"]'),
('ba9fcbe7-39fb-4979-8631-c43b07b728a0','賀范安撫上事十絕  其二','項安世','宋','宋诗','song-poetry','','[]','泰陵初政似昭陵，榮國親扶曉日升。',32,'全唐诗/poet.song.147000.json','["泰陵初政似昭陵，榮國親扶曉日升。", "欲把經綸付喬木，內前車馬已騰騰。"]'),
('8d0ea3db-2b62-46e8-9706-84a5bd1b2895','賀范安撫上事十絕  其三','項安世','宋','宋诗','song-poetry','','[]','忽引風帆下玉京，傍人惟見此身榮。',32,'全唐诗/poet.song.147000.json','["忽引風帆下玉京，傍人惟見此身榮。", "君侯未解眉間摺，元是忠文去國情。"]'),
('2cce419a-3eb7-4e64-a656-36dca30697a1','賀范安撫上事十絕  其四','項安世','宋','宋诗','song-poetry','','[]','泥仙高退故難量，國子先生更善藏。',32,'全唐诗/poet.song.147000.json','["泥仙高退故難量，國子先生更善藏。", "不枉中朝推范呂，小申公畔有滎陽。"]'),
('51ffae6c-2a76-482b-9cf4-742ee96c8621','賀范安撫上事十絕  其五','項安世','宋','宋诗','song-poetry','','[]','太史當年責了翁，二程佳處似春風。',32,'全唐诗/poet.song.147000.json','["太史當年責了翁，二程佳處似春風。", "固應却有諸孫在，重把陽春教郢中。"]'),
('581ef9af-8eb3-44d6-b7b6-d1c3254d25d6','賀范安撫上事十絕  其六','項安世','宋','宋诗','song-poetry','','[]','漲江迎造忽吞天，說與江神莫太顛。',32,'全唐诗/poet.song.147000.json','["漲江迎造忽吞天，說與江神莫太顛。", "公是乘槎天上客，曾經倒海試孤騫。"]'),
('733af332-8374-41c1-b5be-7326b0bd9828','賀范安撫上事十絕  其七','項安世','宋','宋诗','song-poetry','','[]','十日焚雲七澤焦，六千里楚未開窯。',32,'全唐诗/poet.song.147000.json','["十日焚雲七澤焦，六千里楚未開窯。", "使君恰與秋同到，一箑風吹萬慍消。"]'),
('0fc4178f-a228-4217-a4e2-6024b5d973fd','賀范安撫上事十絕  其八','項安世','宋','宋诗','song-poetry','','[]','因聲調笑古揚州，下水如何占上流。',32,'全唐诗/poet.song.147000.json','["因聲調笑古揚州，下水如何占上流。", "却倩枚回洲上月，照將餘潤到瓜州。"]'),
('3bbf6088-3b4a-43cd-a55f-1f53354d6d95','賀范安撫上事十絕  其九','項安世','宋','宋诗','song-poetry','','[]','東觀歸來病史官，枕稜刓盡席痕斑。',32,'全唐诗/poet.song.147000.json','["東觀歸來病史官，枕稜刓盡席痕斑。", "自從公去關門睡，直到公來未啟關。"]'),
('d3ae2b6f-ba5a-4cee-96fc-92ba43336894','賀范安撫上事十絕  其一○','項安世','宋','宋诗','song-poetry','','[]','是人從古爲秋悲，病骨逢秋更可知。',32,'全唐诗/poet.song.147000.json','["是人從古爲秋悲，病骨逢秋更可知。", "說與世人應未信，今年新有羨秋詩。"]'),
('135b5212-46a8-4acc-a501-97baf9ccf1ad','寄湖北張總領六絕句  其一','項安世','宋','宋诗','song-poetry','','["\u592a\u6e56"]','故人天上厭晨趨，走向人間看五湖。',32,'全唐诗/poet.song.147000.json','["故人天上厭晨趨，走向人間看五湖。", "已煮太湖東畔海，更飛青草北邊蒭。"]'),
('9219ff0f-de38-4996-abe9-4b1a37966ba8','寄湖北張總領六絕句  其二','項安世','宋','宋诗','song-poetry','','[]','六千里楚舊堂堂，六十年來爾許荒。',32,'全唐诗/poet.song.147000.json','["六千里楚舊堂堂，六十年來爾許荒。", "敗券殃民爲第一，諸餘報發總尋常。"]'),
('5b72132a-9c04-40b6-86a2-1e3e32962740','寄湖北張總領六絕句  其三','項安世','宋','宋诗','song-poetry','','[]','只道軍儲入較量，誰知民命更禁當。',32,'全唐诗/poet.song.147000.json','["只道軍儲入較量，誰知民命更禁當。", "增錢新有梁膚使，破産舊遭周侍郎。"]'),
