('e95ab16f-f4f8-4ea4-a4b7-a8c815d75cf8','春雨懷承甫兄  其一','項安世','宋','宋诗','song-poetry','','[]','夜深風霰入油疏，小院燈明自勘書。',32,'全唐诗/poet.song.147000.json','["夜深風霰入油疏，小院燈明自勘書。", "料得繫舟低柳下，一江烟雨怨離居。"]'),
('a26f7560-cc62-4338-9aeb-c34473571518','春雨懷承甫兄  其二','項安世','宋','宋诗','song-poetry','','[]','輕寒剪剪透羅衣，正是行人二月時。',32,'全唐诗/poet.song.147000.json','["輕寒剪剪透羅衣，正是行人二月時。", "重下翠帷猶不隔，短篷疎雨更相欺。"]'),
('131db3fb-d2ab-4d2d-82eb-3d0301d16f17','初夏偶作','項安世','宋','宋诗','song-poetry','','[]','一天濃綠點殘霞，百摺湘裙血染紗。',32,'全唐诗/poet.song.147000.json','["一天濃綠點殘霞，百摺湘裙血染紗。", "剛道春歸無覓處，十分妖艷在榴花。"]'),
('f1886099-064a-4d18-977f-d292d6ef5ee1','漫興四絕  其一','項安世','宋','宋诗','song-poetry','','[]','赤日燒雲汗滿衫，一年還却十年閑。',32,'全唐诗/poet.song.147000.json','["赤日燒雲汗滿衫，一年還却十年閑。", "男兒不是憂家國，水簟冰幮正掩關。"]'),
('b0ec0c84-4391-4807-9dc2-6b7bfa669428','漫興四絕  其二','項安世','宋','宋诗','song-poetry','','[]','平生竹帛最關心，未免干戈老繫身。',32,'全唐诗/poet.song.147000.json','["平生竹帛最關心，未免干戈老繫身。", "可共兒曹爭染刺，大書銜位詫比隣。"]'),
('1874f397-2844-4f56-ac3c-7aa9db86327f','漫興四絕  其三','項安世','宋','宋诗','song-poetry','','[]','報國雖貪死後名，還家亦慰老來情。',32,'全唐诗/poet.song.147000.json','["報國雖貪死後名，還家亦慰老來情。", "釣魚船上灣灣月，何用轅門報五更。"]'),
('eba987c4-deaa-41f9-a069-db57b52c7289','漫興四絕  其四','項安世','宋','宋诗','song-poetry','','[]','兵餘初傍碧鈎欄，青杏垂垂綠蔭團。',32,'全唐诗/poet.song.147000.json','["兵餘初傍碧鈎欄，青杏垂垂綠蔭團。", "手接葉條成太息，一春花好不曾看。"]'),
('dae9d1f6-53fb-47bc-942d-26d109d55279','又前韻  其一','項安世','宋','宋诗','song-poetry','','[]','得來棚下脫衣衫，筵席初收戲士閑。',32,'全唐诗/poet.song.147000.json','["得來棚下脫衣衫，筵席初收戲士閑。", "君相恩深何以報，班超生入玉門關。"]'),
('58800493-5976-4479-b9a1-d50e0c5e494f','又前韻  其二','項安世','宋','宋诗','song-poetry','','[]','桃花扇底畫樓心，箇箇三千只一身。',32,'全唐诗/poet.song.147000.json','["桃花扇底畫樓心，箇箇三千只一身。", "可是從來多薄命，枉將顔色似東隣。"]'),
('19e381e7-1560-4136-8d06-6bdd09a35cac','又前韻  其三','項安世','宋','宋诗','song-poetry','','[]','何須紙上十分名，且樂尊前現在情。',32,'全唐诗/poet.song.147000.json','["何須紙上十分名，且樂尊前現在情。", "兩鬢雪霜心尚駭，萬般情僞老方更。"]'),
('192b3153-5580-408c-a386-bb914aa97d9b','又前韻  其四','項安世','宋','宋诗','song-poetry','','[]','庭前黄耳卧花欄，瘦脅長腰駿尾團。',32,'全唐诗/poet.song.147000.json','["庭前黄耳卧花欄，瘦脅長腰駿尾團。", "壁上朱弓雙鵲面，寂寥終日兩相看。"]'),
('9dbc449d-e707-4efc-b703-32ba5c0113d4','鳳仙花','項安世','宋','宋诗','song-poetry','','[]','紫鳳生兒未解啼，三三五五並頭栖。',32,'全唐诗/poet.song.147000.json','["紫鳳生兒未解啼，三三五五並頭栖。", "愛花未識花枝在，隨榦隨根著處迷。"]'),
('bda18590-d6e8-4931-99c4-0b6c7c01fb5f','有感四首  其一','項安世','宋','宋诗','song-poetry','','[]','宋司馬欲兵夫子，哥利王曾刃釋迦。',32,'全唐诗/poet.song.147000.json','["宋司馬欲兵夫子，哥利王曾刃釋迦。", "血面何須尤墜地，赤心終不怨鏌鋣。"]'),
('49452d98-cffc-449a-8d13-9751d7e81af8','有感四首  其二','項安世','宋','宋诗','song-poetry','','[]','夷齊怨惡本不念，堯桀是非今亦忘。',32,'全唐诗/poet.song.147000.json','["夷齊怨惡本不念，堯桀是非今亦忘。", "不知伍子嗔何事，魄化爲潮日夜忙。"]'),
('32f541f4-f5df-4ac7-8312-fe12f929e4d0','有感四首  其三','項安世','宋','宋诗','song-poetry','','[]','向來涉筆賦長楊，辱賜天家七寶牀。',32,'全唐诗/poet.song.147000.json','["向來涉筆賦長楊，辱賜天家七寶牀。", "黄吻少年評大士，白頭宮女說先皇。"]'),
('ea6e4194-6beb-49b7-8515-13e5041862d2','有感四首  其四','項安世','宋','宋诗','song-poetry','','[]','走章臺馬閑遊冶，攀鼎湖龍竟渺茫。',32,'全唐诗/poet.song.147000.json','["走章臺馬閑遊冶，攀鼎湖龍竟渺茫。", "縱使老婆强搽抹，安能更似入時妝。"]'),
('2f01a118-16cd-43ea-b2b3-3d6232188fc2','原酒','項安世','宋','宋诗','song-poetry','','[]','惟天降命，造此芳醇。',140,'全唐诗/poet.song.147000.json','["惟天降命，造此芳醇。", "以養老疾，以奉祭賓。", "少壯强艾，學仕耕耘。", "食焉不暇，何酒之云。", "世衰道降，禮喪法淪。", "以酒爲膳，每食必陳。", "童稚擬老，閨闥僣神。", "心鉗廢慮，體緩妨勤。", "業荒弗竟，行毀弗成。", "俊才中畫，毅志早惛。", "勿謂有常，異于湎沉。", "褻天慢性，其罪則均。", "作此自諭，諭我子孫。", "恐干衆怒，勿示外人。"]'),
('f5262103-0307-416b-9b02-08e48bd4d1cf','轉輪八花詩  其一','項安世','宋','宋诗','song-poetry','','[]','昊芒布政，律呂旋陽。',30,'全唐诗/poet.song.147000.json','["昊芒布政，律呂旋陽。", "草衰化綠，木瘁回蒼。", "老驚歲換，少喜年芳。"]'),
('3e0673d9-f87a-4dce-bfca-934272a53596','轉輪八花詩  其二','項安世','宋','宋诗','song-poetry','','[]','藻動魚戲，泥銜燕忙。',30,'全唐诗/poet.song.147000.json','["藻動魚戲，泥銜燕忙。", "早鶑喜谷，回雁驚湘。", "繅敷麗苑，和風海翔。"]'),
('4479b4e0-9481-4e52-bfa4-1fd974fb05d4','轉輪八花詩  其三','項安世','宋','宋诗','song-poetry','','[]','殀夭申禁，慶惠迎祥。',30,'全唐诗/poet.song.147000.json','["殀夭申禁，慶惠迎祥。", "掃花風暖，飛絮日長。", "道盈士女，勝賞交相。"]'),
('015ad56d-26c8-4494-a9e0-d916389ff9b7','轉輪八花詩  其四','項安世','宋','宋诗','song-poetry','','[]','寶珠簪珥，黛粉勻妝。',30,'全唐诗/poet.song.147000.json','["寶珠簪珥，黛粉勻妝。", "討探賞翫，賦詠盈箱。", "惱客雲陰，愁人雨凉。"]'),
('9c5c3a5d-b434-4d3b-8fac-3e68af6d3758','轉輪八花詩  其五','項安世','宋','宋诗','song-poetry','','[]','好鳥窺簷，戲蝶逾牆。',30,'全唐诗/poet.song.147000.json','["好鳥窺簷，戲蝶逾牆。", "倒醉人歸，歌行客狂。", "島幽含淑，波遠浮光。"]'),
('c0cda4fe-cbdc-4701-b053-7b36f6a854b2','轉輪八花詩  其六','項安世','宋','宋诗','song-poetry','','[]','槁枯滋澤，偃屈抽芒。',30,'全唐诗/poet.song.147000.json','["槁枯滋澤，偃屈抽芒。", "稻畦遠翠，蕙逕幽香。", "皂輿喜洽，風流激揚。"]'),
('59c07685-fa4b-4bba-9e50-b0867f926d33','轉輪八花詩  其七','項安世','宋','宋诗','song-poetry','','[]','皡皡情適，熙熙俗康。',30,'全唐诗/poet.song.147000.json','["皡皡情適，熙熙俗康。", "媼富流形，物阜輿方。", "造回坱圠，元化施張。"]'),
('5f63975a-ba3c-471d-ab55-81f0e977c6d3','轉輪八花詩 鈎枝上四十八句左旋陽字韻右旋昊字韻','項安世','宋','宋诗','song-poetry','','[]','縞夜李積，炫晝桃緗。',30,'全唐诗/poet.song.147000.json','["縞夜李積，炫晝桃緗。", "皓梨鬭雪，金柳敷黄。", "杲日天麗，和風海翔。"]'),
('88927844-1589-4a34-9e79-fbd689ef9473','轉輪八花詩 枝間八字遞相爲韻','項安世','宋','宋诗','song-poetry','','[]','渚明沙霽，雨晴霞麗。',10,'全唐诗/poet.song.147000.json','["渚明沙霽，雨晴霞麗。"]'),
('1f460697-cc47-4305-83cf-67b36a36d7ff','轉輪八花詩 花心八字遞相爲韻','項安世','宋','宋诗','song-poetry','','[]','酒佳人好，柳華春早。',10,'全唐诗/poet.song.147000.json','["酒佳人好，柳華春早。"]'),
('3a6f1011-bc38-48da-b098-70e707d70c37','春遊','項安世','宋','宋诗','song-poetry','','[]','行，行。',70,'全唐诗/poet.song.147000.json','["行，行。", "日暖，烟輕。", "舒遠矚，暢幽情。", "小雨餘潤，微陰護晴。", "草深時見蝶，葉密但聞鶑。", "陌上青絲繫馬，樓頭銀字調箏。", "滿城翠幰遮姚魏，只有東風爲不平。"]'),
('481cbac9-1d41-4088-8739-a1de7e435405','送春詩','項安世','宋','宋诗','song-poetry','','[]','墮紅一片已堪疑，吹到楊花事可知。',32,'全唐诗/poet.song.147000.json','["墮紅一片已堪疑，吹到楊花事可知。", "借問春歸誰與伴，淚痕都付石榴枝。"]'),
('a69b3c0d-6921-4471-8914-1efa32b17833','爲朱文公作','項安世','宋','宋诗','song-poetry','','[]','千畝寒林一樹梅，自妍自笑已堪哀。',32,'全唐诗/poet.song.147000.json','["千畝寒林一樹梅，自妍自笑已堪哀。", "今朝更被風吹却，擬遣春從底處回。"]'),
('951cc525-3726-4200-ab4e-a471984e2150','永州','項安世','宋','宋诗','song-poetry','','[]','日日長沙岸，看雲只念家。',24,'全唐诗/poet.song.147000.json','["日日長沙岸，看雲只念家。", "如何永州夢，偏夢在長沙。"]'),
('8a426ff2-f472-465d-b28f-3aced0dec34a','送水心淮東總領','項安世','宋','宋诗','song-poetry','','[]','藍縷疾耕家四壁，鐵衣高卧日千金。',32,'全唐诗/poet.song.147000.json','["藍縷疾耕家四壁，鐵衣高卧日千金。", "四朝餉士前無古，一旦和戎患至今。"]'),
('984b4b63-ac72-4ec4-870d-2f2932ad5469','春日隄上','項安世','宋','宋诗','song-poetry','','[]','高高下下十五里，白白紅紅千樹花。',32,'全唐诗/poet.song.147000.json','["高高下下十五里，白白紅紅千樹花。", "總在疎籬斷垣裏，背隄臨水少人家。"]'),
('85e2d76d-f4c6-4473-97b6-dc7e20cd84d4','吹帽臺','項安世','宋','宋诗','song-poetry','','[]','千山摇落萬林空，數點黄花酒盞中。',32,'全唐诗/poet.song.147000.json','["千山摇落萬林空，數點黄花酒盞中。", "半破接䍦誰耐管，已將身世付西風。"]'),
('789661cd-dd0f-4190-a492-b4efce6fb667','落帽臺','項安世','宋','宋诗','song-poetry','','[]','分明屈子獨醒愁，故作南華醉夢遊。',32,'全唐诗/poet.song.147000.json','["分明屈子獨醒愁，故作南華醉夢遊。", "豈是晉人真愛酒，渠儂心事更悲秋。"]'),
('f842d05c-e46e-42d7-af20-e042f5dc4b0c','糟蟹和潘德文','項安世','宋','宋诗','song-poetry','','[]','大戴笑汝無穴空雙螯，小戴笑汝有筐如子臯。',164,'全唐诗/poet.song.147000.json','["大戴笑汝無穴空雙螯，小戴笑汝有筐如子臯。", "太玄笑汝長郭索，入穴慚蟺升慚猱。", "知心但有畢吏部，卧起與汝同酒糟。", "後來愛者蘇長公，亦祇許汝中山醪。", "固知合向一丘老，安得上與三辰翱。", "長公貌喜心未敬，雖羨微生猶惡饕。", "我疑吳儂修稻怨，和秫醢汝償民膏。", "雖然因此得長醉，痛貶未必非深褒。", "又疑畢叟妬劉掾，曾以螟蛉輕二豪。", "故回左手就箕倨，持蟹藉糟成兩高。"]'),
('4692e9da-807a-4578-9c21-dc0f4d5c8f22','提壺','項安世','宋','宋诗','song-poetry','','[]','信州城西千萬嶺，上聞提壺有感興。',48,'全唐诗/poet.song.147000.json','["信州城西千萬嶺，上聞提壺有感興。", "頻呼美酒要人聽，應爲先生太獨醒。", "啼處更當千萬嶺，極知山鳥意丁寧。"]'),
('d9f183b7-74fb-41aa-b150-977e7a6de5b7','人日從王安撫鑑湖上分韵得禹字成八十韵','項安世','宋','宋诗','song-poetry','','[]','環山鎮清淵，哲匠儼前矩。',288,'全唐诗/poet.song.147000.json','["環山鎮清淵，哲匠儼前矩。", "懷哉萬夫雄，犯此衆鬼怒。", "豪芒等一死，利澤均衆甫。", "至今越山下，尸祝配神禹。", "我來問父老，三嘆說亂縷。", "湖高籍田丈，海下斗門五。", "蓄洩官有程，水旱儂不苦。", "墾田彼何人，竭澤禍吾土。", "侵尋近百載，饑饉以十數。", "豐穰豈不有，得失詎相補。", "此病日以深，吾生亦云窳。", "我爲父老慙，今非昔人忤。", "直無兩漢吏，更說三王祖。", "是誠我輩責，將柰汝曹瘉。", "且如去年夏，坐看連月雨。", "如人窒其吭，滿脰不得吐。", "陽侯助之决，高岸化爲鹵。", "時聞十萬軍，誰控三千弩。", "向來禾黍場，歘作魚鴈浦。", "哀哉百萬命，政用一擲賭。", "初猶蝦蟹餐，稍復茈葛取。", "木皮食且盡，骨肉儂得聚。", "呱呱載塗巷，赤子弃不乳。", "貿貿出闉闍，枯骸岌相拄。"]'),
('248b5574-3945-4b72-a0e0-9bb5b2721f83','弘齋詩','項安世','宋','宋诗','song-poetry','','[]','剛健中正純粹精，含弘光大品物亨。',96,'全唐诗/poet.song.147000.json','["剛健中正純粹精，含弘光大品物亨。", "兩儀成列易道行，有首無腹非人形。", "李侯毅甚將無朋，少年讀易老愈明。", "以龍代馬變始生，以九代七坤始神。", "與天同德體必弘，負載萬古非蚊虻。", "我無筆力回子鯨，何以贈之有西銘。"]'),
('6a463132-f706-4c16-83b8-55c340fcc266','出北關門','項安世','宋','宋诗','song-poetry','','[]','籃輿欲度北城闉，抖擻衣襟向市人。',32,'全唐诗/poet.song.147000.json','["籃輿欲度北城闉，抖擻衣襟向市人。", "恐逐西風遭舉扇，當關分付二年塵。"]'),
('fe46c3ed-ed44-43e1-bc1e-3f3b1500c0e2','晚出國門以畏熱自艮山門出始見稻田際天','項安世','宋','宋诗','song-poetry','','[]','路轉東門五里塘，夾塘寒水綠泱泱。',32,'全唐诗/poet.song.147000.json','["路轉東門五里塘，夾塘寒水綠泱泱。", "平生枉踏湖洲市，不悟田間有此凉。"]'),
('57ee8589-790a-4cad-aedb-3d99619919c7','莫愁村','項安世','宋','宋诗','song-poetry','','[]','冉冉水上雲，曾聽屈宋鳴。',24,'全唐诗/poet.song.147000.json','["冉冉水上雲，曾聽屈宋鳴。", "娟娟水中月，曾照莫愁行。"]'),
('99561201-cd32-4567-9a44-b60a42343be6','二十七日山行兩日始見文豐村','項安世','宋','宋诗','song-poetry','','[]','將軍嶺下見文豐，如入桃源路始通。',64,'全唐诗/poet.song.147000.json','["將軍嶺下見文豐，如入桃源路始通。", "雞犬人民有生意，田園池館類華風。", "柘林亹亹圍深碧，荆樹霏霏脫晚紅。", "更想書堂翠微裏，聞將雜字教兒童。"]'),
('677b211f-9a88-4d0d-80d8-ae1c2b7c1bfc','文村道中','項安世','宋','宋诗','song-poetry','','[]','十五年前號畏途，祇今開辟盡田廬。',32,'全唐诗/poet.song.147000.json','["十五年前號畏途，祇今開辟盡田廬。", "分明總是辛卿賜，誰信兜鍪出袴襦。"]'),
('0182c17c-9391-4f83-afa8-5c6bfc8ff37d','山行二十里至鶴弄嶺又見息勒村','項安世','宋','宋诗','song-poetry','','[]','初疑峽外更無天，自見文豐意釋然。',64,'全唐诗/poet.song.147000.json','["初疑峽外更無天，自見文豐意釋然。", "復向牛頭行亂石，便知鶴弄有平川。", "兩山開處成塘水，十里寬鄉漫稻田。", "一險一夷元物理，閑悲閑喜漫情牽。"]'),
('08b12312-4331-44e8-8664-fdbc40fb5998','東屯分韻得大字','項安世','宋','宋诗','song-poetry','','[]','詩翁骨成塵，巴子地如芥。',108,'全唐诗/poet.song.147000.json','["詩翁骨成塵，巴子地如芥。", "驅車藤刺亂，跋馬山石隘。", "景因名自佳，物以人故大。", "客來不一到，百歲負清債。", "遂令東屯遊，永作一生快。", "君看黄岡頭，屋破古井壞。", "恃有東坡翁，過者不敢拜。", "諒知萬物靈，山水蒙芘頼。", "男兒勿自貶，著意塵土外。"]'),
('f26181fd-daee-4f77-8483-ad9b43233c14','代人得頃字','項安世','宋','宋诗','song-poetry','','[]','郡官所食稻，共此一百頃。',24,'全唐诗/poet.song.147000.json','["郡官所食稻，共此一百頃。", "小人以力耕，君子以德請。"]'),
('96387523-67f0-4613-909a-cb0486fcc580','代人得平字','項安世','宋','宋诗','song-poetry','','[]','遶澗緣崖入，中間有許平。',24,'全唐诗/poet.song.147000.json','["遶澗緣崖入，中間有許平。", "更栽桃萬樹，應得避秦名。"]'),
('218a60b7-727d-411d-94b9-7fa9f582c587','代人得若字','項安世','宋','宋诗','song-poetry','','[]','尚想東屯詩，十九落巖壑。',24,'全唐诗/poet.song.147000.json','["尚想東屯詩，十九落巖壑。", "雨夜聞笙簧，春風化蘭若。"]'),
('e11f520e-0f16-4e66-ba0e-353bf62a3140','代人得案字','項安世','宋','宋诗','song-poetry','','[]','新收舍前雲，舊管舍北澗。',24,'全唐诗/poet.song.147000.json','["新收舍前雲，舊管舍北澗。", "一爲草堂人，從頭點詩案。"]'),
('5e31706b-708b-4e52-b09f-06998c09cd8f','讀文與可集效其體送新邛州范宗丞','項安世','宋','宋诗','song-poetry','','[]','邛州官多書，大字宜眵昏。',156,'全唐诗/poet.song.147000.json','["邛州官多書，大字宜眵昏。", "中有與可集，瑶琨貯金盆。", "王郎以贈我，讀之淚紛紛。", "每到和蘇作，姓詭字亦諼。", "多稱蘇子平，或號胡使君。", "家侯馬之譜，其事蓋有云。", "是時黨禍起，無敢交蘇門。", "子孫抱遺稿，塗改仍竄焚。", "至今集中字，舛駁難具論。", "最憐黄樓賦，一字今不存。", "哀哉誰作俑，見此傷人魂。", "君今當清時，往駕刺史轅。", "萬一布宣暇，再三修此文。"]'),
('aca664fd-e31b-4732-af74-5c556a38ea8c','精舍','項安世','宋','宋诗','song-poetry','','[]','朝登山上亭，暮宿山下宅。',24,'全唐诗/poet.song.147000.json','["朝登山上亭，暮宿山下宅。", "山鳥與山花，相逢盡相識。"]'),
('ff646dc9-c26b-44fb-ae4c-6d3aed7812f8','寒棲館','項安世','宋','宋诗','song-poetry','','[]','雲壑有仙儒，同居不同道。',24,'全唐诗/poet.song.147000.json','["雲壑有仙儒，同居不同道。", "相與共寒暄，何勞問修夭。"]'),
('dfc0b5e6-c50d-494f-8ca3-7981f04223d8','句  其一','項安世','宋','宋诗','song-poetry','','[]','乳殻中函天渾沌，浮筠破處三嶙峋。',20,'全唐诗/poet.song.147000.json','["乳殻中函天渾沌，浮筠破處三嶙峋。", "孚齋詩。"]'),
('b300a3a3-dc77-4995-ad13-448cfdcd5977','句  其二','項安世','宋','宋诗','song-poetry','','[]','醉中偶爾閑伸脚，便被劉郎賣作名。',16,'全唐诗/poet.song.147000.json','["醉中偶爾閑伸脚，便被劉郎賣作名。"]'),
('1cbfc577-5645-47b1-9d57-104b046fce3e','句 迎神三章二章四句一章五句 其一','朱熹','宋','宋诗','song-poetry','','[]','皇胡爲兮山之幽，翳長薄兮俯清流。',30,'全唐诗/poet.song.147000.json','["皇胡爲兮山之幽，翳長薄兮俯清流。", "渺冀州兮何有，眷此土兮淹留。"]'),
('3004dd81-6e72-4e72-ac71-8f7cff6184d4','句 迎神三章二章四句一章五句 其二','朱熹','宋','宋诗','song-poetry','','[]','皇之仁兮如在，子我民兮不窮以愛。',30,'全唐诗/poet.song.147000.json','["皇之仁兮如在，子我民兮不窮以愛。", "沛皇澤兮橫流，暢威靈兮無外。"]'),
('733320b0-cf69-4b18-879a-e68c58e11567','句 迎神三章二章四句一章五句 其三','朱熹','宋','宋诗','song-poetry','','[]','潔尊兮肥俎，九歌兮招舞，嗟莫報兮皇之祐。',35,'全唐诗/poet.song.147000.json','["潔尊兮肥俎，九歌兮招舞，嗟莫報兮皇之祐。", "皇欲下兮儼相羊，烈風雷兮暮雨。"]'),
('6a1ad236-770d-423c-9ac2-f21af12b9ad7','句 送神三章章四句 其一','朱熹','宋','宋诗','song-poetry','','[]','虞之陽兮灕之滸，皇降集兮巫屢舞。',30,'全唐诗/poet.song.147000.json','["虞之陽兮灕之滸，皇降集兮巫屢舞。", "桂酒湛兮瑶觴，皇之歸兮何許。"]'),
('7cf67a73-493b-463c-8dba-64b75ca0e806','句 送神三章章四句 其二','朱熹','宋','宋诗','song-poetry','','[]','龍駕兮天門，羽旄兮繽紛。',26,'全唐诗/poet.song.147000.json','["龍駕兮天門，羽旄兮繽紛。", "俯故宮兮一嘅，越宇宙兮無鄰。"]'),
('8093c7d0-aac1-4345-9505-8d2d403f704e','句 送神三章章四句 其三','朱熹','宋','宋诗','song-poetry','','[]','無鄰兮奈何，七政協兮群生嘉。',28,'全唐诗/poet.song.147000.json','["無鄰兮奈何，七政協兮群生嘉。", "信玄功兮不宰，猶彷彿兮山阿。"]'),
('437fe0b0-fcb5-49ef-91fb-b2a0c822f30f','招隠操 招隠','朱熹','宋','宋诗','song-poetry','','[]','南山之幽，桂樹之稠。',106,'全唐诗/poet.song.147000.json','["南山之幽，桂樹之稠。", "枝相樛，高拂千崖素秋，下臨深谷之寒流。", "王孫何處，攀援久淹留。", "聞說山中，虎豹晝嗥。", "聞說山中，熊羆夜咆。", "叢薄深林鹿呦呦。", "獼猴與君居，山鬼伴君遊。", "君獨胡爲自聊，歲云暮矣將焉求。", "思君不見，我心徒離憂。"]'),
('7722a377-4f0d-4a1b-a47e-5e187bfd42c5','招隠操 反招隠','朱熹','宋','宋诗','song-poetry','','[]','南山之中桂樹秋，風雲冥濛。',105,'全唐诗/poet.song.147000.json','["南山之中桂樹秋，風雲冥濛。", "下有寒棲老翁，木食澗飲迷春冬。", "此間此樂，優游渺何窮。", "我愛陽林，春葩晝紅。", "我愛陰崖，寒泉夜淙。", "竹柏含烟悄青葱。", "徐行發清商，安坐撫枯桐。", "不問簞瓢屢空，但抱明月甘長終。", "人間雖樂，此心與誰同。"]'),
('835f988e-8134-4a8a-b848-e3c7e057ba56','遠游篇','朱熹','宋','宋诗','song-poetry','','[]','舉坐且停酒，聽我歌遠游。',204,'全唐诗/poet.song.147000.json','["舉坐且停酒，聽我歌遠游。", "遠游何所至，咫尺視九州。", "九州何茫茫，環海以爲疆。", "上有孤鳳翔，下有神駒驤。", "孰能不憚遠，爲我游其方。", "爲子奉尊酒，擊鋏歌慨慷。", "送子臨大路，寒日爲無光。", "悲風來遠壑，執手空徊徨。", "問子何所之，行矣戒關梁。", "世路百險艱，出門始憂傷。", "東征憂暘谷，西遊畏羊腸。", "南轅犯癘毒，北駕風裂裳。", "願子馳堅車，躐險摧其剛。", "峩峩既不支，瑣瑣誰能當。", "朝登南極道，暮宿臨太行。", "睥睨即萬里，超忽凌八荒。", "無爲蹩躠者，終日守空堂。"]'),
('47c4574c-b6a6-41d0-abf1-58b018bc32f1','擬古八首  其一','朱熹','宋','宋诗','song-poetry','','[]','離離原上樹，戢戢澗中蒲。',60,'全唐诗/poet.song.147000.json','["離離原上樹，戢戢澗中蒲。", "娟娟東家子，鬰鬰方幽居。", "濯濯明月姿，靡靡朝華敷。", "昔爲春蘭芳，今爲秋蘼蕪。", "寸心未銷歇，託體思同車。"]'),
('52e756dc-941c-4f11-a9b6-bc93668d327d','擬古八首  其二','朱熹','宋','宋诗','song-poetry','','[]','綺閣百餘尺，朝霞冠其端。',96,'全唐诗/poet.song.147000.json','["綺閣百餘尺，朝霞冠其端。", "飛櫩麗遠漢，曲楹何盤桓。", "清謠發徽音，一唱再三歎。", "借問誰爲此，佳人本邯鄲。", "微響激流風，浮雲慘將寒。", "爲言何所悲，遊子在河關。", "不恨久離闊，但憂芳歲闌。", "願爲清宵夢，燕昵窮餘歡。"]'),
('a634de96-41e7-4ae6-a319-82821d3544ba','擬古八首  其三','朱熹','宋','宋诗','song-poetry','','[]','上山採薇蕨，側徑多幽蘭。',48,'全唐诗/poet.song.147000.json','["上山採薇蕨，側徑多幽蘭。", "采之不盈握，欲寄道里艱。", "沈憂念故人，長夜何漫漫。", "芳馨坐銷歇，徘徊以悲嘆。"]'),
('51a31812-3283-4b0d-88de-10c661abddd1','擬古八首  其四','朱熹','宋','宋诗','song-poetry','','[]','佳月朗秋夜，蟋蟀鳴空堂。',96,'全唐诗/poet.song.147000.json','["佳月朗秋夜，蟋蟀鳴空堂。", "大火西北流，河漢未渠央。", "野草不復滋，白露結爲霜。", "梁燕起高飛，雲鴈亦南翔。", "念我同心子，音形阻一方。", "不念執手歡，隔我如參商。", "寓龍不爲澤，畫餠難充腸。", "金石徒自堅，虛名真可傷。"]'),
('dbe5c2db-47b3-41ea-a301-434f0cd3f40f','擬古八首  其五','朱熹','宋','宋诗','song-poetry','','[]','鬰鬰澗底樹，揚英秋草前。',96,'全唐诗/poet.song.147000.json','["鬰鬰澗底樹，揚英秋草前。", "與君結歡愛，自比金石堅。", "金石終不渝，歡愛終不踈。", "一夕遠離別，悠悠在中途。", "相思未云變，音容定何如。", "傷彼三春蕖，灼灼層華敷。", "盛時不可留，恐逐嚴霜枯。", "夫君來何晚，賤妾長離居。"]'),
('a4f824ea-8643-4a3a-9402-cb85f70110e6','擬古八首  其六','朱熹','宋','宋诗','song-poetry','','[]','高樓一何高，俯瞰窮山河。',120,'全唐诗/poet.song.147000.json','["高樓一何高，俯瞰窮山河。", "秋風一夕至，憔悴已復多。", "寒暑遞推遷，歲月如頹波。", "離騷感遲暮，惜誓閔蹉跎。", "放意極歡虞，咄此可奈何。", "邯鄲多名姬，素豔凌朝華。", "妖歌掩齊右，緩舞傾陽阿。", "徘徊起梁塵，綷縩紛衣羅。", "麗服秉奇芬，顧我長咨嗟。", "願生喬木陰，寅緣若絲蘿。"]'),
('d188031a-1a21-4068-bfce-7c6e2f057cb6','擬古八首  其七','朱熹','宋','宋诗','song-poetry','','[]','夫君滄海至，贈我一篋珠。',60,'全唐诗/poet.song.147000.json','["夫君滄海至，贈我一篋珠。", "誰言君行近，南北萬里餘。", "結作同心花，綴在紅羅襦。", "雙垂合歡带，麗服眷微軀。", "爲君一起舞，君情定何如。"]'),
('b669a0f8-806c-4340-abe8-4f2e4eab1a35','擬古八首  其八','朱熹','宋','宋诗','song-poetry','','[]','衆星何歷歷，嚴宵麗中天。',60,'全唐诗/poet.song.147000.json','["衆星何歷歷，嚴宵麗中天。", "殷憂在之子，起步荒庭前。", "出門今幾時，書札何由宣。", "沉吟不能釋，愁結當誰憐。", "臨風一長嘆，淚落如奔泉。"]'),
('12e5eafa-470e-4c3d-a603-5ae2ae8662e9','題謝少卿藥園二首  其一','朱熹','宋','宋诗','song-poetry','','[]','謝公種藥地，窈窕青山阿。',72,'全唐诗/poet.song.147000.json','["謝公種藥地，窈窕青山阿。", "青山固不群，花藥亦婆娑。", "一掇召沖氣，三掇散沈疴。", "先生澹無事，端居味天和。", "老木百年姿，對立方嵯峨。", "持此供日夕，不樂復如何。"]'),
('cb373eff-6333-4942-9691-93e773762e9d','題謝少卿藥園二首  其二','朱熹','宋','宋诗','song-poetry','','[]','小儒忝師訓，迷謬失其方。',60,'全唐诗/poet.song.147000.json','["小儒忝師訓，迷謬失其方。", "一爲狂瘖病，望道空茫茫。", "頗聞東山園，芝朮緣高岡。", "瘖聾百不治，效在一探囊。", "再拜藥園翁，何以起膏肓。"]'),
('e2c48570-79af-4d97-ad7a-62d694944b37','邵武道中','朱熹','宋','宋诗','song-poetry','','[]','風色戒寒候，歲事已逶遲。',120,'全唐诗/poet.song.147000.json','["風色戒寒候，歲事已逶遲。", "勞生尚行役，遊子能不悲。", "林壑無餘秀，野草不復滋。", "禾黍經秋成，收歛已空畦。", "田翁喜歲豐，婦子亦嘻嘻。", "而我獨何成，悠悠長路岐。", "凌霧即曉裝，落日命晚炊。", "不惜容鬢凋，鎮日長空饑。", "征鴻在雲天，浮萍在青池。", "微蹤政如此，三嘆復何爲。"]'),
('7fd12065-8747-41c7-87ea-fe0e17fb5a45','友人黄子衡欲之上庠以詩留行','朱熹','宋','宋诗','song-poetry','','[]','若士有奇操，久厭山林卑。',108,'全唐诗/poet.song.147000.json','["若士有奇操，久厭山林卑。", "奮衣千里道，已與親友辭。", "子行何悠悠，世路方如茲。", "歸來亦何日，車馬光陸離。", "幽蘭生前林，擢置白玉墀。", "不以芳意遠，結根終不移。", "願子崇明德，潛躍貴因時。", "悲風靜夜聽，喬木歲寒姿。", "何以迴軒駕，千載相與期。"]'),
('d0dfaddc-4b59-4990-824f-0fa38705167f','奉酬丘子野表兄飲酒之句','朱熹','宋','宋诗','song-poetry','','[]','微褐不充體，寒夜懷重衾。',108,'全唐诗/poet.song.147000.json','["微褐不充體，寒夜懷重衾。", "古來窮廬士，歲暮多苦心。", "苦心亦何爲，世路多崎嶔。", "不藉盃中物，離憂坐自侵。", "舉杯當勿辭，何爲復沉吟。", "醺酣遺所拘，神慮契遐襟。", "荒湎思前戒，歡謠發清音。", "雅唱一何高，仰酬非所任。", "申章聊敘報，洪量亦余欽。"]'),
('febc1b07-77f2-4287-b420-31fe29617ae4','丘子野表兄郊園五詠  其一','朱熹','宋','宋诗','song-poetry','','[]','欲識淵明家，離離踈柳下。',24,'全唐诗/poet.song.147000.json','["欲識淵明家，離離踈柳下。", "中有白雲人，良非遯世者。"]'),
('9e51a1f7-79a8-42dc-a441-45f75c1d007b','丘子野表兄郊園五詠  其二','朱熹','宋','宋诗','song-poetry','','[]','結楥遂芳植，覆牆擁深翠。',24,'全唐诗/poet.song.147000.json','["結楥遂芳植，覆牆擁深翠。", "還當具春酒，與客花下醉。"]'),
('45e646a1-7632-41c7-bc8f-ab6149608eca','丘子野表兄郊園五詠  其三','朱熹','宋','宋诗','song-poetry','','[]','移自溪上園，種此牆陰路。',24,'全唐诗/poet.song.147000.json','["移自溪上園，種此牆陰路。", "牆陰少人行，來歲障幽戶。"]'),
('d03120f1-d491-481c-9187-245923e26735','丘子野表兄郊園五詠  其四','朱熹','宋','宋诗','song-poetry','','[]','芭蕉值秋檻，勿云憔悴姿。',24,'全唐诗/poet.song.147000.json','["芭蕉值秋檻，勿云憔悴姿。", "與君障夏日，羽扇寧復持。"]'),
('43663bdd-47de-4109-975f-49327fd75377','丘子野表兄郊園五詠  其五','朱熹','宋','宋诗','song-poetry','','[]','花柳遶宅茂，先生在郊居。',24,'全唐诗/poet.song.147000.json','["花柳遶宅茂，先生在郊居。", "下帷良已苦，時作带經耡。"]'),
('6409e024-2ae8-4029-af05-4a8781881c14','古意','朱熹','宋','宋诗','song-poetry','','[]','兔絲附樸樕，佳木生高岡。',96,'全唐诗/poet.song.147000.json','["兔絲附樸樕，佳木生高岡。", "弱蔓失所依，佳木徒蒼蒼。", "兩美不同根，高下永相望。", "相望無窮期，相思諒徒爲。", "同車在夢想，忽覺淚沾衣。", "不恨歲月遒，但惜芳華姿。", "嚴霜萎百草，坐恐及茲時。", "盛年無再至，已矣不復疑。"]'),
('81cc673c-f73a-4875-b395-781a7ef3d4c9','送劉旬甫之池陽省覲六十四丈遂如行在所上計','朱熹','宋','宋诗','song-poetry','','[]','雨雪成歲暮，之子遠徂征。',72,'全唐诗/poet.song.147000.json','["雨雪成歲暮，之子遠徂征。", "酌酒起相送，慨我別離情。", "池陽實大藩，佐車屈時英。", "子行一請覲，上計趨吳京。", "良玉懷貞操，芳蘭含遠馨。", "臨岐一珍重，即此萬里程。"]'),
('89cc8898-2e9d-4bae-99af-6ce034a5b632','晨起對雨二首  其一','朱熹','宋','宋诗','song-poetry','','[]','凄冽歲云晏，雨雪集晨朝。',72,'全唐诗/poet.song.147000.json','["凄冽歲云晏，雨雪集晨朝。", "高眠適方起，四望但蕭條。", "遠氛白漫漫，風至林靄消。", "流潦冒荒塗，清川亦迢迢。", "遐瞻思莫窮，端居心自超。", "覽物思無託，即事且逍遥。"]'),
('7a5fc03f-0f6f-4bfa-a50f-f235d8d3de07','晨起對雨二首  其二','朱熹','宋','宋诗','song-poetry','','[]','晨起候前障，白煙眇林端。',72,'全唐诗/poet.song.147000.json','["晨起候前障，白煙眇林端。", "雨意方未已，后土何時乾。", "倚竹聽蕭瑟，俯澗聞驚湍。", "景物豈不佳，所嗟歲已闌。", "守道無物役，安時且盤桓。", "翳然陶茲理，貧悴非所歎。"]'),
('54ffed5f-5452-4f2e-ba48-d6566e76259c','殘臘','朱熹','宋','宋诗','song-poetry','','[]','殘臘生春序，愁霖逼歲昏。',48,'全唐诗/poet.song.147000.json','["殘臘生春序，愁霖逼歲昏。", "小紅敷艷萼，衆綠被陳根。", "陰壑泉方注，原田水欲渾。", "農家向東作，百事集柴門。"]'),
('f5036f5e-6a70-4dde-a76f-faf31edd61c2','客舍聽雨','朱熹','宋','宋诗','song-poetry','','[]','沈沈蒼山郭，暮景含餘清。',48,'全唐诗/poet.song.147000.json','["沈沈蒼山郭，暮景含餘清。", "春靄起林際，滿空寒雨生。", "投裝即虛館，簷響通夕鳴。", "遥想山齋夜，蕭蕭木葉聲。"]'),
('88b3a086-340d-483c-8247-17731bcfb64a','宿武夷觀妙堂二首  其一','朱熹','宋','宋诗','song-poetry','','[]','陰靄除已盡，山深夜還冷。',48,'全唐诗/poet.song.147000.json','["陰靄除已盡，山深夜還冷。", "獨卧一齋空，不眠思耿耿。", "閑來生道心，妄遣慕真境。", "稽首仰高靈，塵緣誓當屏。"]'),
('c69e533a-9405-49e6-8a26-b9e8557c4dfa','宿武夷觀妙堂二首  其二','朱熹','宋','宋诗','song-poetry','','[]','清晨叩高殿，緩步遶虛廊。',48,'全唐诗/poet.song.147000.json','["清晨叩高殿，緩步遶虛廊。", "齋心啟真祕，焚香散十方。", "出門戀仙境，仰首雲峰蒼。", "躊躇野水際，頓將塵慮忘。"]'),
('22dc42a1-556a-4323-870f-82493655a0dd','社日諸人集西岡','朱熹','宋','宋诗','song-poetry','','[]','郊原曖芳物，細雨青春時。',72,'全唐诗/poet.song.147000.json','["郊原曖芳物，細雨青春時。", "前岡遐敞地，登覽情無遺。", "農畝懷歲功，壺漿祝神釐。", "我慚里居氓，十載勞驅馳。", "今朝幸休閑，追逐聊嘻嘻。", "笑語歡成舊，盡醉靡歸期。"]'),
('f8c7f171-8758-4eb2-9f0c-77de4469331a','久雨齋居誦經','朱熹','宋','宋诗','song-poetry','','[]','端居獨無事，聊披釋氏書。',48,'全唐诗/poet.song.147000.json','["端居獨無事，聊披釋氏書。", "暫釋塵累牽，超然與道俱。", "門掩竹林幽，禽鳴山雨餘。", "了此無爲法，身心同晏如。"]'),
('30755c2d-3baf-417f-ac54-7f41f5b5d6b7','新竹','朱熹','宋','宋诗','song-poetry','','[]','春雷殷巖際，幽草齊發生。',36,'全唐诗/poet.song.147000.json','["春雷殷巖際，幽草齊發生。", "我種南窗竹，戢戢已抽萌。", "坐獲幽林賞，端居無俗情。"]'),
('ff87011a-bef5-4022-ab25-89da35c4fb5c','雨中示魏惇夫兼懷黄子厚二首  其一','朱熹','宋','宋诗','song-poetry','','[]','讀書春日晏，雨至滿郊園。',48,'全唐诗/poet.song.147000.json','["讀書春日晏，雨至滿郊園。", "一灑幽叢竹，藹藹清陰繁。", "齋居無還往，鎮日空掩門。", "欲將沖靜趣，與子俱忘言。"]'),
('7cd04d05-859f-4971-be28-68893bffdcd3','雨中示魏惇夫兼懷黄子厚二首  其二','朱熹','宋','宋诗','song-poetry','','[]','暄風變春餘，卉木日葱蒨。',48,'全唐诗/poet.song.147000.json','["暄風變春餘，卉木日葱蒨。", "林間一雨來，滿庭寒草徧。", "寂寞謝朋儔，晤語懷雋彥。", "良無一水遥，阻闊何由見。"]'),
('ce38c4ad-56f2-47b1-a3bc-1956407ffbdc','夜聞子規','朱熹','宋','宋诗','song-poetry','','[]','幽林欲雨氣含凄，春晚端居園徑迷。',32,'全唐诗/poet.song.147000.json','["幽林欲雨氣含凄，春晚端居園徑迷。", "獨向高齋展衾卧，南山夜夜子規啼。"]'),
('e7795807-bb1b-4da1-b942-8faa2c0bd7f6','杜門','朱熹','宋','宋诗','song-poetry','','[]','杜門守貞操，養素安沖漠。',60,'全唐诗/poet.song.147000.json','["杜門守貞操，養素安沖漠。", "寂寂閟林園，心空境無作。", "細雨被新筠，微風動幽籜。", "聊成五字句，吟罷山花落。", "浩然與誰期，放情遺所託。"]'),
('aa12d2e1-ad60-4f34-84eb-d1328cf59dea','宿山寺聞蟬作','朱熹','宋','宋诗','song-poetry','','[]','林葉經夏暗，蟬聲今夕聞。',24,'全唐诗/poet.song.147000.json','["林葉經夏暗，蟬聲今夕聞。", "已驚爲客意，更值夕陽曛。"]'),
('d914e9ac-91c0-45c4-8ec9-d3938439986b','晨登雲際閣','朱熹','宋','宋诗','song-poetry','','[]','晨起踏僧閣，徙倚望平郊。',48,'全唐诗/poet.song.147000.json','["晨起踏僧閣，徙倚望平郊。", "攢巒夏雲曉，蒼茫林影交。", "暫釋川途念，憩此煙雲巢。", "聊欲托僧宇，歲晏結蓬茅。"]'),
('03684b7e-6c17-435f-a477-bee1e2d37dab','池上示同遊者','朱熹','宋','宋诗','song-poetry','','[]','藕葉蓋波面，池花猶未紅。',48,'全唐诗/poet.song.147000.json','["藕葉蓋波面，池花猶未紅。", "聊承曉露餘，散步詠凉風。", "香氣已飄忽，客懷誰與同。", "唯應同遊子，芳意更匆匆。"]'),
('db34ddca-bf85-4046-bb18-b967b7891762','過黄塘嶺','朱熹','宋','宋诗','song-poetry','','[]','屈曲危塍轉，沉陰山氣昏。',48,'全唐诗/poet.song.147000.json','["屈曲危塍轉，沉陰山氣昏。", "蟬聲高樹暗，石瀨淺流喧。", "已過黄塘嶺，欲覓桃花源。", "無爲此留滯，驅馬踰山樊。"]'),
('0a89953c-5126-407d-92e6-0b10b2baaa4a','宿白芒畬','朱熹','宋','宋诗','song-poetry','','[]','早發招賢里，夜宿白芒畬。',48,'全唐诗/poet.song.147000.json','["早發招賢里，夜宿白芒畬。", "川暝前山雨，風驚澗樹花。", "途陸綿異縣，曛黑泊田家。", "逢人聊問路，猶恨去程賒。"]'),
('ef9527f9-8f17-43d5-bd9d-1088abd9c1d5','濯足澗水二首  其一','朱熹','宋','宋诗','song-poetry','','[]','濯足澗邊石，山空水流喧。',24,'全唐诗/poet.song.147000.json','["濯足澗邊石，山空水流喧。", "行旅非吾事，寄此一忘言。"]'),
('65798a1a-0a8f-4621-8ea8-efdf93255551','濯足澗水二首  其二','朱熹','宋','宋诗','song-poetry','','[]','澗邊濯足時，脩途倦煩燠。',24,'全唐诗/poet.song.147000.json','["澗邊濯足時，脩途倦煩燠。", "振策欲尋源，山空無往躅。"]'),
('c48dc2eb-3ede-4e78-ab00-6bc5e813285a','自溪口買舟至順昌示同行者','朱熹','宋','宋诗','song-poetry','','[]','時燠倦長途，買舟至西郭。',48,'全唐诗/poet.song.147000.json','["時燠倦長途，買舟至西郭。", "煙波方渺然，坐此溪上閣。", "子留且歡宴，我去成蕭索。", "同行不同調，此意誰與託。"]'),
('f5229ca2-2e22-457d-bfa6-2da425ff04c5','宿篔簹舖','朱熹','宋','宋诗','song-poetry','','[]','庭陰雙樹合，窗夕孤蟬吟。',24,'全唐诗/poet.song.147000.json','["庭陰雙樹合，窗夕孤蟬吟。", "盤礴解煩鬰，超摇生道心。"]'),
('42f0555c-9170-48af-96a4-53e746c597a5','倒水坑作','朱熹','宋','宋诗','song-poetry','','[]','窮幽鮮外慕，殖志在丘園。',48,'全唐诗/poet.song.147000.json','["窮幽鮮外慕，殖志在丘園。", "即此竟無得，空恨歲時遷。", "川陸綿半載，煩燠當歸緣。", "憩此蒼山曲，洗心聞澗泉。"]'),
('52a7d258-f075-480a-98c8-d8e3b1fd237d','夏日二首  其一','朱熹','宋','宋诗','song-poetry','','[]','夏景已逾半，林陰方澹然。',48,'全唐诗/poet.song.147000.json','["夏景已逾半，林陰方澹然。", "鳴蟬咽餘響，池荷競華鮮。", "抱痾守窮廬，釋志趣幽禪。", "即此窮日夕，寧爲外務牽。"]'),
('b1fccfa8-7c12-4479-b79c-30040269b7bf','夏日二首  其二','朱熹','宋','宋诗','song-poetry','','[]','雲臻川谷暝，雨來林景清。',48,'全唐诗/poet.song.147000.json','["雲臻川谷暝，雨來林景清。", "齋舍無餘事，凉氣散煩纓。", "望山懷釋侶，盥手閲仙經。", "誰懷出塵意，來此俱無營。"]'),
('fdc96a85-68a6-46ec-938a-f847454a9a5d','對雨','朱熹','宋','宋诗','song-poetry','','[]','虛堂一遊矚，驟雨滿空至。',72,'全唐诗/poet.song.147000.json','["虛堂一遊矚，驟雨滿空至。", "的皪散方塘，冥濛結雲氣。", "勢逐風威亂，望窮山景翳。", "煙靄集林端，蒼茫欲無際。", "凉氣襲輕裾，炎氛起秋思。", "對此景凄凄，還增沖澹意。"]'),
('e032c708-6b11-488a-85ee-e34644bdbd4b','齋居聞磬','朱熹','宋','宋诗','song-poetry','','[]','幽林滴露稀，華月流空爽。',48,'全唐诗/poet.song.147000.json','["幽林滴露稀，華月流空爽。", "獨士守寒栖，高齋絕羣想。", "此時鄰磬發，聲合前山響。", "起對玉書文，誰知道機長。"]'),
('481f468e-863d-42ea-a290-ec4b4f540d4b','又聞琴作','朱熹','宋','宋诗','song-poetry','','[]','瑶琴清露後，寥亮發窗間。',48,'全唐诗/poet.song.147000.json','["瑶琴清露後，寥亮發窗間。", "韻逐回風遠，情隨玄夜闌。", "端居獨無寐，林扉空掩關。", "起望星河落，哀絃方罷彈。"]'),
('0eba34db-0a3a-43a7-bac0-68a4dfb0e38c','讀道書作六首  其一','朱熹','宋','宋诗','song-poetry','','[]','巖居秉貞操，所慕在玄虛。',72,'全唐诗/poet.song.147000.json','["巖居秉貞操，所慕在玄虛。", "清夜眠齋宇，終朝觀道書。", "形忘氣自沖，性達理不餘。", "於道雖未庶，已超名跡拘。", "至樂在襟懷，山水非所娛。", "寄語狂馳子，營營竟焉如。"]'),
('b199a698-fb3f-49e8-8155-0cf53dfa1a84','讀道書作六首  其二','朱熹','宋','宋诗','song-poetry','','[]','失志墮塵網，浩思屬滄洲。',48,'全唐诗/poet.song.147000.json','["失志墮塵網，浩思屬滄洲。", "靈芝不可得，歲月逐江流。", "碧草晚未凋，悲風颯已秋。", "仰首鸞鶴期，白雲但悠悠。"]'),
('7387807e-63ad-49ad-ad5c-344ee5c981f4','讀道書作六首  其三','朱熹','宋','宋诗','song-poetry','','[]','白露墜秋節，碧陰生夕凉。',48,'全唐诗/poet.song.147000.json','["白露墜秋節，碧陰生夕凉。", "起步廣庭內，仰見天蒼蒼。", "東華綠髮翁，授我不死方。", "願言勤脩學，接景三玄鄉。"]'),
('ae0f3688-39e2-45c4-9912-fdafe595efb9','讀道書作六首  其四','朱熹','宋','宋诗','song-poetry','','[]','四山起秋雲，白日照長道。',48,'全唐诗/poet.song.147000.json','["四山起秋雲，白日照長道。", "西風何蕭索，極目但烟草。", "不學飛仙術，日日成醜老。", "空瞻王子喬，吹笙碧天杪。"]'),
('1ac87137-0f7a-44fa-8896-8056c1ff750b','讀道書作六首  其五','朱熹','宋','宋诗','song-poetry','','[]','鬰羅聳空上，青冥風露凄。',48,'全唐诗/poet.song.147000.json','["鬰羅聳空上，青冥風露凄。", "聊乘白玉鸞，上與九霄期。", "激烈玉簫聲，夭矯餐霞姿。", "一回流星盻，千載空相思。"]'),
('696863d9-06df-4ad7-9b14-5c0a224e11ba','讀道書作六首  其六','朱熹','宋','宋诗','song-poetry','','[]','王喬吹笙去，列子御風還。',48,'全唐诗/poet.song.147000.json','["王喬吹笙去，列子御風還。", "至人絕華念，出入有無間。", "千載但聞名，不見冰玉顔。", "長嘯空宇碧，何許蓬萊山。"]'),
('34e86846-6526-40c3-b1a8-f15c61707155','秋雨','朱熹','宋','宋诗','song-poetry','','[]','一雨散林表，清陰生廣庭。',72,'全唐诗/poet.song.147000.json','["一雨散林表，清陰生廣庭。", "喜茲新秋夜，起向高齋行。", "煩歊獲暫祛，凉氛集華纓。", "沉沉遠林氣，愜此端居情。", "節物坐如此，撫世襟方盈。", "歸當息華念，超遥悟無生。"]'),
('ef73ed63-a529-4a6f-a2ca-1fd3587af278','秋夕懷子厚二首  其一','朱熹','宋','宋诗','song-poetry','','[]','雨歇林氣爽，月華湛遥暉。',48,'全唐诗/poet.song.147000.json','["雨歇林氣爽，月華湛遥暉。", "齋居翫物變，廓落滄洲期。", "焚香散碧虛，撫節陳清詩。", "抗志屬雲端，非君諒誰知。"]'),
('3fb7dda3-85d0-47ba-a68a-8df2d4e6f4f8','秋夕懷子厚二首  其二','朱熹','宋','宋诗','song-poetry','','[]','凉氣沉齋宇，夕陰未渠央。',48,'全唐诗/poet.song.147000.json','["凉氣沉齋宇，夕陰未渠央。", "寒栖屬遥夜，長簟卷單床。", "浮雲蔽中天，愁霖隔秋窗。", "思君一晤對，耿耿何能忘。"]'),
('a9fb5e94-52e3-48ee-8a8d-b051a63c07ef','病中呈諸友','朱熹','宋','宋诗','song-poetry','','[]','窮居值秋晦，抱疾獨齋居。',95,'全唐诗/poet.song.147000.json','["窮居值秋晦，抱疾獨齋居。", "行稀草生徑，一雨復旬餘。", "交親各所營，曠若音塵踈。", "始悟端居樂，復理北窗書。", "讀誦興已闌，起坐方躊躇。", "綠樹滿空庭，策策飊初。", "良時不復停，煩吝未云祛。", "還思對君子，日夕佇軒車。"]'),
('2b2e665b-4bf7-414b-9d6a-23b4b46fd06c','川上見月歸示同行者','朱熹','宋','宋诗','song-poetry','','[]','川上偶携手，皓月起林端。',48,'全唐诗/poet.song.147000.json','["川上偶携手，皓月起林端。", "一舒臨流望，玄露已先漙。", "歸掩荒園扉，更怯裳衣單。", "清夜可晤言，獨處誰爲歡。"]'),
('5cc8e8eb-e9dc-4ce5-bb62-35f8f1857068','月夜述懷','朱熹','宋','宋诗','song-poetry','','[]','皓月出林表，照此秋牀單。',48,'全唐诗/poet.song.147000.json','["皓月出林表，照此秋牀單。", "幽人起晤歎，桂香發窗間。", "高梧滴露鳴，散髮天風寒。", "抗志絕塵氛，何不棲空山。"]'),
('a3cdd8ad-56f0-4890-ae1e-0a88562a8b5b','冬雨不止','朱熹','宋','宋诗','song-poetry','','[]','忽忽時序改，白日藏光輝。',72,'全唐诗/poet.song.147000.json','["忽忽時序改，白日藏光輝。", "重陰潤九野，小雨紛微微。", "蒼山寒氣深，高林霜葉稀。", "田家秋成意，落落乖所期。", "曠望獨興懷，戚戚愁寒饑。", "事至當復遣，且掩荒園扉。"]'),
('2109ec26-1ae4-4117-86a4-4467f11654e0','贈仰上人','朱熹','宋','宋诗','song-poetry','','[]','澗谷秋雲曉，飄颻無定姿。',48,'全唐诗/poet.song.147000.json','["澗谷秋雲曉，飄颻無定姿。", "氛氳升遠樹，凌亂起寒颸。", "雨罷成孤鶴，天高逐散絲。", "上人歸別嶺，心迹但如斯。"]'),
('bdf7cf0d-fda7-447f-9fb1-4e3d8e855fb6','即事偶賦','朱熹','宋','宋诗','song-poetry','','[]','白煙竟日起，雨晦蒼山深。',72,'全唐诗/poet.song.147000.json','["白煙竟日起，雨晦蒼山深。", "老菊不復妍，丹楓滿高林。", "抱病寢齋房，窗戶結愁陰。", "起望一舒情，遐眺豁煩襟。", "人生亦已勞，世路方崎嶔。", "且詠招隠作，無爲名跡侵。"]'),
('54c90e7a-60ca-46a8-b8db-1cea5c27cd52','作室爲焚修之所擬步虛辭','朱熹','宋','宋诗','song-poetry','','[]','歸命仰璇極，寥陽太帝居。',48,'全唐诗/poet.song.147000.json','["歸命仰璇極，寥陽太帝居。", "翛翛列羽幢，八景騰飛輿。", "願傾無極光，回駕俯塵區。", "受我焚香禮，同彼浮黎都。"]'),
('28327f72-6f64-4979-bcea-7c4d4404a4c9','寄題咸清精舍清暉堂','朱熹','宋','宋诗','song-poetry','','[]','山川佳麗地，結宇娛朝昏。',96,'全唐诗/poet.song.147000.json','["山川佳麗地，結宇娛朝昏。", "朝昏有奇變，超忽難具論。", "千嵐蔽夕陰，百嶂明晨暾。", "穹林擢遥景，回澗盪秋氛。", "覽極慚未周，窮深遂忘喧。", "欲將身世遺，况託玄虛門。", "境空乘化往，理妙觸目存。", "珍重忘言子，高唱絕塵紛。"]'),
('0c38c543-7432-40a9-95a0-08c05599ef99','冬日二首  其一','朱熹','宋','宋诗','song-poetry','','[]','蕭索時序晚，已復度高秋。',48,'全唐诗/poet.song.147000.json','["蕭索時序晚，已復度高秋。", "回澗白波起，通川絳樹稠。", "晨風散清霜，嘉稻卷平疇。", "獨懷志士感，歲事幸將休。"]'),
('495f2e1b-f6da-4603-86a9-ef73eb435d00','冬日二首  其二','朱熹','宋','宋诗','song-poetry','','[]','清霜染澗樹，蕭索向嚴冬。',48,'全唐诗/poet.song.147000.json','["清霜染澗樹，蕭索向嚴冬。", "密雨有時集，寒雲無定容。", "波明橫瀨出，風急遠林空。", "一極窗間眺，高旻矗亂峰。"]'),
('0f285df6-985f-48be-b924-6804f19df50f','春日即事','朱熹','宋','宋诗','song-poetry','','[]','郊園卉木麗，林塘煙水清。',48,'全唐诗/poet.song.147000.json','["郊園卉木麗，林塘煙水清。", "閑棲衆累遠，覽物共關情。", "憇樹鳥啼幽，緣原草舒榮。", "悟悅心自遣，誰云非達生。"]'),
('0bfd46f7-8675-46a8-88a0-632ef715ca2c','誦經','朱熹','宋','宋诗','song-poetry','','[]','坐厭塵累積，脫躧味幽玄。',48,'全唐诗/poet.song.147000.json','["坐厭塵累積，脫躧味幽玄。", "靜披笈中素，流味東華篇。", "朝昏一俯仰，歲月如奔川。", "世紛未云遣，仗此息諸緣。"]'),
('5ae8a6e9-8da3-465f-9518-d518017688ba','春日言懷','朱熹','宋','宋诗','song-poetry','','[]','春至草木變，郊園猶掩扉。',84,'全唐诗/poet.song.147000.json','["春至草木變，郊園猶掩扉。", "茲晨與心會，覽物徧芳菲。", "桃萼破淺紅，時禽悅朝暉。", "泉谷暖方融，原田水初肥。", "東作興庶甿，歲功始在茲。", "端居適自慰，世事復有期。", "終然心所向，農畝當還歸。"]'),
('f76f4cf2-de45-4e5b-b371-9c78f0bfa088','晚步','朱熹','宋','宋诗','song-poetry','','[]','東原鬰已秀，嘉樹藹初綠。',72,'全唐诗/poet.song.147000.json','["東原鬰已秀，嘉樹藹初綠。", "衆卉發春陽，前山可遐矚。", "端居日康倦，涉澗步墟曲。", "景幽恣所尋，悟悅何由足。", "鳥鳴華薄深，泉響亂流續。", "握手一同忻，吾生詎幽獨。"]'),
('aeca9695-3414-4952-be8a-2e63d2e6dbb3','懷友','朱熹','宋','宋诗','song-poetry','','[]','山夕煙景亂，林空鳥啼幽。',48,'全唐诗/poet.song.147000.json','["山夕煙景亂，林空鳥啼幽。", "懷人隔春江，夢想積離憂。", "覽物懷悄悄，臨觴但悠悠。", "徘徊東西步，悟歎復何求。"]'),
('78083a4c-128f-43e2-92ae-b6ca4b12ca24','山館觀海棠作二首  其一','朱熹','宋','宋诗','song-poetry','','[]','景暄林氣深，雨罷寒塘淥。',48,'全唐诗/poet.song.147000.json','["景暄林氣深，雨罷寒塘淥。", "置酒此佳辰，尋幽慕前躅。", "芳樹麗煙華，紫緜散清馥。", "當由懷別恨，寂寞向空谷。"]'),
('292bd2fe-220f-43ec-8162-595886387e80','山館觀海棠作二首  其二','朱熹','宋','宋诗','song-poetry','','[]','春草池塘綠，忽驚花嶼紅。',48,'全唐诗/poet.song.147000.json','["春草池塘綠，忽驚花嶼紅。", "亂英深淺色，芳氣有無中。", "置酒賓朋集，披襟賞咏同。", "若非摹寫得，應逐綵雲空。"]'),
('0f8b861e-3695-444b-95fa-5c0dd2e4f9ad','題畫','朱熹','宋','宋诗','song-poetry','','[]','青鸞凌風翔，飛仙窈窕姿。',72,'全唐诗/poet.song.147000.json','["青鸞凌風翔，飛仙窈窕姿。", "高挹謝塵境，妙顔粲瓊蕤。", "登霞抗玉音，結霧吹參差。", "神鈞儛空洞，玄露湛霄暉。", "山中玉斧家，胡不一來嬉。", "真凡路一分，冥運千年期。"]'),
('92218282-8ead-4191-a5b5-543d1c99bf18','過武夷作','朱熹','宋','宋诗','song-poetry','','[]','弄舟緣碧澗，棲集靈峯阿。',60,'全唐诗/poet.song.147000.json','["弄舟緣碧澗，棲集靈峯阿。", "夏木紛已成，流泉注驚波。", "雲闕啟蒼茫，高城鬰嵯峨。", "眷言羽衣子，俛仰日婆娑。", "不學飛仙術，纍纍丘冢多。"]'),
('55b01324-11c0-46a4-87b3-a9c0460f155f','同安官舍夜作二首  其一','朱熹','宋','宋诗','song-poetry','','[]','官署夜方寂，幽林生月初。',48,'全唐诗/poet.song.147000.json','["官署夜方寂，幽林生月初。", "閑居秋意遠，花香寒露濡。", "故國異時節，欲歸懷簡書。", "聊從西軒卧，塵思一蕭踈。"]'),
('7da6be6d-e282-45aa-be26-d1f92a37e229','同安官舍夜作二首  其二','朱熹','宋','宋诗','song-poetry','','[]','窗戶納凉氣，吏休散朱墨。',36,'全唐诗/poet.song.147000.json','["窗戶納凉氣，吏休散朱墨。", "無事一翛然，形神罷拘役。", "暫愒豈非閑，無論心與跡。"]'),
('4674dce3-aea4-46b6-9ebe-a15b4739b0c3','寄山中舊知七首  其一','朱熹','宋','宋诗','song-poetry','','[]','結茅雲壑外，石澗流清泉。',48,'全唐诗/poet.song.147000.json','["結茅雲壑外，石澗流清泉。", "澗底采菖蒲，顔色永芳鮮。", "超世慕肥遯，鍊形學飛仙。", "未諧物外期，已絕區中緣。"]'),
('99f828f9-ec86-4e5f-905e-cf7a6da44993','寄山中舊知七首  其二','朱熹','宋','宋诗','song-poetry','','[]','客子歸來晚，江湖欲授衣。',48,'全唐诗/poet.song.147000.json','["客子歸來晚，江湖欲授衣。", "路岐終寂寞，老天足傷悲。", "慷慨平生志，冥茫造物機。", "清秋鵰鶚上，萬里看橫飛。"]'),
('187b0e06-e254-4b3e-ad28-cc94ec50bcad','寄山中舊知七首  其三','朱熹','宋','宋诗','song-poetry','','[]','晨興香火罷，入室披仙經。',48,'全唐诗/poet.song.147000.json','["晨興香火罷，入室披仙經。", "玄默豈非尚，素餐空自驚。", "起與塵事俱，是非忽我營。", "此道難坐進，要須悟無生。"]'),
('944aecc4-68cb-4a8a-833a-f8048c54533a','寄山中舊知七首  其四','朱熹','宋','宋诗','song-poetry','','[]','故園今夜半，林影澹逾清。',48,'全唐诗/poet.song.147000.json','["故園今夜半，林影澹逾清。", "曳杖南溪路，君應獨自行。", "潺湲流水思，蕭索早秋聲。", "盡向琴中寫，焉知離恨情。"]'),
('4a3c345b-20bc-4c2a-a3c5-54b7a51cb537','寄山中舊知七首  其五','朱熹','宋','宋诗','song-poetry','','[]','采藥侵晨入亂峯，宿雲無處認行蹤。',32,'全唐诗/poet.song.147000.json','["采藥侵晨入亂峯，宿雲無處認行蹤。", "歸來應念塵中客，寄與玄芝手自封。"]'),
('455f30a8-4a40-42bc-a8b0-663b42196418','寄山中舊知七首  其六','朱熹','宋','宋诗','song-poetry','','[]','凄凉梧葉變，芬馥桂花秋。',24,'全唐诗/poet.song.147000.json','["凄凉梧葉變，芬馥桂花秋。", "日夕湖皋勝，哦詩憶舊遊。"]'),
('4392d8ff-268f-4084-b1f2-1866c6831f44','寄山中舊知七首  其七','朱熹','宋','宋诗','song-poetry','','[]','秋至池閣靜，天高林薄踈。',24,'全唐诗/poet.song.147000.json','["秋至池閣靜，天高林薄踈。", "西園有佳處，那得與君俱。"]'),
('237b881c-1a9c-43f4-a420-5b9e8f7090c1','述懷','朱熹','宋','宋诗','song-poetry','','[]','夙尚本林壑，灌園無寸資。',96,'全唐诗/poet.song.147000.json','["夙尚本林壑，灌園無寸資。", "始懷經濟策，復愧軒裳姿。", "效官刀筆間，朱墨手所持。", "謂言殫蹇劣，詎敢論居卑。", "任小才亦短，抱念一無施。", "幸蒙大夫賢，加惠寬箠苔。", "撫己實已優，於道豈所期。", "終當反初服，高揖與世辭。"]'),
('c48a9953-9c3b-4216-9a5e-f1bf1d160cd4','釋奠齋居','朱熹','宋','宋诗','song-poetry','','[]','理事未逾月，簿書終日親。',72,'全唐诗/poet.song.147000.json','["理事未逾月，簿書終日親。", "簡編不及顧，几閣積埃塵。", "今辰屬齋居，煩跼一舒伸。", "瞻眺庭宇肅，仰首但秋旻。", "茂樹禽轉幽，忽如西澗濱。", "聊參物外趣，豈與俗子羣。"]'),
('9f0fb550-4716-403e-8a9d-661eeb06203b','試院雜詩五首  其一','朱熹','宋','宋诗','song-poetry','','[]','齋宇夜沉寂，凄凉群物秋。',48,'全唐诗/poet.song.147000.json','["齋宇夜沉寂，凄凉群物秋。", "卧聽簷瀉盡，心屬故園幽。", "了事知何日，分曹喜勝流。", "笑談真暫爾，不敢恨淹留。"]'),
('d8f0fb75-c9e6-4435-96ae-2a9e59988590','試院雜詩五首  其二','朱熹','宋','宋诗','song-poetry','','[]','寒燈耿欲滅，照此一窗幽。',24,'全唐诗/poet.song.147000.json','["寒燈耿欲滅，照此一窗幽。", "坐聽秋簷響，淋浪殊未休。"]'),
('a5f101fb-068b-4e4a-affd-99b708307567','試院雜詩五首  其三','朱熹','宋','宋诗','song-poetry','','[]','窮秋一雨至，暫止復蕭蕭。',48,'全唐诗/poet.song.147000.json','["窮秋一雨至，暫止復蕭蕭。", "曲沼寒流滿，空庭凉葉飄。", "聞鍾懷故宇，覽物屬今朝。", "一詠歸來賦，頓將形跡超。"]'),
('c1edc1d4-e112-41cb-8262-68665df52ffe','試院雜詩五首  其四','朱熹','宋','宋诗','song-poetry','','[]','長廊一遊步，愛此方塘凈。',48,'全唐诗/poet.song.147000.json','["長廊一遊步，愛此方塘凈。", "急雨散遥空，圓文滿幽鏡。", "階空綠苔長，院僻寒飆勁。", "長嘯不逢人，超摇得真性。"]'),
('8c33e99c-bd57-4713-a87d-ca66d12df592','試院雜詩五首  其五','朱熹','宋','宋诗','song-poetry','','[]','藝苑門禁肅，長廊似僧居。',48,'全唐诗/poet.song.147000.json','["藝苑門禁肅，長廊似僧居。", "偶來一散步，暫與塵網疎。", "文字謝時輩，銓衡頼羣儒。", "伊予獨何者，偪仄心煩紆。"]'),
('35ee78c2-0706-4d20-891d-38caa4675623','巖桂','朱熹','宋','宋诗','song-poetry','','[]','山中綠玉樹，蕭灑向秋深。',48,'全唐诗/poet.song.147000.json','["山中綠玉樹，蕭灑向秋深。", "小閣芬微度，書帷氣欲侵。", "披懷清露曉，遇賞夕嵐陰。", "珍重王孫意，天涯淚滿襟。"]'),
('a6b9be2a-bbf4-42c3-8d2e-48299a0fa30f','秋懷','朱熹','宋','宋诗','song-poetry','','[]','井梧已飄黄，澗樹猶含碧。',72,'全唐诗/poet.song.147000.json','["井梧已飄黄，澗樹猶含碧。", "煙水但逶迤，空齋坐蕭瑟。", "端居生遠興，散漫委書帙。", "愛此北窗閑，時來岸輕幘。", "微鍾忽迢遞，禽語破幽寂。", "賞罷一悁然，淡泊忘所適。"]'),
('a095649b-dc3c-489a-bb4f-68eb20ee54eb','喜晴','朱熹','宋','宋诗','song-poetry','','[]','衝飆動高柳，淥水澹微波。',48,'全唐诗/poet.song.147000.json','["衝飆動高柳，淥水澹微波。", "日照秋空凈，雨餘寒草多。", "放懷遺簿領，發興託煙蘿。", "忽念故園日，東阡時一過。"]'),
('e909c7f6-0973-46be-874c-d58ef5c5a1b8','夜賦','朱熹','宋','宋诗','song-poetry','','[]','暗窗螢影亂，秋幃露氣深。',48,'全唐诗/poet.song.147000.json','["暗窗螢影亂，秋幃露氣深。", "羣籟喧已寂，青天但沈沈。", "惻愴懷高侶，幽默抱沖襟。", "遥憶忘言子，一寫山水音。"]'),
('15d93d3c-96ba-4bc8-8434-b6974ecf3380','曉步','朱熹','宋','宋诗','song-poetry','','[]','初日麗高閣，廣步愛脩廊。',96,'全唐诗/poet.song.147000.json','["初日麗高閣，廣步愛脩廊。", "重門掩秋氣，高柳廕方塘。", "閩海冬尚溫，晏陰天未霜。", "坐悲景物殊，亦念歲時荒。", "故園屬佳辰，登覽遍陵岡。", "賓遊盡才彥，蕭散屏壺觴。", "別來時已失，懷思寧暫忘。", "宦遊何所娛，要使心懷傷。"]'),
('c008bb72-ef5b-41a0-811c-30b10e5d5b87','書事','朱熹','宋','宋诗','song-poetry','','[]','重門掩晝靜，寂無人境喧。',48,'全唐诗/poet.song.147000.json','["重門掩晝靜，寂無人境喧。", "嚴程事云已，端居秋向殘。", "超摇捐外慮，幽默與誰言。", "即此自爲樂，何用脫籠樊。"]'),
('6f29d8d6-8f29-4ef2-b4af-1ffc6ab74361','八月十七夜月','朱熹','宋','宋诗','song-poetry','','[]','忽忽秋逾半，清輝萬里同。',48,'全唐诗/poet.song.147000.json','["忽忽秋逾半，清輝萬里同。", "遥知竹林夜，共賞碧雲空。", "寂寞盈尊酒，凄凉滿院風。", "寒塘空自綠，不似小園東。"]'),
('70eef01f-e640-4341-8b1c-7dd7baac9914','憶齋中二首  其一','朱熹','宋','宋诗','song-poetry','','[]','高齋一遠眺，西南見秋山。',48,'全唐诗/poet.song.147000.json','["高齋一遠眺，西南見秋山。", "景翳夕陰起，竹密幽禽還。", "賞愜慮方融，理會心自閑。", "誰料今爲客，寥落一窗間。"]'),
('078a13f2-2e5e-441a-9148-6ffee2cd40f2','憶齋中二首  其二','朱熹','宋','宋诗','song-poetry','','[]','蟋蟀亂秋草，故園風露深。',24,'全唐诗/poet.song.147000.json','["蟋蟀亂秋草，故園風露深。", "何因不歸去，坐使百憂侵。"]'),
('44c313a6-50d1-483d-a4fb-f939b9a2bbd8','秋夕','朱熹','宋','宋诗','song-poetry','','[]','秋風桂花發，夕露寒螿吟。',48,'全唐诗/poet.song.147000.json','["秋風桂花發，夕露寒螿吟。", "歲月坐悠遠，江湖亦阻深。", "紛思寧復整，離憂信難任。", "終遣誰爲侶，獨此澹沖襟。"]'),
('5b34e463-2a15-4db2-9122-56ffa871b980','夢山中故人','朱熹','宋','宋诗','song-poetry','','[]','風雨蕭蕭已送愁，不堪懷抱更離憂。',64,'全唐诗/poet.song.147000.json','["風雨蕭蕭已送愁，不堪懷抱更離憂。", "故人只在千巖裏，桂樹無端一夜秋。", "把袖追歡勞夢寐，舉杯相屬暫綢繆。", "覺來却是天涯客，簷響潺潺瀉未休。"]'),
('86c8e381-fcf4-4d68-87d6-8683d75a34da','懷子厚','朱熹','宋','宋诗','song-poetry','','[]','中夏辭故里，涉秋未停車。',96,'全唐诗/poet.song.147000.json','["中夏辭故里，涉秋未停車。", "賓友坐離闊，田園想榛蕪。", "感茲風露朝，起望一煩紆。", "眷彼忘言子，鬰鬰西齋居。", "俯飲蒼澗流，仰咏古人書。", "名應里閭薦，心豈榮利俱。", "琅然撫枯桐，幽韻泉谷虛。", "褰裳欲往聽，乖隔靡所如。"]'),
('ed9a2392-2dbd-4678-baad-1840907568d9','南安道中','朱熹','宋','宋诗','song-poetry','','[]','曉澗淙流急，秋山寒氣深。',48,'全唐诗/poet.song.147000.json','["曉澗淙流急，秋山寒氣深。", "高蟬多遠韻，茂樹有餘陰。", "煙火居民少，荒蹊草露侵。", "悠悠秋稼晚，寥落歲寒心。"]'),
('52807d21-a4ff-426a-8763-c26b34bf8441','垂澗藤','朱熹','宋','宋诗','song-poetry','','[]','寒泉下碧澗，古木垂蒼藤。',36,'全唐诗/poet.song.147000.json','["寒泉下碧澗，古木垂蒼藤。", "蔭此萬里流，閑花自層層。", "何人賞幽致，白髮巖中僧。"]'),
('28afcb79-17bf-44d0-9051-6c4f0be40ff9','臨流石','朱熹','宋','宋诗','song-poetry','','[]','偃蹇西澗濱，枵然似枯木。',36,'全唐诗/poet.song.147000.json','["偃蹇西澗濱，枵然似枯木。", "下有幽泉鳴，上有蒼苔綠。", "來往定何人，山空此遺躅。"]'),
('d9ca7d5c-530e-406d-9377-d9087d6eb388','懸崖水','朱熹','宋','宋诗','song-poetry','','[]','秋天林薄踈，翠壁呈清曉。',36,'全唐诗/poet.song.147000.json','["秋天林薄踈，翠壁呈清曉。", "迢遞瀉寒泉，下有深潭悄。", "時飄桂葉來，尋源路殊杳。"]'),
('a8bd99c1-1125-43a6-9c64-64e3df14c376','穿林徑','朱熹','宋','宋诗','song-poetry','','[]','屈曲上雲端，似向崖陰斷。',36,'全唐诗/poet.song.147000.json','["屈曲上雲端，似向崖陰斷。", "行聞山鳥鳴，下與泉聲亂。", "去去不知疲，幽林自成玩。"]'),
('8b14e66c-2b8e-4dc4-ae16-972d3f22f332','九日','朱熹','宋','宋诗','song-poetry','','[]','故國音書阻一方，天涯此日思茫茫。',64,'全唐诗/poet.song.147000.json','["故國音書阻一方，天涯此日思茫茫。", "風煙歲晚添離恨，湖海尊前即大荒。", "薄宦驅人向愁悴，舊遊惟我最顛狂。", "細思萬石亭前事，辜負黄花滿帽香。"]'),
('ae50f6b5-8e02-4730-bac9-36530509ac3e','督役城樓','朱熹','宋','宋诗','song-poetry','','[]','天高無遊氣，林景澹餘暉。',72,'全唐诗/poet.song.147000.json','["天高無遊氣，林景澹餘暉。", "感此霜露節，但傷風土非。", "季秋時序溫，百卉不復腓。", "祗役郊原上，暄風一吹衣。", "仕身諒無補，課督漸饑羸。", "還憶故園日，策杖田中歸。"]'),
('a2212725-b84d-46a1-ac1c-e82ae8e2ce0d','再至作','朱熹','宋','宋诗','song-poetry','','[]','荒城一騁望，落景麗譙門。',48,'全唐诗/poet.song.147000.json','["荒城一騁望，落景麗譙門。", "隠隠鍾猶度，依依嵐欲昏。", "風霜非故里，禾黍但秋原。", "極目歸來晚，茲懷誰與論。"]'),
('de220b0e-b628-4879-b657-218f413c7ae5','晚望','朱熹','宋','宋诗','song-poetry','','[]','禾黍彌平野，凄凉故國秋。',48,'全唐诗/poet.song.147000.json','["禾黍彌平野，凄凉故國秋。", "清霜凝碧樹，落日翳層丘。", "覽物知時變，爲農覺歲遒。", "不堪從吏役，憔悴欲歸休。"]'),
('7070f1c2-200d-4af9-b1e9-ee1806bcc2d2','苧溪道中','朱熹','宋','宋诗','song-poetry','','[]','秋山有紅樹，忽憶野田中。',48,'全唐诗/poet.song.147000.json','["秋山有紅樹，忽憶野田中。", "禾黍收將盡，氛埃晚欲空。", "登原悲落景，倚杖怯高風。", "更有寒塘水，應將此處同。"]'),
('cc9893a3-96d8-4e09-a1b8-745d3ce0b8fe','十月朔旦懷先隴作','朱熹','宋','宋诗','song-poetry','','[]','十月氣候變，獨懷霜露悽。',72,'全唐诗/poet.song.147000.json','["十月氣候變，獨懷霜露悽。", "僧廬寄楸檟，饋奠失茲時。", "竹柏翳陰岡，華林敞神扉。", "汛掃託群隸，瞻護煩名緇。", "封塋諒久安，千里一歔欷。", "持身慕前烈，銜訓倘在斯。"]'),
('331401c9-2b3d-403e-98b8-2c5ad422d1ac','步虛詞二首  其一','朱熹','宋','宋诗','song-poetry','','[]','扉景廓天津，空同無員方。',96,'全唐诗/poet.song.147000.json','["扉景廓天津，空同無員方。", "丹晨儛七氣，朵秀東渟房。", "餐吐碧琳華，仰噏飛霞漿。", "竦轡絕冥外，眄目撫大荒。", "策我綠軒軿，上際於浪滄。", "神鈞亦寥朗，晻靄晨風翔。", "養翮塵波裏，縱神非有亡。", "一樂無終永，千春詎能當。"]'),
('27a4d428-c0db-4c45-8e20-a7bf6cdf49e1','步虛詞二首  其二','朱熹','宋','宋诗','song-poetry','','[]','褰裳八度外，竦轡霄上遊。',84,'全唐诗/poet.song.147000.json','["褰裳八度外，竦轡霄上遊。", "軒觀隨雲起，偃駕東渟丘。", "丹荑耀瓊岡，三素粲曾幽。", "躡景遺塵波，偶想即虛柔。", "盼目娛真際，不喜亦不憂。", "宴罷三椿期，顛徊翳滄流。", "千載何足道，太空自然疇。"]'),
('ebd2966e-a46d-40b1-9c98-05a422b716d2','民安道中','朱熹','宋','宋诗','song-poetry','','[]','祗役東原路，長風海氣陰。',48,'全唐诗/poet.song.147000.json','["祗役東原路，長風海氣陰。", "蒼茫生遠思，憭慄起寒襟。", "午泊僧寮靜，昏投縣郭深。", "拙勤終不補，誰使漫勞心。"]'),
('0b9b5e60-75d1-4e10-9a48-cac472ba36e3','西郊縱步','朱熹','宋','宋诗','song-poetry','','[]','西郊一遊步，極目是秋山。',48,'全唐诗/poet.song.147000.json','["西郊一遊步，極目是秋山。", "積水羣峰碧，清霜楓樹丹。", "故園心不展，投策詎能閑。", "且適平生意，無令雙鬢斑。"]'),
('b9a0911a-b014-45d1-bdf0-d569bfe2d559','寄黄子衡','朱熹','宋','宋诗','song-poetry','','[]','遠宦去鄉井，終日無一歡。',72,'全唐诗/poet.song.147000.json','["遠宦去鄉井，終日無一歡。", "援琴不能操，臨觴起長歎。", "我友客京都，肅肅雲天翰。", "別去今幾時，各在天一端。", "有酒不同斟，中情誰與宣。", "裁詩一問訊，重使心思傳。"]'),
('7be80f11-7be9-4121-808e-af56120b6229','濯足萬里流','朱熹','宋','宋诗','song-poetry','','[]','褰裳緣碧澗，濯足憇清幽。',48,'全唐诗/poet.song.147000.json','["褰裳緣碧澗，濯足憇清幽。", "却拂千巖石，聊乘萬里流。", "氛埃隨脫屣，步武欲橫秋。", "極目滄江晚，煙波殊未休。"]'),
('fb16da8d-7ef0-4bc6-b144-aa4e7a3d104a','孤鶴思太清','朱熹','宋','宋诗','song-poetry','','[]','孤鶴悲秋晚，凌風絕太清。',48,'全唐诗/poet.song.147000.json','["孤鶴悲秋晚，凌風絕太清。", "一爲棲苑客，空有叫群聲。", "夭矯千年質，飄颻萬里情。", "九臯無枉路，從遣碧雲生。"]'),
('c8a34d53-c907-413f-9600-f81f090f0c1e','與諸同寮謁奠北山過白巖小憩','朱熹','宋','宋诗','song-poetry','','[]','聯車涉修坂，覽物窮山川。',120,'全唐诗/poet.song.147000.json','["聯車涉修坂，覽物窮山川。", "踈林汎朝景，翠嶺含雲煙。", "祠殿何沈邃，古木鬰蒼然。", "明靈自安宅，牲酒告恭虔。", "肸蠁理潜通，神虯亦蜿蜒。", "既欣歲事舉，重喜景物妍。", "解带憩精廬，尊酌且留連。", "縱談遺名跡，煩慮絕拘牽。", "迅晷諒難留，歸軫忽已騫。", "蒼蒼暮色起，反旆東城阡。"]'),
('a0dc7461-eb14-49db-a883-334707818582','懷山田作二首  其一','朱熹','宋','宋诗','song-poetry','','[]','郊園多所樂，况此歲云暮。',48,'全唐诗/poet.song.147000.json','["郊園多所樂，况此歲云暮。", "寒色澹遥空，清霜變紅樹。", "欲舒林表望，詎識塵中趣。", "向晚寂無人，氤氳欲成霧。"]'),
('784a4a8d-691e-433f-8e1f-20dc68b7acd4','懷山田作二首  其二','朱熹','宋','宋诗','song-poetry','','[]','冰溪流已咽，陰嶺寒方結。',48,'全唐诗/poet.song.147000.json','["冰溪流已咽，陰嶺寒方結。", "忽值早梅春，未恐芳心歇。", "的皪終自妍，殷勤爲誰折。", "千里寄相思，相思政愁絕。"]'),
('3f61f44b-ee31-4338-89a4-5f015f701c02','夜雨二首  其一','朱熹','宋','宋诗','song-poetry','','[]','擁衾獨宿聽寒雨，聲在荒庭竹樹間。',32,'全唐诗/poet.song.147000.json','["擁衾獨宿聽寒雨，聲在荒庭竹樹間。", "萬里故園今夜永，遥知風雪滿前山。"]'),
('def2cf10-ea21-413f-9b4a-2b194f92b675','夜雨二首  其二','朱熹','宋','宋诗','song-poetry','','[]','故山風雪深寒夜，只有梅花獨自香。',32,'全唐诗/poet.song.147000.json','["故山風雪深寒夜，只有梅花獨自香。", "此日無人問消息，不應憔悴損年芳。"]'),
('3f68b52a-982e-42d3-8618-44918f5c0637','將理西齋','朱熹','宋','宋诗','song-poetry','','[]','欲理西齋居，厭茲塵境擾。',48,'全唐诗/poet.song.147000.json','["欲理西齋居，厭茲塵境擾。", "發地得幽芳，斸石依寒篠。", "閑暇一題詩，懷沖獨觀眇。", "偶此愜高情，公門何日了。"]'),
('27ce1b17-0bcd-4521-b0f4-9f182540e8a5','寄題金元鼎同年長泰面山亭','朱熹','宋','宋诗','song-poetry','','[]','抗心塵境外，結宇臨秋山。',72,'全唐诗/poet.song.147000.json','["抗心塵境外，結宇臨秋山。", "乘高一騁望，表裏窮遐觀。", "衆崿互攢列，連岡莽縈環。", "陽崖煙景舒，陰壑悲風寒。", "碧草晚未凋，林薄已復丹。", "仙人吳門子，歲晚當來還。"]'),
('ba3e0071-c1c1-401c-b556-83f39f86f035','冬至陰雨','朱熹','宋','宋诗','song-poetry','','[]','愆陽值歲晏，忽復層陰結。',72,'全唐诗/poet.song.147000.json','["愆陽值歲晏，忽復層陰結。", "一雨散霏微，千林共騷屑。", "端居遺簿領，遠意懷幽潔。", "曠慮守微痾，殊方感新節。", "豈伊田廬念，丘壠心摧折。", "還登東領岡，瞻竚何由歇。"]'),
('488ea3bd-893d-4d60-b582-fa36b1468e6e','安溪道中泉石奇甚絕類建劍間山水佳處也','朱熹','宋','宋诗','song-poetry','','[]','驅車陟連岡，振轡出林莽。',72,'全唐诗/poet.song.147000.json','["驅車陟連岡，振轡出林莽。", "霧露曉方除，日照川如掌。", "行行遵曲岸，水石窮幽賞。", "地偏寒篠多，澗激淙流響。", "祗役未忘倦，心神暫蕭爽。", "感茲懷故山，何日稅征鞅。"]'),
('b4ab5790-2c49-4814-b4ea-01ae9b631614','留安溪三日按事未竟','朱熹','宋','宋诗','song-poetry','','[]','縣郭四依山，清流下如駛。',72,'全唐诗/poet.song.147000.json','["縣郭四依山，清流下如駛。", "居民煙火少，市列無行次。", "嵐陰常至午，陽景猶氛翳。", "向夕悲風多，遊子不遑寐。", "我來亦何事，吏乘古所記。", "奉檄正淹留，何當語歸計。"]'),
('4032d05d-a174-421f-8dd4-07bd53c6ac5c','安溪書事','朱熹','宋','宋诗','song-poetry','','[]','清溪流不極，夕霧起嵐陰。',48,'全唐诗/poet.song.147000.json','["清溪流不極，夕霧起嵐陰。", "虛邑带寒水，悲風號遠林。", "涵山日欲晦，窺閣景方沉。", "極目無遺眺，空令愁寸心。"]'),
('605e620c-37e8-420a-8534-c13652419e15','梅花兩絕句  其一','朱熹','宋','宋诗','song-poetry','','[]','溪上寒梅應已開，故人不寄一枝來。',32,'全唐诗/poet.song.147000.json','["溪上寒梅應已開，故人不寄一枝來。", "天涯豈是無芳物，爲爾無心向酒杯。"]'),
('a3b46afd-c3cb-45d4-a7a4-0348ac412806','梅花兩絕句  其二','朱熹','宋','宋诗','song-poetry','','[]','幽壑潺湲小水通，茅茨煙雨竹籬空。',32,'全唐诗/poet.song.147000.json','["幽壑潺湲小水通，茅茨煙雨竹籬空。", "梅花亂發籬邊樹，似倚寒枝恨朔風。"]'),
('e2b01cf2-b602-4a4d-be19-842421295e65','柚花','朱熹','宋','宋诗','song-poetry','','[]','春融百卉茂，素榮敷綠枝。',48,'全唐诗/poet.song.147000.json','["春融百卉茂，素榮敷綠枝。", "淑郁麗芳遠，悠颺風日遲。", "南國富嘉樹，騷人留恨詞。", "空齋對日夕，愁絕鬢成絲。"]'),
('be573032-3400-4872-b231-499e0a6ceb50','病告齋居作','朱熹','宋','宋诗','song-poetry','','[]','層陰靄已布，小雨時漂洒。',60,'全唐诗/poet.song.147000.json','["層陰靄已布，小雨時漂洒。", "獨卧一窗間，有懷無與寫。", "高居生遠興，春物彌平野。", "慮曠景方融，事遠情無捨。", "聊寄茲日閑，塵勞等虛假。"]'),
('bdbaeea2-aab6-4276-ba46-992d1033849c','感事有嘆','朱熹','宋','宋诗','song-poetry','','[]','榮華難久恃，代謝安可量。',96,'全唐诗/poet.song.147000.json','["榮華難久恃，代謝安可量。", "宿昔堂上飲，今歸荒草鄉。", "高臺一以傾，繐帳施空房。", "繁絃既闕奏，緩舞亦輟行。", "桃李自妍華，春風自飄揚。", "戀幄靡遺思，更衣有餘芳。", "身徂名亦滅，事往恨空長。", "寄語繁華子，古今同一傷。"]'),
('5079489b-70c5-4c2c-bdc5-6800fe41e357','夏日','朱熹','宋','宋诗','song-poetry','','[]','凉氣集幽樹，清陰生廣庭。',48,'全唐诗/poet.song.147000.json','["凉氣集幽樹，清陰生廣庭。", "偶茲憩煩燠，忽憶郊園行。", "婉娩碧草滋，迢遞玄蟬鳴。", "官曹且休暇，自適幽居情。"]'),
('68ce3bfa-a0ac-475a-bf7c-537b8247b69f','聞蟬','朱熹','宋','宋诗','song-poetry','','[]','悄悄山郭暗，故園應掩扉。',24,'全唐诗/poet.song.147000.json','["悄悄山郭暗，故園應掩扉。", "蟬聲深樹起，林外夕陽稀。"]'),
('10db2630-3a17-45d1-9d40-95116721bdfc','秋夜歎','朱熹','宋','宋诗','song-poetry','','[]','秋風淅瀝鳴清商，秋草未死啼寒螿。',64,'全唐诗/poet.song.147000.json','["秋風淅瀝鳴清商，秋草未死啼寒螿。", "幽人幽人起晤歎，仰視河漢天中央。", "河漢西流去不息，人生辛苦何終極。", "蒼山萬疊雲氣深，去鍊形魂生羽翼。"]'),
('d97de329-32fd-4570-896f-aff21bdbade0','茅舍獨飲','朱熹','宋','宋诗','song-poetry','','[]','出身從吏役，驅車涉窮山。',48,'全唐诗/poet.song.147000.json','["出身從吏役，驅車涉窮山。", "日落陰景晦，天高風氣寒。", "豈無斗酒資，獨酌誰爲歡。", "一盃且復醉，百念中闌干。"]'),
('2cc293d2-eb8c-40b8-96d8-2b5922837100','宿傳舍見月','朱熹','宋','宋诗','song-poetry','','[]','空堂寒夜月華清，獨宿凄凉夢不成。',32,'全唐诗/poet.song.147000.json','["空堂寒夜月華清，獨宿凄凉夢不成。", "欲向階前舞凌亂，手持杯酒爲誰傾。"]'),
('a9531511-daad-4c16-b361-1d2aefc611b3','寄諸同寮','朱熹','宋','宋诗','song-poetry','','[]','把酒江頭煙雨時，遥知江樹已芳菲。',32,'全唐诗/poet.song.147000.json','["把酒江頭煙雨時，遥知江樹已芳菲。", "應憐倦客荒茅裏，落盡梅花未得歸。"]'),
('1ad392dc-3548-4f68-83f5-637227109caf','登羅漢峰','朱熹','宋','宋诗','song-poetry','','[]','休暇曹事簡，登高恣窺臨。',72,'全唐诗/poet.song.147000.json','["休暇曹事簡，登高恣窺臨。", "徜徉偶此地，曠望披塵襟。", "落日瞰遠郊，暮色生寒陰。", "歡娛未云已，更欲窮幽尋。", "行披茂樹盡，豁見滄溟深。", "恨無雙飛翼，往詣蓬山岑。"]'),
('be0919e5-a758-4284-b0d9-d373926e4916','登面山亭','朱熹','宋','宋诗','song-poetry','','[]','新亭夙所聞，登眺遂茲日。',48,'全唐诗/poet.song.147000.json','["新亭夙所聞，登眺遂茲日。", "極目但蒼茫，前瞻如有失。", "煙鬟稍呈露，衆嶺方含鬰。", "長嘯天風來，雲散空宇碧。"]'),
('4c578327-96d9-471e-803d-ff4c982b68f1','雙髻峰','朱熹','宋','宋诗','song-poetry','','[]','絕壑藤蘿貯翠煙，水聲幽咽亂峯前。',32,'全唐诗/poet.song.147000.json','["絕壑藤蘿貯翠煙，水聲幽咽亂峯前。", "行人但說青山好，腸斷雲間雙髻仙。"]'),
('1cf5df53-bf67-4e55-ad38-f9ea889b2639','涉澗水作','朱熹','宋','宋诗','song-poetry','','[]','幽谷濺濺小水通，細穿危石認行蹤。',32,'全唐诗/poet.song.147000.json','["幽谷濺濺小水通，細穿危石認行蹤。", "回頭自愛情嵐好，却立灘頭數亂峰。"]'),
('d773f048-52c2-4bda-871f-f5ef415644a1','試院即事','朱熹','宋','宋诗','song-poetry','','[]','端居惜春晚，庭樹綠已深。',48,'全唐诗/poet.song.147000.json','["端居惜春晚，庭樹綠已深。", "重門掩晝靜，高館正陰沈。", "披衣步前除，悟物懷貞心。", "澹泊方自適，好鳥鳴高林。"]'),
('af408820-1ae1-46d6-ba23-57fe8441b72b','借王嘉叟所藏趙祖文畫孫興公天台賦凝思幽巖朗詠長川一幅有契于心因作此詩二首  其一','朱熹','宋','宋诗','song-poetry','','[]','翩然乘孤鶴，往至蒼崖巔。',48,'全唐诗/poet.song.147000.json','["翩然乘孤鶴，往至蒼崖巔。", "上有桂樹林，下有清泠淵。", "洗心詠太素，汎景窺靈詮。", "棲身託歲暮，畢此巖中緣。"]'),
('76f4a9ed-162b-4be9-94e0-8eec9c1039dc','借王嘉叟所藏趙祖文畫孫興公天台賦凝思幽巖朗詠長川一幅有契于心因作此詩二首  其二','朱熹','宋','宋诗','song-poetry','','[]','山空四無人，澗樹生凉秋。',48,'全唐诗/poet.song.147000.json','["山空四無人，澗樹生凉秋。", "杖策忘所適，水木娛清幽。", "散髮塵外飆，濯足清瑶流。", "靜嘯長林內，舉翮仍丹丘。"]'),
('b318168d-4620-49a1-a3b5-1b7e2f6ea80f','雜記草木九首  其一','朱熹','宋','宋诗','song-poetry','','[]','高蘿引蔓長，插楥垂碧絲。',24,'全唐诗/poet.song.147000.json','["高蘿引蔓長，插楥垂碧絲。", "西窗夜來雨，無人領幽姿。"]'),
('1db66ed1-8c08-427c-92b8-89ac69fcf788','雜記草木九首  其二','朱熹','宋','宋诗','song-poetry','','[]','弱植不自持，芳根爲誰好。',24,'全唐诗/poet.song.147000.json','["弱植不自持，芳根爲誰好。", "雖微九秋幹，丹心中自保。"]'),
('cce2d256-0d16-4e8d-8735-4bded9422e05','雜記草木九首  其三','朱熹','宋','宋诗','song-poetry','','[]','根節含露辛，苕穎扶楥綠。',24,'全唐诗/poet.song.147000.json','["根節含露辛，苕穎扶楥綠。", "蠻中靈草多，夏永清陰足。"]'),
('9dd26329-8b0b-496d-89f4-b711db180c98','雜記草木九首  其四','朱熹','宋','宋诗','song-poetry','','[]','種竹官牆陰，經年但憔悴。',24,'全唐诗/poet.song.147000.json','["種竹官牆陰，經年但憔悴。", "故園新綠多，宿幹轉蒼翠。"]'),
('75a9b5eb-864b-4f4f-9af9-9d47204861ea','雜記草木九首  其五','朱熹','宋','宋诗','song-poetry','','[]','窈窕安榴花，乃是西鄰樹。',24,'全唐诗/poet.song.147000.json','["窈窕安榴花，乃是西鄰樹。", "墜萼可憐人，風吹落幽戶。"]'),
('d164693f-4a71-448b-80f2-bfd2c1e436bf','雜記草木九首  其六','朱熹','宋','宋诗','song-poetry','','[]','春條擁深翠，夏花明夕陰。',24,'全唐诗/poet.song.147000.json','["春條擁深翠，夏花明夕陰。", "北堂罕悴物，獨爾澹沖襟。"]'),
('7c200119-4e7e-4dac-91d0-d5e009be116b','雜記草木九首  其七','朱熹','宋','宋诗','song-poetry','','[]','西窗萱草藂，昔是何人種。',24,'全唐诗/poet.song.147000.json','["西窗萱草藂，昔是何人種。", "移向北堂前，諸孫時遶弄。"]'),
('3ff9b312-f16c-4f47-a398-c242c1faf61c','雜記草木九首  其八','朱熹','宋','宋诗','song-poetry','','[]','端居春向殘，夏氣已清穆。',24,'全唐诗/poet.song.147000.json','["端居春向殘，夏氣已清穆。", "睡起悄無人，風驚滿窗綠。"]'),
('3a5dc511-8fe0-46e6-a5a4-040aba893c0d','雜記草木九首  其九','朱熹','宋','宋诗','song-poetry','','[]','晨起獨行園，花藥發奇穎。',24,'全唐诗/poet.song.147000.json','["晨起獨行園，花藥發奇穎。", "猶嫌墜露稀，更汲寒泉井。"]'),
('6530f685-09af-4893-b29c-3a6483ba05c1','觀黄德美延平春望兩圖爲賦二首  其一','朱熹','宋','宋诗','song-poetry','','[]','川流匯南奔，山豁類天闢。',24,'全唐诗/poet.song.147000.json','["川流匯南奔，山豁類天闢。", "層甍麗西崖，朝旦群峯碧。"]'),
('67042113-755e-486a-adbc-51bb8e1aad82','觀黄德美延平春望兩圖爲賦二首  其二','朱熹','宋','宋诗','song-poetry','','[]','方舟越大江，凌風下飛閣。',24,'全唐诗/poet.song.147000.json','["方舟越大江，凌風下飛閣。", "仙子去不還，蒼屏倚寥廓。"]'),
('9f715dff-e16f-4251-a76b-053549d1391b','祠事齋居聽雨呈劉子晉','朱熹','宋','宋诗','song-poetry','','[]','刀筆常時篋笥盈，齋祠今喜骨毛清。',32,'全唐诗/poet.song.147000.json','["刀筆常時篋笥盈，齋祠今喜骨毛清。", "與君此日俱無事，共愛寒階滴雨聲。"]'),
('002ee783-b0c8-452d-98a2-a8683fbf6f24','送王季山赴龍溪','朱熹','宋','宋诗','song-poetry','','[]','故人千石令，便道此之官。',48,'全唐诗/poet.song.147000.json','["故人千石令，便道此之官。", "契闊三秋永，逢迎一笑懽。", "田園知不遠，謠俗問非難。", "已想躬玄默，鳴絃亦罷彈。"]'),
('9626baf3-0c43-4994-8e2b-3a87b8eb138d','之德化宿劇頭鋪夜聞杜宇','朱熹','宋','宋诗','song-poetry','','[]','王事賢勞只自嗤，一官今是五年期。',32,'全唐诗/poet.song.147000.json','["王事賢勞只自嗤，一官今是五年期。", "如何獨宿荒山夜，更擁寒衾聽子規。"]'),
('86eb9c25-7b1a-4783-9bf0-2f108db7539e','次韻傅丈題呂少衛教授藏書閣','朱熹','宋','宋诗','song-poetry','','[]','西樓誰與共閑居，茂樹婆娑清晝餘。',64,'全唐诗/poet.song.147000.json','["西樓誰與共閑居，茂樹婆娑清晝餘。", "大隠祇今同一壑，行吟非昔似三閭。", "揣摩心事惟黄卷，料理家傳亦素書。", "更鑿寒泉供漱石，世紛不擬問焉如。"]'),
('ddbf30ae-0fb2-4f24-8823-2a0068719348','次旬父韻','朱熹','宋','宋诗','song-poetry','','[]','五字何人寄，鏘鳴滿袖金。',48,'全唐诗/poet.song.147000.json','["五字何人寄，鏘鳴滿袖金。", "劇知多暇日，誰與共幽尋。", "簿領淹窮海，鶑花遶故林。", "功名終好在，且莫負初心。"]'),
('46a2d546-a75a-4f6e-8a4f-3349a798dc7c','次祝澤之表兄韻','朱熹','宋','宋诗','song-poetry','','[]','裸裎相向但悠悠，信道乾坤日夜浮。',64,'全唐诗/poet.song.147000.json','["裸裎相向但悠悠，信道乾坤日夜浮。", "此去安心知有法，向來示病不難瘳。", "優游靜室閑窗底，放浪東阡南陌頭。", "萬事何由到懷抱，夕陽芳草自春秋。"]'),
('5765e833-01da-4b7f-9fde-2fdd114e0455','次祝澤之表兄韻送劉子晉歸省','朱熹','宋','宋诗','song-poetry','','[]','之子真吾友，心期到古人。',48,'全唐诗/poet.song.147000.json','["之子真吾友，心期到古人。", "慇懃來講學，迢遞遠辭親。", "黄卷工夫妙，斑衣夢想頻。", "今朝首歸路，何處問知津。"]'),
('dcf0192c-32cc-4dc7-9267-9ea65f7f87a8','送祝澤之表兄還鄉','朱熹','宋','宋诗','song-poetry','','[]','首夏何來此，清秋却復歸。',48,'全唐诗/poet.song.147000.json','["首夏何來此，清秋却復歸。", "應緣心未快，豈是世相違。", "落日空書館，凉風凈客衣。", "功名須努力，別淚莫頻揮。"]'),
('136bebb4-51c3-4fc8-9794-3fef245561e2','知郡傅丈載酒幞被過熹於九日山夜泛小舟弄月劇飲二首  其一','朱熹','宋','宋诗','song-poetry','','[]','扁舟轉空闊，煙水浩將平。',48,'全唐诗/poet.song.147000.json','["扁舟轉空闊，煙水浩將平。", "月色中流滿，秋聲兩岸生。", "杯深同醉極，嘯罷獨魂驚。", "歸去空山黑，西南河漢傾。"]'),
('032ebcd1-06aa-4498-8c44-90a3d2a3139b','知郡傅丈載酒幞被過熹於九日山夜泛小舟弄月劇飲二首  其二','朱熹','宋','宋诗','song-poetry','','[]','誰知方外客，亦愛酒中仙。',48,'全唐诗/poet.song.147000.json','["誰知方外客，亦愛酒中仙。", "共踏空林月，來尋野渡船。", "醉醒非各趣，心跡兩忘緣。", "江海情何限，秋生蓬鬢邊。"]'),
('94e15db4-63b9-4af2-8a40-fc913fcad8d3','教思堂作示諸同志','朱熹','宋','宋诗','song-poetry','','[]','吏局了無事，橫舍終日閑。',72,'全唐诗/poet.song.147000.json','["吏局了無事，橫舍終日閑。", "庭樹秋風至，凉氣滿窗間。", "高閣富文史，諸生時往還。", "縱談忽忘倦，時觀非云慳。", "詠歸同與點，坐忘庶希顔。", "塵累日以銷，何必棲空山。"]'),
('ba82375f-fd31-4b55-8354-b432ced9bc34','再得古木','朱熹','宋','宋诗','song-poetry','','[]','青山一何深，上下盡雲木。',48,'全唐诗/poet.song.147000.json','["青山一何深，上下盡雲木。", "中有千歲姿，偃蹇卧寒谷。", "明堂不徵材，大匠肯回目。", "樵斧莫謾尋，從渠媚幽獨。"]'),
('9dd6fb29-7330-4b98-8acc-3c3511bafc2f','示諸同志','朱熹','宋','宋诗','song-poetry','','[]','夏木已云暗，時禽變新聲。',96,'全唐诗/poet.song.147000.json','["夏木已云暗，時禽變新聲。", "林園草被徑，端居有餘清。", "端居亦何爲，日夕掩柴荆。", "靜有絃誦樂，而無塵慮并。", "良朋肯顧予，尚有夙心傾。", "深慚未聞道，折衷非所寧。", "眷焉撫流光，中夜歎以驚。", "高山徒仰止，遠道何由征。"]'),
('04f84ad2-885e-4c7f-8a1a-871d7b34f424','示四弟','朱熹','宋','宋诗','song-poetry','','[]','十日一洗沐，諸生各歸休。',48,'全唐诗/poet.song.147000.json','["十日一洗沐，諸生各歸休。", "虛齋息羣響，兀坐心悠悠。", "雨久苔徑荒，林深鳥啼幽。", "階前樹萱草，與子俱忘憂。"]'),
('4a380dc8-500d-4e6a-8583-fdfdcdc957ff','還家即事','朱熹','宋','宋诗','song-poetry','','[]','獻歲事行役，徂春始還歸。',84,'全唐诗/poet.song.147000.json','["獻歲事行役，徂春始還歸。", "昔往草未芳，今來翠成幃。", "扶踈滿園陰，時禽互翻飛。", "叢萱亦已秀，丹葩耀晨輝。", "即事誰與娛，淹留自忘機。", "日暮復出門，悵然心事違。", "古人不可見，獨掩荒園扉。"]'),
('899df567-4a86-46a6-a070-01b1983325fb','小盈道中','朱熹','宋','宋诗','song-poetry','','[]','今朝行役是登臨，極目郊原快賞心。',32,'全唐诗/poet.song.147000.json','["今朝行役是登臨，極目郊原快賞心。", "却笑從前嫌俗事，一春牢落閉門深。"]'),
('699ba2dd-e479-408c-a617-50e19462f8de','題囊山寺','朱熹','宋','宋诗','song-poetry','','[]','曉發漁溪驛，夜宿囊山寺。',48,'全唐诗/poet.song.147000.json','["曉發漁溪驛，夜宿囊山寺。", "雲海近蒼茫，層嵐擁深翠。", "行役倦脩途，投歸聊一憩。", "不學塔中仙，名塗定何事。"]'),
('e4b52857-44e7-44b2-bed5-5fec4bd41e07','題九日山石佛院亂峰軒二首  其一','朱熹','宋','宋诗','song-poetry','','[]','因依古佛居，結屋寒林杪。',24,'全唐诗/poet.song.147000.json','["因依古佛居，結屋寒林杪。", "當戶碧峯稠，雲烟自昏曉。"]'),
('1c7ac730-883d-4ab0-beea-caf9e50d08b3','題九日山石佛院亂峰軒二首  其二','朱熹','宋','宋诗','song-poetry','','[]','巖中老釋子，白髮對青山。',24,'全唐诗/poet.song.147000.json','["巖中老釋子，白髮對青山。", "不作看山想，秋雲時往還。"]'),
('7a987be7-6e77-4169-8154-5a385445893a','題可老所藏徐明叔畫卷二首  其一','朱熹','宋','宋诗','song-poetry','','[]','羣峯相接連，斷處秋雲起。',24,'全唐诗/poet.song.147000.json','["羣峯相接連，斷處秋雲起。", "雲起山更深，咫尺愁千里。"]'),
('23bff97c-8757-4f6e-9426-cb49d1e57ed6','題可老所藏徐明叔畫卷二首  其二','朱熹','宋','宋诗','song-poetry','','[]','流雲繞空山，絕壁上蒼翠。',24,'全唐诗/poet.song.147000.json','["流雲繞空山，絕壁上蒼翠。", "應有采芝人，相期烟雨外。"]'),
('517e2e3a-1509-41a7-9398-0096639276a0','再至同安假民舍以居示諸生','朱熹','宋','宋诗','song-poetry','','[]','端居託窮巷，廩食守微官。',72,'全唐诗/poet.song.147000.json','["端居託窮巷，廩食守微官。", "事少心慮怡，吏休庭宇寬。", "晨興吟誦餘，體物隨所安。", "杜門不復出，悠然得真歡。", "良朋夙所敦，精義時一殫。", "壺餐雖牢落，此亦非所難。"]'),
('ddb30233-a941-48b8-9196-84cce544de76','六月十五日詣水公菴雨作','朱熹','宋','宋诗','song-poetry','','[]','雲起欲爲雨，中川分晦明。',96,'全唐诗/poet.song.147000.json','["雲起欲爲雨，中川分晦明。", "纔驚橫嶺斷，已覺踈林鳴。", "空際旱塵滅，虛堂凉思生。", "頹簷滴瀝餘，忽作流泉傾。", "况此高人居，地偏園景清。", "芳馨雜悄蒨，俯仰同鮮榮。", "我來偶茲適，中懷澹無營。", "歸路綠泱漭，因之想巖耕。"]'),
('8b319249-a2c4-4037-8abf-abdcd65df05c','末利','朱熹','宋','宋诗','song-poetry','','[]','曠然塵慮盡，爲對夕花明。',48,'全唐诗/poet.song.147000.json','["曠然塵慮盡，爲對夕花明。", "密葉低層幄，冰蕤亂玉英。", "不因秋露濕，詎識此香清。", "預恐芳菲盡，微吟遶砌行。"]'),
('bf9f72fa-4d0b-4a4d-adf3-5d56ddf25c97','謝人送蘭  其一','朱熹','宋','宋诗','song-poetry','','[]','幽獨塵事屏，晼晚秋蘭滋。',48,'全唐诗/poet.song.147000.json','["幽獨塵事屏，晼晚秋蘭滋。", "芳馨不自媚，掩抑空相思。", "晤對日方永，披叢露未晞。", "翛然發孤詠，九畹陳悲詩。"]'),
('23f9f4ec-a9ed-45db-b2c7-4989515d4bc2','謝人送蘭  其二','朱熹','宋','宋诗','song-poetry','','[]','淹留閲歲序，契闊心懷憂。',84,'全唐诗/poet.song.147000.json','["淹留閲歲序，契闊心懷憂。", "獨卧寄僧閭，一室空山秋。", "徘徊起顧望，俯仰誰爲儔。", "伊人遠贈問，孤根亦綢繆。", "芳馨不我遺，三載娛清幽。", "愧無瓊琚報，厚意竟莫酬。", "瞻彼南陔詩，使我心悠悠。"]'),
('80a5bbb1-b643-4a31-8f20-0c0a9c0f30d9','秋蘭已悴以其根歸學古','朱熹','宋','宋诗','song-poetry','','[]','秋至百草晦，寂寞寒露滋。',48,'全唐诗/poet.song.147000.json','["秋至百草晦，寂寞寒露滋。", "蘭皋一以悴，蕪穢不能治。", "端居念離索，無以遺所思。", "願言託孤根，歲晏以爲期。"]'),
('b508bda4-2a53-4038-8df3-8126a8c03947','去歲蒙學古分惠蘭花清賞既歇復以根叢歸之故畹而學古預有今歲之約近聞頗已著花輒賦小詩以尋前約幸一笑','朱熹','宋','宋诗','song-poetry','','[]','秋蘭遞初馥，芳意滿沖襟。',48,'全唐诗/poet.song.147000.json','["秋蘭遞初馥，芳意滿沖襟。", "想子空齋裏，凄凉楚客心。", "夕風生遠思，晨露灑中林。", "頗憶孤根在，幽期得重尋。"]'),
('74300a6e-ef3d-4c6c-a833-4edbce0ab348','秋夕二首  其一','朱熹','宋','宋诗','song-poetry','','[]','西齋坐竟日，曠然誰與儔。',48,'全唐诗/poet.song.147000.json','["西齋坐竟日，曠然誰與儔。", "感茲風露夕，始知天宇秋。", "庭樹且扶踈，時物詎淹留。", "心空累云遠，歲月真悠悠。"]'),
('c5758812-1044-4aef-bae2-ee8f816ce3e8','秋夕二首  其二','朱熹','宋','宋诗','song-poetry','','[]','公門了無事，吏散終日閑。',48,'全唐诗/poet.song.147000.json','["公門了無事，吏散終日閑。", "凉葉何蕭蕭，悲吟庭樹間。", "琴書寫塵慮，菽水怡親顔。", "憶在中林日，秋來長掩關。"]'),
('5019dead-4d82-4a2b-afd9-f460a315eb20','秋夜聽雨奉懷子厚','朱熹','宋','宋诗','song-poetry','','[]','悄悄窗戶暗，青燈讀殘書。',72,'全唐诗/poet.song.147000.json','["悄悄窗戶暗，青燈讀殘書。", "忽聽踈雨落，稍知凉氣初。", "披襟聊自適，掩卷方躊躇。", "亦念同懷人，悵望心煩紆。", "鳴琴愛靜夜，樂道今閑居。", "岑岑空山中，此夕知焉如。"]'),
('9d453202-b3cc-49b3-9ef0-e86d29017adb','對月思故山夜景','朱熹','宋','宋诗','song-poetry','','[]','沉沉新秋夜，凉月滿荆扉。',48,'全唐诗/poet.song.147000.json','["沉沉新秋夜，凉月滿荆扉。", "露泫凝餘彩，川明澄素暉。", "中林竹樹映，踈星河漢稀。", "此夕情無限，故園何日歸。"]'),
('5e0f1fa0-c828-4127-88de-683f82b39760','同僚小集梵天寺坐間雨作已復開霽步至東橋玩月賦詩二首  其一','朱熹','宋','宋诗','song-poetry','','[]','傑閣翔林杪，披襟此日閑。',48,'全唐诗/poet.song.147000.json','["傑閣翔林杪，披襟此日閑。", "層雲生薄晚，凉雨遍空山。", "地迥衣裳冷，天高澄霽還。", "出門迷所適，月色滿林關。"]'),
('cb22582c-3986-4452-a2d0-85444ccb59b1','同僚小集梵天寺坐間雨作已復開霽步至東橋玩月賦詩二首  其二','朱熹','宋','宋诗','song-poetry','','[]','空山看雨罷，微步喜新凉。',48,'全唐诗/poet.song.147000.json','["空山看雨罷，微步喜新凉。", "月出澄餘景，川明發素光。", "星河方耿耿，雲樹轉蒼蒼。", "晤語逢清夜，茲懷殊未央。"]'),
('2d6e1243-228e-4a92-92bf-df4bc4ea384b','梵天觀雨','朱熹','宋','宋诗','song-poetry','','[]','持身乏古節，寸祿久棲遲。',48,'全唐诗/poet.song.147000.json','["持身乏古節，寸祿久棲遲。", "暫寄靈山寺，空吟招隠詩。", "讀書清磬外，看雨暮鍾時。", "漸喜凉秋近，滄洲去有期。"]'),
('0bba2e58-7fe9-4d85-899a-095714cc9a1d','兼山閣雨中','朱熹','宋','宋诗','song-poetry','','[]','兩山相接雨冥冥，四牖東西萬木青。',32,'全唐诗/poet.song.147000.json','["兩山相接雨冥冥，四牖東西萬木青。", "面似凍梨頭似雪，後生誰與屬遺經。"]'),
('f8f14981-bbd0-4f43-9dc9-532b97175d7a','登閣','朱熹','宋','宋诗','song-poetry','','[]','橫空敞新閣，高處絕炎氛。',48,'全唐诗/poet.song.147000.json','["橫空敞新閣，高處絕炎氛。", "野迥長風入，天秋凉氣分。", "憑欄生逸想，投迹遠人羣。", "終憶茅簷外，空山多白雲。"]'),
('09a95fcc-fad3-4d9f-a007-eacf0fbcfd05','秋懷二首  其一','朱熹','宋','宋诗','song-poetry','','[]','秋風吹庭戶，客子懷故鄉。',84,'全唐诗/poet.song.147000.json','["秋風吹庭戶，客子懷故鄉。", "矧此卧愁疾，徘徊守空房。", "佇想澗谷居，林深慘悲凉。", "鵾鷄感蕭辰，拊翼號風霜。", "氛雜無留氣，悄蒨有餘芳。", "幸聞衛生要，招隠夙所臧。", "終期謝世慮，矯翮茲山岡。"]'),
('9e9ce54c-fc9d-4672-979b-b7b11e9fdca8','秋懷二首  其二','朱熹','宋','宋诗','song-poetry','','[]','懷痾坐竟日，晚色散幽樹。',72,'全唐诗/poet.song.147000.json','["懷痾坐竟日，晚色散幽樹。", "寂歷候蟲悲，沆瀁碧草露。", "端居興方澹，沉默自成趣。", "羽觴歡獨持，瑶琴誰與晤。", "空知玄思清，未惜年華度。", "美人殊不來，歲月恐遲暮。"]'),
('9365dfa6-8aff-46e8-aa52-6c5d75139e0a','中元雨中呈子晉','朱熹','宋','宋诗','song-poetry','','[]','徂暑尚繁鬰，大火空西流。',84,'全唐诗/poet.song.147000.json','["徂暑尚繁鬰，大火空西流。", "茲辰喜佳節，凉雨忽驚秋。", "晼晚蘭徑滋，蕭疈庭樹幽。", "炎氣一以去，恢台逝不留。", "刀筆隨事屏，塵囂與心休。", "端居諷道言，焚香味真諏。", "子亦玩文史，及此同優游。"]'),
('3816fc35-ea6c-4c80-a395-d23906b10f26','秋暑','朱熹','宋','宋诗','song-poetry','','[]','晨興納新凉，亭午倦猶暑。',48,'全唐诗/poet.song.147000.json','["晨興納新凉，亭午倦猶暑。", "卧對北窗扉，淡泊將誰侶。", "踈樹含輕颸，時禽轉幽語。", "端居悟物情，即事聊容與。"]'),
('01b20795-94b4-4165-9b9b-a76d727f344e','和李伯玉用東坡韻賦梅花','朱熹','宋','宋诗','song-poetry','','[]','北風日日霾江村，歸夢正爾勞營魂。',128,'全唐诗/poet.song.147000.json','["北風日日霾江村，歸夢正爾勞營魂。", "忽聞梅蘂臘前破，楚客不愛蘭佩昏。", "尋幽舊識此堂古，曳杖偶集僧家園。", "嵐陰春物未全到，邂逅只有南枝溫。", "冷光自照眼色界，雲艷未怯扶桑暾。", "遥知雲臺溪上路，玉樹十里藏山門。", "自憐塵羈不得去，坐想佳處知難言。", "但哦君詩慰岑寂，已似共倒花前罇。"]'),
('0428adc5-8e9b-48fc-9499-cda2337152a3','與諸人用東坡韻共賦梅花適得元履書有懷其人因復賦此以寄意焉','朱熹','宋','宋诗','song-poetry','','[]','羅浮山下黄茅村，蘇仙仙去餘詩魂。',128,'全唐诗/poet.song.147000.json','["羅浮山下黄茅村，蘇仙仙去餘詩魂。", "梅花自入三疊曲，至今不受蠻煙昏。", "佳名一旦異凡木，絕艷千古高名園。", "却憐冰質不自暖，雖有步障難爲溫。", "羞同桃李媚春色，敢與葵藿爭朝暾。", "歸來只有脩竹伴，寂歷自掩踈籬門。", "亦知真意還有在，未覺浩氣終難言。", "一杯勸汝吾不淺，要汝共保山林罇。"]'),
('9261f2cf-a733-462d-aef5-3b691355ed6f','挽劉寶學二首  其一','朱熹','宋','宋诗','song-poetry','','[]','天地誰翻覆，人謀痛莫支。',48,'全唐诗/poet.song.147000.json','["天地誰翻覆，人謀痛莫支。", "公扶西極柱，威動北征旗。", "肉食謀何鄙，家山志忽齎。", "平生出師表，今日重傷悲。"]'),
('8e7317a9-e1d9-400d-96f9-80b129b7a11c','挽劉寶學二首  其二','朱熹','宋','宋诗','song-poetry','','[]','生死公何有，飄零我自傷。',48,'全唐诗/poet.song.147000.json','["生死公何有，飄零我自傷。", "向非憐不造，那得此深藏。", "心折風霜裏，衣沾子姪行。", "哦詩當肅挽，悲哽不成章。"]'),
('9f0eb413-d64b-40b8-98ac-0b500e6dfeab','寄題梅川溪堂','朱熹','宋','宋诗','song-poetry','','[]','滄波流不極，上有一畝園。',108,'全唐诗/poet.song.147000.json','["滄波流不極，上有一畝園。", "幽人掩關卧，脩竹何娟娟。", "虛堂面群峯，秀色摩青天。", "靜有山水樂，而無車馬喧。", "人言市門子，往往蒼崖顛。", "揮手謝世人，日中翔紫煙。", "遺迹尚可覿，神交邈無緣。", "慨然一永歎，耀靈忽西遷。", "褰裳下中沚，濯足娛清川。"]'),
('b0c1e1a0-b001-4aea-80fa-89632d45efe8','和劉抱一','朱熹','宋','宋诗','song-poetry','','[]','幾年牢落舊村墟，此日脩然水竹居。',64,'全唐诗/poet.song.147000.json','["幾年牢落舊村墟，此日脩然水竹居。", "病起試尋春逕草，客來聊煮雪畦蔬。", "開樽細說平生事，信手同繙集古書。", "適意何勞一千卷，新詩閑出笑談餘。"]'),
('e93a77a7-4aed-4092-8703-f1989e89700f','再和','朱熹','宋','宋诗','song-poetry','','[]','久矣投裝返舊墟，不將心事賦閑居。',64,'全唐诗/poet.song.147000.json','["久矣投裝返舊墟，不將心事賦閑居。", "荷鉏带月朝治穢，植杖臨風夕挽蔬。", "三逕猶尋陶令宅，萬籤聊借鄴侯書。", "木瓜更得瓊琚報，吟咏從今樂有餘。"]'),
('628be66d-7351-4ebf-a8d0-5e9c41d68c27','送芮國器二首  其一','朱熹','宋','宋诗','song-poetry','','[]','拄節千山外，勤勞飽所經。',48,'全唐诗/poet.song.147000.json','["拄節千山外，勤勞飽所經。", "一心無適莫，萬口自丹青。", "拂拭先賢傳，光輝處士星。", "活人功更遠，試與問林坰。"]'),
('d77c27a6-da75-4f5c-b92b-f75b548da5ac','送芮國器二首  其二','朱熹','宋','宋诗','song-poetry','','[]','紫陌同年舊，青雲得路新。',48,'全唐诗/poet.song.147000.json','["紫陌同年舊，青雲得路新。", "論心端有契，下榻豈辭頻。", "話別驚如許，相逢渺未因。", "期公念經濟，從此上星辰。"]'),
('7530446d-970f-4154-a4d0-d9948e47c6ef','梅花開盡不及吟賞感嘆成詩聊貽同好二首  其一','朱熹','宋','宋诗','song-poetry','','[]','憶昔身無事，尋梅只怕遲。',48,'全唐诗/poet.song.147000.json','["憶昔身無事，尋梅只怕遲。", "沉吟窺老樹，取次折橫枝。", "絕艷驚衰鬢，餘芳入小詩。", "今年何草草，政爾負幽期。"]'),
('db4a0a68-84f9-465b-b1b3-359ccb05ef04','梅花開盡不及吟賞感嘆成詩聊貽同好二首  其二','朱熹','宋','宋诗','song-poetry','','[]','棐几冰壺在，梅梢雪蕊空。',48,'全唐诗/poet.song.147000.json','["棐几冰壺在，梅梢雪蕊空。", "不堪三弄咽，誰與一尊同。", "鼻觀殘香裏，心期昨夢中。", "那知北枝北，猶有未開叢。"]'),
('cd7155af-f6a6-4934-b544-19ecc6691d8c','宋丈示及紅梅臘梅借韻兩詩輒復和呈以發一笑  其一','朱熹','宋','宋诗','song-poetry','','[]','聞說寒梅盡，尋芳去已遲。',48,'全唐诗/poet.song.147000.json','["聞說寒梅盡，尋芳去已遲。", "冷香無宿蕊，穠艷有繁枝。", "正復非同調，何妨續舊詩。", "廣平偏娬媚，鐵石悞心期。"]'),
('d1c2e4ab-b73f-411b-b629-8bac27a9b964','宋丈示及紅梅臘梅借韻兩詩輒復和呈以發一笑  其二','朱熹','宋','宋诗','song-poetry','','[]','風雪催殘臘，南枝一夜空。',48,'全唐诗/poet.song.147000.json','["風雪催殘臘，南枝一夜空。", "誰知荒草裏，却有暗香同。", "質瑩輕黄外，芳滕淺絳中。", "不遭岑寂侶，何以媚孤叢。"]'),
('34cc83f7-10a0-47ee-8e3d-8387dd35e49a','呈黄子厚','朱熹','宋','宋诗','song-poetry','','[]','茅齋塵事遠，幽獨興無窮。',48,'全唐诗/poet.song.147000.json','["茅齋塵事遠，幽獨興無窮。", "永晝呻吟內，新凉愁思中。", "朱顔非昨日，綠鬢又秋風。", "珍重牆東客，遥憐此意同。"]'),
('4ae63b3d-c42f-4e17-9482-c39219a38716','奉酬子厚詠雪之作','朱熹','宋','宋诗','song-poetry','','[]','遥夜不能寐，披衣起彷徨。',132,'全唐诗/poet.song.147000.json','["遥夜不能寐，披衣起彷徨。", "仰視天正黑，寒氣慘悲凉。", "飛霰忽下零，雪花亦飄揚。", "飄揚未云已，須臾滿空翔。", "前山失舊姿，川谷流素光。", "念昔少小時，無事志四方。", "五年江海上，不見雪與霜。", "飄颻今日情，浩蕩誰能量。", "凌晨飲一杯，竟日守空堂。", "竚立玩奇變，永言獲新章。", "躊躇欲何報，玉樹生瓊岡。"]'),
('369eefff-49ea-4133-96e2-73e2d2eff581','送籍溪胡丈赴館供職二首  其一','朱熹','宋','宋诗','song-poetry','','[]','祖餞衣冠滿道周，此行誰與話端由。',32,'全唐诗/poet.song.147000.json','["祖餞衣冠滿道周，此行誰與話端由。", "心知不作功名計，祇爲蒼生未敢休。"]'),
('c8fc9d8e-21da-4ca8-8e6a-dc28c90182c1','送籍溪胡丈赴館供職二首  其二','朱熹','宋','宋诗','song-poetry','','[]','執我仇仇詎我知，謾將行止驗天機。',32,'全唐诗/poet.song.147000.json','["執我仇仇詎我知，謾將行止驗天機。", "猿悲鶴怨因何事，祇恐先生袖手歸。"]'),
('80ea2798-11aa-440c-b72a-437ac20d4a87','寄籍溪胡丈及劉恭父二首  其一','朱熹','宋','宋诗','song-poetry','','[]','先生去上芸香閣，閣老新峩豸角冠。',32,'全唐诗/poet.song.147000.json','["先生去上芸香閣，閣老新峩豸角冠。", "留取幽人卧空谷，一川風月要人看。"]'),
('299682e5-ac8f-4cb4-a2ab-aea3aba16689','寄籍溪胡丈及劉恭父二首  其二','朱熹','宋','宋诗','song-poetry','','[]','甕牖前頭翠作屏，晚來相對靜儀刑。',32,'全唐诗/poet.song.147000.json','["甕牖前頭翠作屏，晚來相對靜儀刑。", "浮雲一任閑舒卷，萬古青山祇麽青。"]'),
('5ab3470e-e474-4543-9da4-b0dd165d1674','挽范直閣二首  其一','朱熹','宋','宋诗','song-poetry','','[]','獻納陪興運，如公衆所期。',48,'全唐诗/poet.song.147000.json','["獻納陪興運，如公衆所期。", "憂時最深切，信道不磷緇。", "落落歸來賦，匆匆殄瘁詩。", "菟裘當日計，宰木後人悲。"]'),
('1bea4e20-596c-4339-9f86-b628b9d84156','挽范直閣二首  其二','朱熹','宋','宋诗','song-poetry','','[]','先友多名士，存亡幾許人。',48,'全唐诗/poet.song.147000.json','["先友多名士，存亡幾許人。", "惟公且彊健，於我更情親。", "出處論心晚，音書枉誨頻。", "素車今日會，誰與共傷神。"]'),
('5c5fe9cc-9c80-4ff8-81c1-13ee9cd5706a','頃以多言害道絕不作詩兩日讀大學誠意章有感至日之朝起書此以自箴蓋不得已而有言云','朱熹','宋','宋诗','song-poetry','','[]','神心洞玄鑒，好惡審薰蕕。',72,'全唐诗/poet.song.147000.json','["神心洞玄鑒，好惡審薰蕕。", "云何反自誑，閔默還包羞。", "今辰仲冬節，寤歎得隠憂。", "心知一寸光，昱彼重泉幽。", "朋來自茲始，羣陰邈難留。", "行迷亦已遠，及此旋吾輈。"]'),
('52a1a570-3f08-4d5d-aa8e-43a7b2053390','仁術','朱熹','宋','宋诗','song-poetry','','[]','在昔賢君子，存心每欲仁。',72,'全唐诗/poet.song.147000.json','["在昔賢君子，存心每欲仁。", "求端從有術，及物豈無因。", "惻隠來何自，虛明覺處真。", "擴充從此念，福澤遍斯民。", "入井倉皇際，牽牛觳觫辰。", "向來看楚越，今日備吾身。"]'),
('f899137d-05fe-4c7a-884c-74a01350dafd','聞善决江河','朱熹','宋','宋诗','song-poetry','','[]','大舜深山日，靈襟保太和。',72,'全唐诗/poet.song.147000.json','["大舜深山日，靈襟保太和。", "一言分善利，萬里决江河。", "可欲非由外，惟聰不在它。", "勇如爭赴壑，進豈待盈科。", "學海功難並，防川患益多。", "何人親祖述，耳順肯同波。"]'),
('0504bf13-35cc-42ab-91dc-bd52fcb1b8f5','仰思二首  其一','朱熹','宋','宋诗','song-poetry','','[]','公德明光萬世師，從容酬酢更何疑。',32,'全唐诗/poet.song.147000.json','["公德明光萬世師，從容酬酢更何疑。", "當年不合知何事，清夜端居獨仰思。"]'),
('3d47c617-951f-452f-82ee-c0c410b2dea1','仰思二首  其二','朱熹','宋','宋诗','song-poetry','','[]','聖賢事業理難同，僭作新題欲自攻。',32,'全唐诗/poet.song.147000.json','["聖賢事業理難同，僭作新題欲自攻。", "王事兼施吾豈敢，儻容思勉議成功。"]'),
('663972db-c1cd-4a27-a8da-7e13d5b773b2','困學二首  其一','朱熹','宋','宋诗','song-poetry','','[]','舊喜安心苦覓心，捐書絕學費追尋。',32,'全唐诗/poet.song.147000.json','["舊喜安心苦覓心，捐書絕學費追尋。", "困衡此日安無地，始覺從前枉寸陰。"]'),
('14a70070-0096-4c62-b278-814bbc5f81e3','困學二首  其二','朱熹','宋','宋诗','song-poetry','','[]','困學工夫豈易成，斯名獨恐是虛稱。',32,'全唐诗/poet.song.147000.json','["困學工夫豈易成，斯名獨恐是虛稱。", "傍人莫笑標題誤，庸行庸言實未能。"]'),
('c475ecaa-1d49-4b4f-b112-48ca82023a41','復齋偶題','朱熹','宋','宋诗','song-poetry','','[]','出入無時是此心，豈知鷄犬易追尋。',32,'全唐诗/poet.song.147000.json','["出入無時是此心，豈知鷄犬易追尋。", "請看屏上初爻旨，便識名齋用意深。"]'),
('0dd5f22e-bc89-4465-8de0-68851c8c78da','示四弟','朱熹','宋','宋诗','song-poetry','','[]','務學脩身要及時，競辰須念隙駒馳。',32,'全唐诗/poet.song.147000.json','["務學脩身要及時，競辰須念隙駒馳。", "清宵白日供遊蕩，愁殺堂前老古錐。"]'),
('d4aaca96-2018-4149-9c84-8a6de78b508d','克己','朱熹','宋','宋诗','song-poetry','','[]','寶鑑當年照膽寒，向來埋沒太無端。',32,'全唐诗/poet.song.147000.json','["寶鑑當年照膽寒，向來埋沒太無端。", "祇今垢盡明全見，還得當年寶鑑看。"]'),
('9e25ad12-3dd3-44b7-a6b2-9a6c08422e5c','曾點','朱熹','宋','宋诗','song-poetry','','[]','春服初成麗景遲，步隨流水玩晴漪。',32,'全唐诗/poet.song.147000.json','["春服初成麗景遲，步隨流水玩晴漪。", "微吟緩節歸來晚，一任輕風拂面吹。"]'),
('a7050cfb-125e-497e-a705-d262f00fd6bf','伐木','朱熹','宋','宋诗','song-poetry','','[]','伐木相將入遠山，共聽幽鳥語關關。',32,'全唐诗/poet.song.147000.json','["伐木相將入遠山，共聽幽鳥語關關。", "殷勤若解當時意，此日那容不盡歡。"]'),
('30e1ae22-cfa0-420d-8f3a-1744264b60fd','春日','朱熹','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u5b8b\u8bd7", "\u4e09\u5e74\u7ea7\u4e0b\u518c"]','勝日尋芳泗水濱，無邊光景一時新。',32,'全唐诗/poet.song.147000.json','["勝日尋芳泗水濱，無邊光景一時新。", "等閑識得東風面，萬紫千紅總是春。"]'),
('a4175e6f-18c7-4659-93d1-9619589b1252','春日偶作','朱熹','宋','宋诗','song-poetry','','[]','聞道西園春色深，急穿芒屩去登臨。',32,'全唐诗/poet.song.147000.json','["聞道西園春色深，急穿芒屩去登臨。", "千葩萬蕊爭紅紫，誰識乾坤造化心。"]'),
('84eb30d4-a625-4456-be4d-f2bfb211fb9c','觀書有感二首  其一','朱熹','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u8bfb\u4e66", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)"]','半畝方塘一鑑開，天光雲影共徘徊。',32,'全唐诗/poet.song.147000.json','["半畝方塘一鑑開，天光雲影共徘徊。", "問渠那得清如許，爲有源頭活水來。"]'),
('50ad5156-30fa-4df2-8071-df857b52b827','觀書有感二首  其二','朱熹','宋','宋诗','song-poetry','','["\u63cf\u5199\u6c34", "\u54f2\u7406", "\u5b8b\u8bd7", "\u8bfb\u4e66", "\u5199\u6c34"]','昨夜江邊春水生，蒙衝巨艦一毛輕。',32,'全唐诗/poet.song.147000.json','["昨夜江邊春水生，蒙衝巨艦一毛輕。", "向來枉費推移力，此日中流自在行。"]'),
('dd8fad19-bc11-4593-88ac-91e42f660240','題西林院壁二首  其一','朱熹','宋','宋诗','song-poetry','','[]','觸目風光不易裁，此間何似舞雩臺。',32,'全唐诗/poet.song.147000.json','["觸目風光不易裁，此間何似舞雩臺。", "病軀若得長無事，春服成時歲一來。"]'),
('dfcc97a6-19df-4dd1-b300-15e466bc407f','題西林院壁二首  其二','朱熹','宋','宋诗','song-poetry','','[]','巾屨翛然一鉢囊，何妨且住贊公房。',32,'全唐诗/poet.song.147000.json','["巾屨翛然一鉢囊，何妨且住贊公房。", "却嫌宴坐觀心處，不奈簷花抵死香。"]'),
('f5ec9b7d-dec4-4396-8073-8dc60e62083c','題西林可師達觀軒','朱熹','宋','宋诗','song-poetry','','[]','窈窕雲房深復深，層軒俄此快登臨。',32,'全唐诗/poet.song.147000.json','["窈窕雲房深復深，層軒俄此快登臨。", "卷簾一目遥山碧，底是高人達觀心。"]'),
('4c40d938-2dbc-497a-bc64-0c975b9c1c6a','再題','朱熹','宋','宋诗','song-poetry','','[]','古寺重來感慨深，小軒仍是舊窺臨。',32,'全唐诗/poet.song.147000.json','["古寺重來感慨深，小軒仍是舊窺臨。", "向來妙處今遺恨，萬古長空一片心。"]'),
('18e83e91-c94e-4a57-99e3-66697faab6ee','示西林可師二首  其一','朱熹','宋','宋诗','song-poetry','','[]','身世年來欲兩忘，一春隨意住僧房。',32,'全唐诗/poet.song.147000.json','["身世年來欲兩忘，一春隨意住僧房。", "行逢舊隠低回久，綠樹鶑啼清晝長。"]'),
('0577320e-2a27-4817-8ee4-5de976aed202','示西林可師二首  其二','朱熹','宋','宋诗','song-poetry','','[]','幽居四畔只空林，啼鳥落花春意深。',32,'全唐诗/poet.song.147000.json','["幽居四畔只空林，啼鳥落花春意深。", "獨宿塵龕無夢寐，五更山月照寒衾。"]'),
('2e060ed9-05b9-48f3-ba94-80279cc873ed','感事書懷十六韻','朱熹','宋','宋诗','song-poetry','','[]','胡虜何年盛，神州遂陸沉。',192,'全唐诗/poet.song.147000.json','["胡虜何年盛，神州遂陸沉。", "翠華棲浙右，紫塞僅淮陰。", "志士憂虞切，朝家預備深。", "一朝頒細札，三捷便聞音。", "授鉞無遺算，沈機識聖心。", "東西兵合勢，南北怨重尋。", "小却奇還勝，窮凶禍所臨。", "旃裘方舞雪，血刃已披襟。", "殘類隨煨燼，遺黎脫斧碪。", "戴商仍夙昔，思漢劇謳吟。", "共惜山河固，同嗟歲月侵。", "泉蓍久憔翠，陵柏幸蕭椮。", "正爾資羣策，何妨試盍簪。", "折衝須舊衮，出牧仗南金。", "衆志非難狥，天休詎可諶。", "故人司獻納，早晚奉良箴。"]'),
('b291affb-ff4c-4492-a5ae-5679e52d7d23','次韻劉彥采觀雪之句','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','朔風吹空林，眇眇無因依。',168,'全唐诗/poet.song.147000.json','["朔風吹空林，眇眇無因依。", "但有西北雲，冉冉東南飛。", "須臾層陰合，慘淡周八維。", "凍雨不流淵，飛花舞妍姿。", "翳空乍滅沒，散影還參差。", "萬點隨飄零，百嘉潛潤滋。", "徘徊瞻詠久，默識造化機。", "上寒下必溫，欲積無根基。", "漸看谷樹變，稍覺叢篁低。", "皓然遂同色，宇宙乃爾奇。", "繁華改新觀，凜冽忘前悲。", "摛章愧佳友，佇立迎寒吹。", "感此節物好，嘆息今何時。", "當念長江北，鐵馬紛交馳。"]'),
('9e1dfc15-a6ef-48c7-a82e-a85b37ef341a','次韻彥采病中口占','朱熹','宋','宋诗','song-poetry','','[]','一榻流年度，篝燈遥夜闌。',48,'全唐诗/poet.song.147000.json','["一榻流年度，篝燈遥夜闌。", "短衾閑自擁，清鏡莫頻看。", "竹密初驚雪，梅踈却耐寒。", "從今花木夢，無復在雕欄。"]'),
('90cd84e0-f122-414e-bf8a-19c10cc7da01','感事','朱熹','宋','宋诗','song-poetry','','[]','聞說淮南路，胡塵滿眼黄。',48,'全唐诗/poet.song.147000.json','["聞說淮南路，胡塵滿眼黄。", "棄軀慚國士，嘗膽念君王。", "却敵非干櫓，信威藉紀綱。", "丹心危欲折，竚立但彷徨。"]'),
('f668e11e-8730-4c03-bde7-6446e79753f6','聞二十八日之報喜而成詩七首  其一','朱熹','宋','宋诗','song-poetry','','[]','胡馬無端莫四馳，漢家元有中興期。',32,'全唐诗/poet.song.147000.json','["胡馬無端莫四馳，漢家元有中興期。", "旃裘喋血淮山寺，天命人心合自知。"]'),
('b7f0cfb1-c125-45a9-9df4-3cff77f5a0ef','聞二十八日之報喜而成詩七首  其二','朱熹','宋','宋诗','song-poetry','','[]','天驕得意任驅馳，太歲乘蛇已應期。',32,'全唐诗/poet.song.147000.json','["天驕得意任驅馳，太歲乘蛇已應期。", "一夜旄頭光殞地，飲江胡馬未全知。"]'),
('3136148b-c77f-482b-ad19-3bd35cfc6cc2','聞二十八日之報喜而成詩七首  其三','朱熹','宋','宋诗','song-poetry','','[]','雪擁貂裘一馬馳，孤軍左袒事難期。',32,'全唐诗/poet.song.147000.json','["雪擁貂裘一馬馳，孤軍左袒事難期。", "奏函夜入明光殿，底事廬兒探得知。"]'),
('af92a9c5-6e21-4bcc-a28a-ac69acd058a8','聞二十八日之報喜而成詩七首  其四','朱熹','宋','宋诗','song-poetry','','[]','渡淮諸將已爭馳，兔脫鷹揚不會期。',32,'全唐诗/poet.song.147000.json','["渡淮諸將已爭馳，兔脫鷹揚不會期。", "殺盡殘胡方反旆，里閭元未有人知。"]'),
('06e823b2-c733-4081-ae62-2706d22df81b','聞二十八日之報喜而成詩七首  其五','朱熹','宋','宋诗','song-poetry','','[]','漢節熒煌直北馳，皇家卜世萬年期。',32,'全唐诗/poet.song.147000.json','["漢節熒煌直北馳，皇家卜世萬年期。", "東京盛德符高祖，說與中原父老知。"]'),
('aa8dafbe-c1fb-412c-bfff-737a2315634a','聞二十八日之報喜而成詩七首  其六','朱熹','宋','宋诗','song-poetry','','[]','追鋒聞說日驅馳，舊德登庸儻有期。',32,'全唐诗/poet.song.147000.json','["追鋒聞說日驅馳，舊德登庸儻有期。", "聖主聰明似堯禹，忠邪如許詎難知。"]'),
('dfad32e8-ed31-40af-acca-222155cb7cc2','聞二十八日之報喜而成詩七首  其七','朱熹','宋','宋诗','song-poetry','','[]','恭惟大號久風馳，清蹕傳呼却未期。',32,'全唐诗/poet.song.147000.json','["恭惟大號久風馳，清蹕傳呼却未期。", "此日不須勞玉趾，寸心那得侍臣知。"]'),
('1f2dcbcb-5993-45d2-85c9-a93968a33987','次子有聞捷韻四首  其一','朱熹','宋','宋诗','song-poetry','','[]','神州荆棘欲成林，霜露凄凉感聖心。',32,'全唐诗/poet.song.147000.json','["神州荆棘欲成林，霜露凄凉感聖心。", "故老幾人今好在，壺漿爭聽鼓鼙音。"]'),
('af83988f-d181-47a3-aea4-cfd79afb4457','次子有聞捷韻四首  其二','朱熹','宋','宋诗','song-poetry','','[]','殺氣先歸江上林，貔貅百萬想同心。',32,'全唐诗/poet.song.147000.json','["殺氣先歸江上林，貔貅百萬想同心。", "明朝滅盡天驕子，南北東西盡好音。"]'),
('5d4b6af9-e7e9-4ad6-927f-63bfa913d484','次子有聞捷韻四首  其三','朱熹','宋','宋诗','song-poetry','','[]','孤臣殘疾卧空林，不奈憂時一寸心。',32,'全唐诗/poet.song.147000.json','["孤臣殘疾卧空林，不奈憂時一寸心。", "誰遣捷書來蓽戶，真同百蟄聽雷音。"]'),
('7908e22d-5c9d-4fc9-8ffd-501ea3b18c5d','次子有聞捷韻四首  其四','朱熹','宋','宋诗','song-poetry','','[]','胡命須臾兔走林，驕豪無復向來心。',32,'全唐诗/poet.song.147000.json','["胡命須臾兔走林，驕豪無復向來心。", "莫煩王旅追窮寇，鶴唳風聲盡好音。"]'),
('f8664f55-7e14-437e-b2dc-4c2ba8c2c969','奉陪判院丈充父平父兄宿回向用知郡丈壁間舊題之韻','朱熹','宋','宋诗','song-poetry','','[]','暮雨停驂處，僧廬古道邊。',48,'全唐诗/poet.song.147000.json','["暮雨停驂處，僧廬古道邊。", "千峯環傑閣，一水下平田。", "行役無期度，經過幾歲年。", "明朝須飽飯，躡足上寒煙。"]'),
('072f77fe-4967-4fbb-898c-9890011c6801','感事再用回向壁間舊韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','江北傳烽火，胡兒大入邊。',48,'全唐诗/poet.song.147000.json','["江北傳烽火，胡兒大入邊。", "已聞隳列障，不但擾屯田。", "借箸思人傑，摧鋒屬少年。", "偷安慙暇食，萬竈起愁煙。"]'),
('bd6c050d-f661-4e57-ad00-a9a96b8c69b2','感事再用回向壁間舊韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','廊廟憂虞裏，風塵慘淡邊。',48,'全唐诗/poet.song.147000.json','["廊廟憂虞裏，風塵慘淡邊。", "早知煩汗馬，悔不是留田。", "迷國嗟誰子，和戎誤往年。", "腐儒空感慨，無策靜狼煙。"]'),
('5c63af47-51c3-46bf-b982-723396c5726a','蒙判院丈示及再用元韻之作率易和呈以求指誨','朱熹','宋','宋诗','song-poetry','','[]','疇昔經行地，溪山寂寞邊。',48,'全唐诗/poet.song.147000.json','["疇昔經行地，溪山寂寞邊。", "冰霜凝巨壑，風雨暗中田。", "古寺堪投晚，塵龕閲紀年。", "論文寒夜永，清絕裊爐烟。"]'),
('fd5c6a47-009e-4a30-b6b1-bf710ea046e4','數日前與判院丈有宋村之約雪中有懷奉呈判院通判二丈','朱熹','宋','宋诗','song-poetry','','[]','雲垂天闊歲將闌，一室翛然獨掩關。',64,'全唐诗/poet.song.147000.json','["雲垂天闊歲將闌，一室翛然獨掩關。", "擁褐不知風折木，開軒惟見雪漫山。", "玄空杳靄低迷外，碧樹瓏璁掩映間。", "吟罷左思招隠句，扁舟無路過長灣。"]'),
('de91c3ad-bec8-4996-9870-768ee6e3af9d','次韻判院丈雪意之作','朱熹','宋','宋诗','song-poetry','','[]','端居歲復窮，閉戶守沖澹。',48,'全唐诗/poet.song.147000.json','["端居歲復窮，閉戶守沖澹。", "風陰原野悲，月黑庭除暗。", "淅瀝靜先知，崩奔誰與探。", "坐想青瑶林，寒光生素艷。"]'),
('5c7b7dab-542f-4451-ad34-ba300fe9de2b','熹伏蒙判院丈垂示用韻喜晴之句率爾奉酬伏乞笑覽','朱熹','宋','宋诗','song-poetry','','[]','客枕終難穩，歸來鼾息深。',48,'全唐诗/poet.song.147000.json','["客枕終難穩，歸來鼾息深。", "曉鷄回遠夢，缺月掛空林。", "冰谷晨加帽，晴窗晝解襟。", "詩筒多妙語，仍喜舊盟尋。"]'),
('3cb30930-7059-4050-8300-f8ee8705e3f1','登梅嶺','朱熹','宋','宋诗','song-poetry','','[]','去路霜威勁，歸程雪意深。',48,'全唐诗/poet.song.147000.json','["去路霜威勁，歸程雪意深。", "往還無幾日，景物變千林。", "曉磴初移屐，寒雲欲滿襟。", "玉梅踈半落，猶足慰幽尋。"]'),
('f24e5588-18f3-4354-8044-ec3286f669bd','雪意','朱熹','宋','宋诗','song-poetry','','[]','向晚浮雲四面平，北風號怒達天明。',32,'全唐诗/poet.song.147000.json','["向晚浮雲四面平，北風號怒達天明。", "寒窗一夜清無睡，擬聽杉篁葉上聲。"]'),
('6cd48eb8-7a77-41a7-be7e-2cb4ac076162','昨夕不知有雪而晨起四望遠峰皆已變色再用元韻作兩絕句  其一','朱熹','宋','宋诗','song-poetry','','[]','朔風吹盡暮雲平，室暖爐紅睡達明。',32,'全唐诗/poet.song.147000.json','["朔風吹盡暮雲平，室暖爐紅睡達明。", "但怪朝來滿山白，不知昨夜打窗聲。"]'),
('be2c18f2-bd6f-43ee-aa03-95b43bd9f8fe','昨夕不知有雪而晨起四望遠峰皆已變色再用元韻作兩絕句  其二','朱熹','宋','宋诗','song-poetry','','[]','千林無葉一川平，萬壑瓊瑶照夜明。',32,'全唐诗/poet.song.147000.json','["千林無葉一川平，萬壑瓊瑶照夜明。", "未覺殘梅飄落盡，祇愁羌管不成聲。"]'),
('6362c93f-0590-421d-86d2-c00f55908312','奉陪彥集充父同游瑞巖謹次莆田使君留題之韻','朱熹','宋','宋诗','song-poetry','','[]','踏破千林黄葉堆，林間臺殿鬰崔嵬。',64,'全唐诗/poet.song.147000.json','["踏破千林黄葉堆，林間臺殿鬰崔嵬。", "谷泉噴薄秋逾響，山翠空濛晝不開。", "一壑祇今藏勝概，三生疇昔記曾來。", "解衣正作留連計，未許山靈便却回。"]'),
('5a7310f8-c182-4f8c-878f-91bdeb9704fe','伏讀趙清獻公瑞巖留題感歎之餘追次元韻','朱熹','宋','宋诗','song-poetry','','[]','趙公名迹此猶微，已薦行藏第一機。',64,'全唐诗/poet.song.147000.json','["趙公名迹此猶微，已薦行藏第一機。", "直自當年留翰墨，至今窮谷尚光輝。", "時清諫疏空遺稿，歲晚高齋自掩扉。", "珍重九原如可作，問渠何處是真歸。"]'),
('f8d05ac6-0342-4ccd-ab51-0664e8dcc00c','伏讀二劉公瑞巖留題感事興懷至於隕涕追次元韻偶成二篇  其一','朱熹','宋','宋诗','song-poetry','','[]','誰將健筆寫崖陰，想見當年抱膝吟。',64,'全唐诗/poet.song.147000.json','["誰將健筆寫崖陰，想見當年抱膝吟。", "緩带輕裘成昨夢，遺風餘烈到如今。", "西山爽氣看猶在，北闕精誠直自深。", "故壘近聞新破竹，起公無路祇傷心。"]'),
('6c70b543-f8a1-498f-a386-4312543d856f','伏讀二劉公瑞巖留題感事興懷至於隕涕追次元韻偶成二篇  其二','朱熹','宋','宋诗','song-poetry','','[]','投紱歸來卧赤城，家山無處不經行。',64,'全唐诗/poet.song.147000.json','["投紱歸來卧赤城，家山無處不經行。", "寒巖解榻夢應好，絕壁題詩語太清。", "陳迹一朝成寂寞，靈臺千古自虛明。", "傳來舊業荒蕪盡，慙愧秋原宿草生。"]'),
('b02c05da-7be1-4720-9366-d06f6aaba1f7','入瑞巖道間得四絕句呈彥集充父二兄  其一','朱熹','宋','宋诗','song-poetry','','[]','憶昔南遊桂樹陰，歸來遺恨滿塵襟。',32,'全唐诗/poet.song.147000.json','["憶昔南遊桂樹陰，歸來遺恨滿塵襟。", "籃輿此日無窮思，萬壑千岩秋氣深。"]'),
('1be32e87-25a7-4124-a345-7850ee88b420','入瑞巖道間得四絕句呈彥集充父二兄  其二','朱熹','宋','宋诗','song-poetry','','[]','翩翩一馬兩肩輿，路轉秋原十里餘。',32,'全唐诗/poet.song.147000.json','["翩翩一馬兩肩輿，路轉秋原十里餘。", "共說前山深更好，不辭迢遞款禪居。"]'),
('2c74586d-82ea-4c7c-aa8d-c78b79cb18a8','入瑞巖道間得四絕句呈彥集充父二兄  其三','朱熹','宋','宋诗','song-poetry','','[]','清溪流過碧山頭，空水澄鮮一色秋。',32,'全唐诗/poet.song.147000.json','["清溪流過碧山頭，空水澄鮮一色秋。", "隔斷紅塵三十里，白雲黄葉共悠悠。"]'),
('fbd8f294-aac9-4e9d-b139-e1a0b0b57b2e','入瑞巖道間得四絕句呈彥集充父二兄  其四','朱熹','宋','宋诗','song-poetry','','[]','風高木落晚秋時，日暮千林黄葉稀。',32,'全唐诗/poet.song.147000.json','["風高木落晚秋時，日暮千林黄葉稀。", "祇有蒼蒼谷中樹，歲寒心事不相違。"]'),
('b3b8f2cd-2c04-4cc7-89b4-5e60a48844f5','挽籍溪胡先生三首  其一','朱熹','宋','宋诗','song-poetry','','[]','夫子生名世，窮居幾歲年。',48,'全唐诗/poet.song.147000.json','["夫子生名世，窮居幾歲年。", "聖門雖力造，美質自天全。", "樂道初辭幣，憂時晚奏篇。", "行藏今已矣，心迹故超然。"]'),
('ccf13f3b-6fa4-4d95-b8a5-eb814d77438c','挽籍溪胡先生三首  其二','朱熹','宋','宋诗','song-poetry','','[]','澹泊忘懷久，渾淪玩意深。',48,'全唐诗/poet.song.147000.json','["澹泊忘懷久，渾淪玩意深。", "簞瓢無改樂，山水自知音。", "冊府遺編在，丘原宰樹陰。", "門人封馬鬣，寒日共沾襟。"]'),
('929c63bb-e538-4781-a34d-cba346464655','挽籍溪胡先生三首  其三','朱熹','宋','宋诗','song-poetry','','[]','先友多淪謝，唯公尚典刑。',48,'全唐诗/poet.song.147000.json','["先友多淪謝，唯公尚典刑。", "向來深繾綣，猶足慰飄零。", "喬木摧霜幹，長空沒曉星。", "傷心遽如許，孤路轉竛竮。"]'),
('364288a6-2620-4741-8b56-1e3d2f82a710','次韻潮州詩六首 濠上齋二首 其一','朱熹','宋','宋诗','song-poetry','','[]','黄堂理事餘，便坐永茲日。',48,'全唐诗/poet.song.147000.json','["黄堂理事餘，便坐永茲日。", "語默趣雖殊，晦明心本一。", "舊聞真體露，已歎群疑失。", "迨此復幾年，定知久純白。"]'),
('bda0cb62-45a3-4ec0-b0d4-b0af292e43c8','次韻潮州詩六首 濠上齋二首 其二','朱熹','宋','宋诗','song-poetry','','[]','道若大路然，奈此人好徑。',48,'全唐诗/poet.song.147000.json','["道若大路然，奈此人好徑。", "即事昧本心，離動覓真靜。", "安知濠上翁，妙入玄中境。", "偶寄郡齋閑，無欲民自正。"]'),
('0a160073-f5da-4231-a519-bdeaa139e237','次韻潮州詩六首 閑坐','朱熹','宋','宋诗','song-poetry','','[]','坐嘯無餘事，淡然塵慮希。',48,'全唐诗/poet.song.147000.json','["坐嘯無餘事，淡然塵慮希。", "閑中自怡悅，妙處絕幾微。", "韓子成今古，顛師果是非。", "悠然發孤些，千載儻來歸。"]'),
('de4fb8cd-b8c0-4126-aa88-685ebe3379e9','次韻潮州詩六首 銷寇','朱熹','宋','宋诗','song-poetry','','[]','年來揭陽郡，牢落海陰墟。',48,'全唐诗/poet.song.147000.json','["年來揭陽郡，牢落海陰墟。", "雲嶠無幽子，潢池有跖徒。", "單車亦已稅，蔓草不須鉏。", "比屋絃歌裏，功高化鰐圖。"]'),
('ca36f7e0-b7bc-4f32-80cb-3db09fdf64ef','次韻潮州詩六首 山丹','朱熹','宋','宋诗','song-poetry','','[]','昔遊嶺海間，幾見蠻卉拆。',48,'全唐诗/poet.song.147000.json','["昔遊嶺海間，幾見蠻卉拆。", "素英漙夕露，朱蘤爛晴日。", "歸來今幾年，晤對祇寒碧。", "因君賦山丹，悅復見顔色。"]'),
('6cbb6c09-7b42-4aa7-8766-479a58e618fd','次韻潮州詩六首 山居即事用疊翠亭韻','朱熹','宋','宋诗','song-poetry','','[]','世情日以踈，庭樹日以密。',48,'全唐诗/poet.song.147000.json','["世情日以踈，庭樹日以密。", "我心自悠悠，兩忘喧與寂。", "門開山疊翠，雨罷雲絕迹。", "天涯此興同，萬里寄消息。"]'),
('d08cceb6-73a8-4f9a-8d19-65ead42c3666','柬舍姪','朱熹','宋','宋诗','song-poetry','','[]','回頭別子時，歲月劇風雨。',48,'全唐诗/poet.song.147000.json','["回頭別子時，歲月劇風雨。", "老大無所成，慙嘆中夜舞。", "長鑱足呻吟，短褐極藍縷。", "古人不可期，炯炯心獨苦。"]'),
('d0cb176c-50aa-478f-93a8-e0754b8d0347','夏日齋居得潮州詩卷咏歎之餘用卒章之韻以紀其事','朱熹','宋','宋诗','song-poetry','','[]','孟夏氣淑清，窗戶有佳色。',72,'全唐诗/poet.song.147000.json','["孟夏氣淑清，窗戶有佳色。", "卧聞幽籜翻，轉覺林景寂。", "參差帙委素，縹緲香橫碧。", "啜菽有餘歡，纓冠非所職。", "故人海邊郡，妙語寄遠翼。", "咏嘆不得聞，超然見胸臆。"]'),
('20e0f040-69e8-4297-9729-aab99afe643d','壽母生朝  其一','朱熹','宋','宋诗','song-poetry','','[]','秋風蕭爽天氣凉，此日何日升斯堂。',144,'全唐诗/poet.song.147000.json','["秋風蕭爽天氣凉，此日何日升斯堂。", "堂中老人壽而康，紅顔綠鬢雙瞳方。", "家貧兒癡但深藏，五年不出門庭荒。", "竈陘十日九不煬，豈辦甘脆陳壺觴。", "低頭包羞汗如漿，老人此心久已忘。", "一笑謂汝庸何傷，人間榮耀豈可常。", "惟有道義思無疆，勉勵汝節彌堅剛。", "熹前再拜謝阿娘，自古作善天降祥。", "但願年年似今日，老萊母子俱徜徉。"]'),
('113d9e9a-90b2-434d-9c89-d645c133d9dc','壽母生朝  其二','朱熹','宋','宋诗','song-poetry','','[]','敬爲生朝舉一觴，短歌歌罷意偏長。',32,'全唐诗/poet.song.147000.json','["敬爲生朝舉一觴，短歌歌罷意偏長。", "願言壽考宜孫子，綠鬢朱顔樂未央。"]'),
('5a45c92b-37c6-4cc7-af20-960a91a40416','壽母生朝  其三','朱熹','宋','宋诗','song-poetry','','[]','陰澹園林歲欲霜，怪來和氣滿中堂。',32,'全唐诗/poet.song.147000.json','["陰澹園林歲欲霜，怪來和氣滿中堂。", "要知積善工夫巧，變得人間作壽鄉。"]'),
('78dd5ab4-f674-49cf-a272-dbb18e8c2d4a','壽母生朝  其四','朱熹','宋','宋诗','song-poetry','','[]','昨夜秋風凉氣歸，今朝喜色動簾幃。',64,'全唐诗/poet.song.147000.json','["昨夜秋風凉氣歸，今朝喜色動簾幃。", "細斟瀲灩新春酒，戲舞斑斕舊綵衣。", "願上龜蓮千歲壽，永令鳬藻一家肥。", "也知厚德天應報，更說陰功世所希。"]'),
('a537b62b-2a0f-4b00-b590-91a7395cf27b','壽母生朝  其五','朱熹','宋','宋诗','song-poetry','','[]','暑退秋容欲凜然，北堂佳氣倍澄鮮。',64,'全唐诗/poet.song.147000.json','["暑退秋容欲凜然，北堂佳氣倍澄鮮。", "舊痾已向新凉失，壽骨應隨爽籟堅。", "塵外光陰那有盡，尊前風月浩無邊。", "癡兒六六今如許，慚媿西河不老仙。"]'),
('2aa80185-95eb-4faa-b31e-98c81daa2cb3','壽母生朝  其六','朱熹','宋','宋诗','song-poetry','','[]','仙人昔住紫琳房，一旦翩然下大荒。',64,'全唐诗/poet.song.147000.json','["仙人昔住紫琳房，一旦翩然下大荒。", "久悟客塵無自性，故應福祿未渠央。", "徙居邂逅成嘉遯，捧檄因循愧漫郎。", "願借寒潭千丈碧，年年此日奉華觴。"]'),
('e02ec247-320e-4e9f-8478-22d4ec74e910','壽母生朝  其七','朱熹','宋','宋诗','song-poetry','','[]','竹柏交柯庭院清，西風不動翠簾旌。',64,'全唐诗/poet.song.147000.json','["竹柏交柯庭院清，西風不動翠簾旌。", "高堂正喜新凉入，樂事仍逢壽斝傾。", "盡室丹衷歸善禱，滿頭綠鬢定重生。", "年年此日歡娛意，更願時豐樂太平。"]'),
('a82a66a8-d9ed-4474-be41-32b8a49146c5','丁丑冬在溫陵陪敦宗李丈與一二道人同和東坡惠州梅花詩皆一再往反昨日見梅追省前事忽忽五年舊詩不復可記憶再和一篇呈諸友兄一笑同賦','朱熹','宋','宋诗','song-poetry','','[]','江梅欲破江南村，無人解與招芳魂。',128,'全唐诗/poet.song.147000.json','["江梅欲破江南村，無人解與招芳魂。", "朔雲爲斷蜂蝶信，凍雨一洗煙塵昏。", "天憐絕艷世無匹，故遣寂寞依山園。", "自欣羌笛娛夜永，未要鄒律回春溫。", "連娟窺水墮殘月，的礫泣露晞晨暾。", "海山清游記玉面，衰病此日空柴門。", "相逢不敢話疇昔，能賦豈必皆成言。", "雕鎸肝腎竟何益，况復制酒哦空樽。"]'),
('3646eeec-2bc1-4466-bbe2-ca0980358c8f','歲晚燕集以梅花已判隔年開分韻賦詩得已字','朱熹','宋','宋诗','song-poetry','','[]','陽愆冬氣昏，日暮悲風起。',96,'全唐诗/poet.song.147000.json','["陽愆冬氣昏，日暮悲風起。", "晤言欲誰從，斗酒會隣里。", "盤餐乏珍脆，肴核闕儲峙。", "無以奉嘉賓，瓶罄亦可耻。", "所頼數子賢，深睠不余鄙。", "夜闌更促席，燈火共歡喜。", "酣歌氣激冽，傑句韻清美。", "衰懶愧英游，歲晚情何已。"]'),
('160a3433-a2e0-4658-a55b-29e33177f3e2','卓國太生朝  其一','朱熹','宋','宋诗','song-poetry','','[]','鳳凰山下鳳凰城，十載重來雙眼明。',64,'全唐诗/poet.song.147000.json','["鳳凰山下鳳凰城，十載重來雙眼明。", "賸喜故人頻獻納，足知賢母外榮名。", "生朝舉酒天香裏，賤子當歌魯頌聲。", "問訊豪眉今幾許，年年此日照人清。"]'),
('c86149a6-ae2f-419f-ab4d-cca8b6879667','卓國太生朝  其二','朱熹','宋','宋诗','song-poetry','','[]','玄冬周四運，肅氣驅煩喧。',120,'全唐诗/poet.song.147000.json','["玄冬周四運，肅氣驅煩喧。", "孕此貞秀質，德美難具論。", "巍巍北堂高，福履神所敦。", "晨昏極榮養，夙昔蒙天恩。", "明年啟國封，屈狄文魚軒。", "斑衣結紫綬，玉樹承金尊。", "歡娛何所忘，千載如飛奔。", "惟應玄中趣，眇眇自本根。", "洗心河漢津，入此無窮門。", "超然謝衆甫，永與天壤存。"]'),
('609c7c81-c237-4495-b6f9-33829fe7ccd6','社後一日作','朱熹','宋','宋诗','song-poetry','','[]','聖作重品節，等殺古所詳。',132,'全唐诗/poet.song.147000.json','["聖作重品節，等殺古所詳。", "里有秦社稷，僭差遂無章。", "王綱諒已隳，精意尚不亡。", "尚論千載前，簡編有遺芳。", "侃侃陳孺子，恂恂萬春鄉。", "敬恭事耆老，禱賽謹田桑。", "悠悠我里居，歲事有故常。", "向來諸老翁，惇厖亦端莊。", "交神庶或享，與物同樂康。", "今我胡不樂，悵然下頹岡。", "古人不可見，今人自猖狂。"]'),
('e66c520f-6538-4474-99cb-937cdf0003bd','三月三日祀事畢因脩禊事于靈梵以高閣一長望分韻賦詩得一字','朱熹','宋','宋诗','song-poetry','','[]','逝川無停波，歲月一何疾。',144,'全唐诗/poet.song.147000.json','["逝川無停波，歲月一何疾。", "居然雨露濡，我意日蕭瑟。", "共惟西山足，宰樹久蒙密。", "晤言起哀敬，時事該禮律。", "肴羞既紛羅，薦饋亦芳苾。", "周旋極悽愴，俛仰詎終畢。", "更衣適精舍，鄰曲會茲日。", "簋黍畀煇胞，從容罄膋膟。", "嘉賓更盤礴，環堵窺逸筆。", "即事君獨哦，非才我何述。", "矧茲衰病餘，苦畏煩慮怵。", "賦罷掩寒棲，存存常抱一。"]'),
('9f3be18d-84e3-4a63-a90e-956bdc171a8c','夏日二首  其一','朱熹','宋','宋诗','song-poetry','','[]','端居倦時暑，竟日掩柴門。',48,'全唐诗/poet.song.147000.json','["端居倦時暑，竟日掩柴門。", "窗風遠飆至，竹樹清陰繁。", "靜有圖史樂，寂無車馬喧。", "茲焉愜所尚，難與世人論。"]'),
('6a4ac35b-3efe-403e-8c57-5bd956637486','夏日二首  其二','朱熹','宋','宋诗','song-poetry','','[]','季夏園木暗，窗戶貯清陰。',48,'全唐诗/poet.song.147000.json','["季夏園木暗，窗戶貯清陰。", "長風一掩苒，衆綠何蕭椮。", "玩此消永晝，泠然滌幽襟。", "俯仰無所爲，聊復得此心。"]'),
('192934cf-7655-49b1-9293-8456115599f0','汲清泉漬奇石置熏爐其後香烟被之江山雲物居然有萬里趣因作四小詩  其一','朱熹','宋','宋诗','song-poetry','','[]','晴窗出寸碧，倒影媚中川。',24,'全唐诗/poet.song.147000.json','["晴窗出寸碧，倒影媚中川。", "雲氣一吞吐，湖江心渺然。"]'),
('ebb14f05-9397-4c0b-85f8-2b00e3413a9f','汲清泉漬奇石置熏爐其後香烟被之江山雲物居然有萬里趣因作四小詩  其二','朱熹','宋','宋诗','song-poetry','','[]','一水渺空闊，羣山中接連。',24,'全唐诗/poet.song.147000.json','["一水渺空闊，羣山中接連。", "寒陰白霧湧，飛度碧峰前。"]'),
('d93f77f0-c61e-4ec1-b862-2bb9074d7bcf','汲清泉漬奇石置熏爐其後香烟被之江山雲物居然有萬里趣因作四小詩  其三','朱熹','宋','宋诗','song-poetry','','[]','隠几對寒碧，忘言心自閑。',24,'全唐诗/poet.song.147000.json','["隠几對寒碧，忘言心自閑。", "豈知宜寂士，滅跡青峯間。"]'),
('6217f08e-0e71-4b5c-96e7-ccaba5f52dce','汲清泉漬奇石置熏爐其後香烟被之江山雲物居然有萬里趣因作四小詩  其四','朱熹','宋','宋诗','song-poetry','','[]','吟餘忽自笑，老矣方好弄。',24,'全唐诗/poet.song.147000.json','["吟餘忽自笑，老矣方好弄。", "慨然思古人，尺璧寸陰重。"]'),
('cbe3b06a-675c-4ab9-8318-0c5b18c417c4','偶題三首  其一','朱熹','宋','宋诗','song-poetry','','[]','門外青山翠紫堆，幅巾終日面崔嵬。',32,'全唐诗/poet.song.147000.json','["門外青山翠紫堆，幅巾終日面崔嵬。", "只看雲斷成飛雨，不道雲從底處來。"]'),
('acf25653-e00c-4e16-bd5f-7dc195b8e55b','偶題三首  其二','朱熹','宋','宋诗','song-poetry','','[]','擘開蒼峽吼奔雷，萬斛飛泉湧出來。',32,'全唐诗/poet.song.147000.json','["擘開蒼峽吼奔雷，萬斛飛泉湧出來。", "斷梗枯槎無泊處，一川寒碧自縈回。"]'),
('6bb1be1d-71dd-4a5f-8112-701e5cec76f8','偶題三首  其三','朱熹','宋','宋诗','song-poetry','','[]','步隨流水覓溪源，行到源頭却惘然。',32,'全唐诗/poet.song.147000.json','["步隨流水覓溪源，行到源頭却惘然。", "始悟真源行不到，倚筇隨處弄潺湲。"]'),
('d445f3b4-e3a9-453f-a178-5383bbe137d5','次張彥輔韻','朱熹','宋','宋诗','song-poetry','','[]','風霜歲云徂，塵事瞇雙目。',240,'全唐诗/poet.song.147000.json','["風霜歲云徂，塵事瞇雙目。", "故人書鼎來，照眼一連玉。", "把玩不知疲，日晏坐空腹。", "卷藏什襲秘，寒光夜穿櫝。", "嗟予骯髒姿，十駕不能速。", "丘壑聊自娛，簞瓢亦云足。", "君侯湖海士，逸氣謝追逐。", "胡爲不予鄙，乃肯顧林谷。", "高軒緩前期，清夢遶雙竹。", "起將杜陵句，寫寄玉川屋。", "我窮詩未工，最覺貂難續。", "感君慇懃意，吟苦屢更燭。", "羣公饒藻思，裂牋動盈束。", "歷險正摧輈，爭先俄擊轂。", "低回欲引避，悵望曷歸宿。", "出吻竟無奇，彊顔終自恧。", "北風催歲年，兩鬢失新綠。", "樊生念學稼，曹子悲食粟。", "死灰寧復然，寡過良所欲。", "耿耿自知明，何勞詹尹卜。"]'),
('26c45d77-b3db-475a-bfdd-85677e1a7b0e','次張彥輔賞梅韻','朱熹','宋','宋诗','song-poetry','','[]','朔風萬里開雲屏，清霜夜墜朝景晴。',256,'全唐诗/poet.song.147000.json','["朔風萬里開雲屏，清霜夜墜朝景晴。", "南枝浩蕩正春色，凍蘂的皪含空明。", "花邊偶對青銅鏡，槁項不堪冰雪映。", "擁爐獨坐只悲吟，振策出遊舒遠興。", "暗香何處時一飄，行行復值最長條。", "仰頭欲折渺誰贈，滿意相思那得邀。", "極知異縣淹行李，心賞未甘輕付畀。", "石雄賦罷不相聞，秀野書來因舉似。", "兩翁句法爭新奇，畫出踈影沉寒漪。", "幽探自出塵境外，勝概未許兒曹知。", "祇今嚼蘂攀條處，它日重來記前度。", "風臺月觀悄無言，玉笛冰灘索同賦。", "嗟予衰懶倦將迎，過眼紛紛無復情。", "尚喜踈英窺水白，更憐落片點苔青。", "興來亂插飛蓬首，擬向君家醉君酒。", "酒酣耳熱莫狂歌，布鼓雷門須縮手。"]'),
('c9870b69-89d7-42c9-8048-77f3a6d44c98','借韻呈府判張丈既以奉箴且求教藥','朱熹','宋','宋诗','song-poetry','','[]','一生江海迥無儔，材大應容小未周。',64,'全唐诗/poet.song.147000.json','["一生江海迥無儔，材大應容小未周。", "景好身閑真復樂，酒酣耳熱却堪憂。", "飛騰莫羨摩天鵠，純熟須參露地牛。", "我亦醒狂多忤物，頗能還贈一言不。"]'),
('db572a8f-b793-4fd9-a0ef-9adc1423854a','家山堂晚照效輞川體作二首  其一','朱熹','宋','宋诗','song-poetry','','[]','夕陽浮遠空，西峯背殘照。',24,'全唐诗/poet.song.147000.json','["夕陽浮遠空，西峯背殘照。", "爽氣轉分明，與君共晚眺。"]'),
('0e58feb3-7fc4-4d5c-ae6a-93a5c9353f3e','家山堂晚照效輞川體作二首  其二','朱熹','宋','宋诗','song-poetry','','[]','山外夕嵐明，山前空翠滴。',24,'全唐诗/poet.song.147000.json','["山外夕嵐明，山前空翠滴。", "日暮無與期，閑來岸輕幘。"]'),
('0ae1aef7-7d3a-4876-8d1a-db8070a2e192','即事有懷寄彥輔仲宗二兄二首  其一','朱熹','宋','宋诗','song-poetry','','[]','一水方涵碧，千林已變紅。',48,'全唐诗/poet.song.147000.json','["一水方涵碧，千林已變紅。", "農收爭暖日，老病怯高風。", "徙倚非無計，心期莫與同。", "向來歡會處，離合太匆匆。"]'),
('36923cb4-2873-4d5a-83f0-7a6ceed84ed3','即事有懷寄彥輔仲宗二兄二首  其二','朱熹','宋','宋诗','song-poetry','','[]','聞說雙飛槳，翩然下廣津。',48,'全唐诗/poet.song.147000.json','["聞說雙飛槳，翩然下廣津。", "江湖知子樂，魚鳥諒情親。", "淹速須關命，行藏不繫人。", "三山雖好在，惜取自由身。"]'),
('cffe481f-0b19-47a4-abfb-98b7b13abf73','次知府府判二丈韻三首  其一','朱熹','宋','宋诗','song-poetry','','[]','兩公清廟瑟，窈窕拂朱絲。',48,'全唐诗/poet.song.147000.json','["兩公清廟瑟，窈窕拂朱絲。", "事紀一朝勝，名從千古垂。", "流傳當共賦，惆悵不同時。", "且要君頤解，寧辭匡說詩。"]'),
('d7bd7ab1-8cc5-4421-a91e-852c637c878a','次知府府判二丈韻三首  其二','朱熹','宋','宋诗','song-poetry','','[]','憶昨中秋夕，寒盟約重尋。',48,'全唐诗/poet.song.147000.json','["憶昨中秋夕，寒盟約重尋。", "幔亭歡舉酒，江閣快論心。", "月墮俱忘起，罍空始罷斟。", "只今千嶺隔，悵望一何深。"]'),
('f739ff0c-0780-4431-89ec-c3fdb486801e','次知府府判二丈韻三首  其三','朱熹','宋','宋诗','song-poetry','','[]','志士懷韜畧，奇兵吼鏌干。',48,'全唐诗/poet.song.147000.json','["志士懷韜畧，奇兵吼鏌干。", "關河那得往，肝膽不勝寒。", "壯節悲如許，雄圖渺未闌。", "皇輿方仄席，陋巷敢求安。"]'),
('ea63a41f-0aba-4646-b7a6-b7c28290c859','巢居之集以中有學仙侶吹簫弄明月爲韻探策賦之而熹得中字遂誤爲諸君所推高俾專主約既而賦詩者頗失期於是令最後者具主禮以當罰乃稍集獨敦夫圭甫違令後至衆白罰如約飲罷以蒼茫雲海路歲晚將無獲分韻熹得將字而子衡兄得蒼字實代熹出令','朱熹','宋','宋诗','song-poetry','','[]','一昨樓上飲，所歡不可忘。',108,'全唐诗/poet.song.147000.json','["一昨樓上飲，所歡不可忘。", "羣公各賦詩，佩玉何鏘鏘。", "二子朱絲絃，掩抑獨叵量。", "經營久不作，一奏聲滿堂。", "巧遲未足多，譴負先取償。", "主盟謬夙推，否德愧莫當。", "茲焉不舉法，何以存令章。", "劉子具盤食，魏子輸壺漿。", "悠然復一醉，歸路相扶將。"]'),
('cc3f51a2-2b7d-4146-ab05-d3e60746e921','昨承諸兄臨辱不揆以薄酒蔬食延駐都騎明日視壁間所張墨刻有亡去者人以爲德慶丈之廋也馳問遣索蒙需拙詩輒賦所懷往奉一笑而尊犍刻可以歸於我矣','朱熹','宋','宋诗','song-poetry','','[]','歲暮霜霰集，賓友從我游。',96,'全唐诗/poet.song.147000.json','["歲暮霜霰集，賓友從我游。", "置酒臨高齋，觴酌屢獻酬。", "雞黍整中庖，肴核供庶羞。", "所恨乏珍肥，歡意不得周。", "何牾上客懷，徙我夜壑舟。", "平明但素壁，篆刻不可求。", "究索勞象罔，高蹤希盜丘。", "我亦慚仲子，獨未忘輕裘。"]'),
('8a7406aa-c109-41b7-812d-491c78238d7e','昨以詩徵亡碑於四十一丈既蒙酬和而諸兄亦繼作焉聯爲巨編藏之巾笥雖所亡古刻不可復得而此之所獲則已多矣顧其中猶有不能釋然者因念吾子厚隸法妙古人當爲我大書偉辭於壁庶以焜燿區區之望彼死鬼之陳迹其存亡蓋不足爲重輕也次韻見意云','朱熹','宋','宋诗','song-poetry','','[]','端居感物化，悵恨不出游。',96,'全唐诗/poet.song.147000.json','["端居感物化，悵恨不出游。", "賦詩往追亡，顧得雜佩酬。", "結綬光陸離，縕袍非所羞。", "終然抱耿耿，尼父悲東周。", "凄凉尊犍崖，望想滄浪舟。", "低徊不得去，寂寞將焉求。", "安知崔蔡徒，考槃共斯丘。", "爲我揮素壁，報君當紫裘。"]'),
('d1d464ec-c151-440c-94de-958a36d21877','再賦解嘲','朱熹','宋','宋诗','song-poetry','','[]','宇宙一瞬息，人生等浮游。',96,'全唐诗/poet.song.147000.json','["宇宙一瞬息，人生等浮游。", "云何百年內，萬變紛相酬。", "顛倒不自知，旁觀乃堪羞。", "拱揖尚虞夏，干戈到商周。", "豈悟曠士懷，泛若不繫舟。", "駟馬諒弗視，名高非所求。", "彼哉夸奪子，逝矣崑崙丘。", "褰裳絕冥外，天風舞雲裘。"]'),
('99a7abd6-a5b6-4ed7-8623-4e69bf57e9ad','題祝生畫呈裴丈二首  其一','朱熹','宋','宋诗','song-poetry','','[]','近代丹青手，心期良獨難。',48,'全唐诗/poet.song.147000.json','["近代丹青手，心期良獨難。", "夫君偏有思，妙處却無端。", "堂上三湘遠，人間五月寒。", "空囊今有此，不用一錢看。"]'),
('cf44d2e3-38e3-48fb-943c-c546910559bb','題祝生畫呈裴丈二首  其二','朱熹','宋','宋诗','song-poetry','','[]','斗酒淋漓後，顛狂不作難。',48,'全唐诗/poet.song.147000.json','["斗酒淋漓後，顛狂不作難。", "千峯俄紙上，萬景忽豪端。", "石瘦岡巒古，林深煙雨寒。", "蒼茫無限意，俗眼若爲看。"]'),
('b0f2ee0a-f08f-47a9-b246-ab3645264006','挽延平李先生三首  其一','朱熹','宋','宋诗','song-poetry','','[]','河洛傳心後，毫釐復易差。',48,'全唐诗/poet.song.147000.json','["河洛傳心後，毫釐復易差。", "淫辭方眩俗，夫子獨名家。", "本本初無二，存存自不邪。", "誰知經濟業，零落舊煙霞。"]'),
('58ed114b-efae-4d8a-b832-573c399bfd23','挽延平李先生三首  其二','朱熹','宋','宋诗','song-poetry','','[]','聞道無餘事，窮居不計年。',48,'全唐诗/poet.song.147000.json','["聞道無餘事，窮居不計年。", "簞瓢渾謾與，風月自悠然。", "灑落濂溪句，從容洛社篇。", "平生行樂地，今日但新阡。"]'),
('4cc7f8f2-a3c8-4af4-b940-ece4f65d6d22','挽延平李先生三首  其三','朱熹','宋','宋诗','song-poetry','','[]','岐路方南北，師門數仞高。',48,'全唐诗/poet.song.147000.json','["岐路方南北，師門數仞高。", "一言資善誘，十載笑徒勞。", "斬板今來此，懷經痛所遭。", "有疑無與析，揮淚首頻搔。"]'),
('a8687277-0f36-4cc8-b31c-48ea8a2a935c','用西林舊韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','一自籃輿去不回，故山空鎖舊池臺。',32,'全唐诗/poet.song.147000.json','["一自籃輿去不回，故山空鎖舊池臺。", "傷心觸目經行處，幾度親陪杖屨來。"]'),
('aa709c3f-0270-44a9-9c5f-8b48bfe6ab5b','用西林舊韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','上疏歸來空皂囊，未妨隨意宿僧房。',32,'全唐诗/poet.song.147000.json','["上疏歸來空皂囊，未妨隨意宿僧房。", "舊題歲月那堪數，慙愧平生一瓣香。"]'),
('e84df7ea-606e-4738-86ae-c2bdcd8b3f0d','奉同張敬夫城南二十詠 納湖','朱熹','宋','宋诗','song-poetry','','[]','詩筒連畫卷，坐看復行吟。',24,'全唐诗/poet.song.147000.json','["詩筒連畫卷，坐看復行吟。", "想像南湖水，秋來幾許深。"]'),
('900b635c-e269-4015-8ec2-b6e781c28b62','奉同張敬夫城南二十詠 東渚','朱熹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','小山幽桂叢，歲暮靄佳色。',24,'全唐诗/poet.song.147000.json','["小山幽桂叢，歲暮靄佳色。", "花落洞庭波，秋風渺何極。"]'),
('2170ba1c-373b-47e0-98c6-9648b33526e0','奉同張敬夫城南二十詠 詠歸橋','朱熹','宋','宋诗','song-poetry','','[]','綠漲平湖水，朱欄跨小橋。',24,'全唐诗/poet.song.147000.json','["綠漲平湖水，朱欄跨小橋。", "舞雩千載事，歷歷在今朝。"]'),
('7039bccb-3332-462a-a547-4244e4161a8c','奉同張敬夫城南二十詠 船齋','朱熹','宋','宋诗','song-poetry','','[]','考槃雖在陸，滉瀁水雲深。',24,'全唐诗/poet.song.147000.json','["考槃雖在陸，滉瀁水雲深。", "正爾滄洲趣，難忘魏闕心。"]'),
('4d1a7932-1539-43f8-a449-48da48174763','奉同張敬夫城南二十詠 麗澤堂','朱熹','宋','宋诗','song-poetry','','[]','堂後林陰密，堂前湖水深。',24,'全唐诗/poet.song.147000.json','["堂後林陰密，堂前湖水深。", "感君懷我意，千里夢相尋。"]'),
('3a2584a0-5f0b-474a-b7dc-befa5149b322','奉同張敬夫城南二十詠 蘭澗','朱熹','宋','宋诗','song-poetry','','[]','光風浮碧澗，蘭杜日猗猗。',24,'全唐诗/poet.song.147000.json','["光風浮碧澗，蘭杜日猗猗。", "竟歲無人采，含薰祇自知。"]'),
('de4c94fe-a89b-416b-b531-0964a458caa0','奉同張敬夫城南二十詠 書樓','朱熹','宋','宋诗','song-poetry','','[]','君家一編書，不自圯上得。',24,'全唐诗/poet.song.147000.json','["君家一編書，不自圯上得。", "石室寄林端，時來玩幽賾。"]'),
('e732fe36-b931-4627-a7b9-ac2889f2708d','奉同張敬夫城南二十詠 山齋','朱熹','宋','宋诗','song-poetry','','[]','藏書樓上頭，讀書樓下屋。',24,'全唐诗/poet.song.147000.json','["藏書樓上頭，讀書樓下屋。", "懷哉千載心，俯仰數椽足。"]'),
('ca630343-ad71-4d71-b656-16186e2776cc','奉同張敬夫城南二十詠 蒙軒','朱熹','宋','宋诗','song-poetry','','[]','先生湖海姿，蒙養今自閟。',24,'全唐诗/poet.song.147000.json','["先生湖海姿，蒙養今自閟。", "銘坐仰先賢，點畫存彖繫。"]'),
('8cee3252-b57d-4fbb-9c8d-820757de3a27','奉同張敬夫城南二十詠 石瀨','朱熹','宋','宋诗','song-poetry','','[]','疏此竹下渠，漱彼澗中石。',24,'全唐诗/poet.song.147000.json','["疏此竹下渠，漱彼澗中石。", "暮館繞寒聲，秋空動澄碧。"]'),
('7a9a525d-08ab-46e4-b740-e14e480eab7a','奉同張敬夫城南二十詠 卷雲亭','朱熹','宋','宋诗','song-poetry','','[]','西山雲氣深，徙倚一舒嘯。',24,'全唐诗/poet.song.147000.json','["西山雲氣深，徙倚一舒嘯。", "浩蕩忽搴開，爲君展遐眺。"]'),
('7a081597-6ad9-4475-80b9-7b5f7a159624','奉同張敬夫城南二十詠 柳堤','朱熹','宋','宋诗','song-poetry','','[]','渚華初出水，堤樹亦成行。',24,'全唐诗/poet.song.147000.json','["渚華初出水，堤樹亦成行。", "吟罷天津句，薰風拂面凉。"]'),
('fd4e2728-6e5e-4468-af6e-4295666ae0c0','奉同張敬夫城南二十詠 月榭','朱熹','宋','宋诗','song-poetry','','[]','月色三秋白，湖光四面平。',24,'全唐诗/poet.song.147000.json','["月色三秋白，湖光四面平。", "與君凌倒景，上下極空明。"]'),
('1140bc04-f665-48eb-bb03-e7071ba15b48','奉同張敬夫城南二十詠 濯清','朱熹','宋','宋诗','song-poetry','','[]','涉江采芙蓉，十反心無斁。',24,'全唐诗/poet.song.147000.json','["涉江采芙蓉，十反心無斁。", "不遇無極翁，深衷竟誰識。"]'),
('40c8969c-8487-4f6e-8a3c-edfd1f47392e','奉同張敬夫城南二十詠 西嶼','朱熹','宋','宋诗','song-poetry','','[]','朝吟東渚風，夕弄西嶼月。',24,'全唐诗/poet.song.147000.json','["朝吟東渚風，夕弄西嶼月。", "人境諒非遥，湖山自幽絕。"]'),
('1cad2fdf-d110-4232-9be7-8378f7939dcf','奉同張敬夫城南二十詠 淙琤谷','朱熹','宋','宋诗','song-poetry','','[]','湖光湛不流，嵌竇亦潜注。',24,'全唐诗/poet.song.147000.json','["湖光湛不流，嵌竇亦潜注。", "倚杖忽淙琤，竹深無覓處。"]'),
('6512adef-7f51-4881-b6ff-ff484d8f58a7','奉同張敬夫城南二十詠 聽雨舫','朱熹','宋','宋诗','song-poetry','','[]','綵舟停畫槳，容與得欹眠。',24,'全唐诗/poet.song.147000.json','["綵舟停畫槳，容與得欹眠。", "夢破蓬窗雨，寒聲動一川。"]'),
('1eb3ed95-5bf4-4ce0-a95b-ebfec3c8f660','奉同張敬夫城南二十詠 梅堤','朱熹','宋','宋诗','song-poetry','','[]','仙人冰雪姿，貞秀絕倫擬。',24,'全唐诗/poet.song.147000.json','["仙人冰雪姿，貞秀絕倫擬。", "驛使詎知聞，尋香問煙水。"]'),
('cc6df97f-220e-416a-bce1-53ebe87edc76','奉同張敬夫城南二十詠 采菱舟','朱熹','宋','宋诗','song-poetry','','[]','湖平秋水碧，桂棹木蘭舟。',24,'全唐诗/poet.song.147000.json','["湖平秋水碧，桂棹木蘭舟。", "一曲菱歌晚，驚飛欲下鷗。"]'),
('b6f66941-008d-435f-916f-04a1b5b1841c','奉同張敬夫城南二十詠 南阜','朱熹','宋','宋诗','song-poetry','','[]','高丘復層觀，何日去登臨。',24,'全唐诗/poet.song.147000.json','["高丘復層觀，何日去登臨。", "一目長空盡，寒江列暮岑。"]'),
('782b4f29-b464-4604-8e32-9d18ac663752','次韻傅丈武夷道中五絕句  其一','朱熹','宋','宋诗','song-poetry','','[]','地久天長歲不留，坐來念念失藏舟。',32,'全唐诗/poet.song.147000.json','["地久天長歲不留，坐來念念失藏舟。", "回看萬法皆兒戲，還直先生一笑不。"]'),
('9ed4338c-34f8-4587-89c0-755bcfb0ae14','次韻傅丈武夷道中五絕句  其二','朱熹','宋','宋诗','song-poetry','','[]','分符擁節幾經年，聞道方成屋數椽。',32,'全唐诗/poet.song.147000.json','["分符擁節幾經年，聞道方成屋數椽。", "只恐未容高枕卧，却須持橐聽鳴鞭。"]'),
('3db68305-7219-45a6-82d9-f0220397350f','次韻傅丈武夷道中五絕句  其三','朱熹','宋','宋诗','song-poetry','','[]','勳業今從鏡裏休，篋中空有敝貂裘。',32,'全唐诗/poet.song.147000.json','["勳業今從鏡裏休，篋中空有敝貂裘。", "死灰那復飛揚意，惠許深慚不易酬。"]'),
('1b025cff-b74e-4951-b17f-e3d328ce038f','次韻傅丈武夷道中五絕句  其四','朱熹','宋','宋诗','song-poetry','','[]','常記桐城十載前，幾回風雨對床眠。',32,'全唐诗/poet.song.147000.json','["常記桐城十載前，幾回風雨對床眠。", "他年空憶今年事，却說黄亭共惘然。"]'),
('5bbd4c56-95bf-4829-bbb9-f8b37f7aca98','次韻傅丈武夷道中五絕句  其五','朱熹','宋','宋诗','song-poetry','','[]','諸郎步武各駸駸，季子尤憐産萬金。',32,'全唐诗/poet.song.147000.json','["諸郎步武各駸駸，季子尤憐産萬金。", "衣鉢相傳自端的，老生無用與安心。"]'),
('b533a3eb-3fc9-4371-8759-2e6118262c0b','題畫卷 小山','朱熹','宋','宋诗','song-poetry','','[]','飛來小坡坨，未雨已滂濞。',24,'全唐诗/poet.song.147000.json','["飛來小坡坨，未雨已滂濞。", "荒此定何人，蘇公有遺記。"]'),
('a3739187-a2c2-48c8-9dbb-3120951f9976','題畫卷 吳畫','朱熹','宋','宋诗','song-poetry','','[]','妙絕吳生筆，飛揚信有神。',24,'全唐诗/poet.song.147000.json','["妙絕吳生筆，飛揚信有神。", "羣仙不愁思，步步出風塵。"]'),
('4c89b92e-387f-495e-8e29-57e4c66e7c30','題畫卷 卵研','朱熹','宋','宋诗','song-poetry','','[]','端溪有潜虬，孕此金玉質。',24,'全唐诗/poet.song.147000.json','["端溪有潜虬，孕此金玉質。", "混沌一竅開，千年瀉寒液。"]'),
('46d9aa7a-4a23-4cfb-832c-cc70d76c8e82','題畫卷 鬼佛','朱熹','宋','宋诗','song-poetry','','[]','冥濛罔象姿，相好菩薩面。',24,'全唐诗/poet.song.147000.json','["冥濛罔象姿，相好菩薩面。", "鬼佛吾詎知，水石翫奇變。"]'),
('f3408dd5-0a75-4f12-aba6-eea550f15331','題畫卷 范寬','朱熹','宋','宋诗','song-poetry','','[]','山雄雲氣深，樹老風霜勁。',24,'全唐诗/poet.song.147000.json','["山雄雲氣深，樹老風霜勁。", "下有考槃人，超摇得真性。"]'),
('338bba53-3dc3-4b2e-af29-e332cadff4a6','題祝生畫','朱熹','宋','宋诗','song-poetry','','[]','裴侯愛畫老成癖，歲晚倦遊家四壁。',192,'全唐诗/poet.song.147000.json','["裴侯愛畫老成癖，歲晚倦遊家四壁。", "隨身只有萬疊山，秘不示人私自惜。", "俗人教看亦不識，我獨摩挲三太息。", "問君何處得此奇，和璧隋珠未爲敵。", "答云衢州老祝翁，胸次自有陰陽工。", "峙山融川取世界，咳雲唾雨呼雷風。", "昨來邂逅衢城東，定交斗酒歡無窮。", "自言妙處容我識，爲我掃此須臾中。", "爾時聞名今識面，回首十年齊掣電。", "裴侯已死我亦衰，祇君雖老身猶𡏖。", "眼明骨輕鬚不變，筆下江山轉葱蒨。", "爲君多織機中練，更約無事重相見。"]'),
('4c02bd37-bb84-4f51-8370-a1e6fa0dc63c','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其一','朱熹','宋','宋诗','song-poetry','','[]','高人山水心，結習自無始。',48,'全唐诗/poet.song.147000.json','["高人山水心，結習自無始。", "五畝江上園，清陰遍桃李。", "一堂聊自娛，三徑亦可喜。", "試問避俗翁，何如尊賢里。"]'),
('884cec9a-05bd-46cf-b150-3e3ab643f146','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其二','朱熹','宋','宋诗','song-poetry','','[]','門前車馬客，無非朝大夫。',48,'全唐诗/poet.song.147000.json','["門前車馬客，無非朝大夫。", "問公獨何事，中歲遽此圖。", "長安二三公，髮白形枯臞。", "隠憂念名節，亦有此樂無。"]'),
('6cad3f09-b74c-4e5c-a182-4dc2d9f2327f','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其三','朱熹','宋','宋诗','song-poetry','','[]','君侯嗜圖史，插架何其多。',48,'全唐诗/poet.song.147000.json','["君侯嗜圖史，插架何其多。", "徙居三十乘，流汗幾橐駝。", "千載誰晤語，端居自絃歌。", "至哉天下樂，歲月如子何。"]'),
('8d764e1b-5238-4387-bc42-adf691996016','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其四','朱熹','宋','宋诗','song-poetry','','[]','西山一何高，雲氣出寒麓。',48,'全唐诗/poet.song.147000.json','["西山一何高，雲氣出寒麓。", "中有無事人，鳴泉遶茅屋。", "宴坐今幾何，無以媚幽獨。", "興至偶成篇，呼兒爲余讀。"]'),
('37f3db90-0910-4e87-b56d-ba9324b5b1e6','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其五','朱熹','宋','宋诗','song-poetry','','[]','我居深山中，茅舍破不補。',48,'全唐诗/poet.song.147000.json','["我居深山中，茅舍破不補。", "上見風攪林，下有雲承宇。", "聞公落新宮，戶牖不可數。", "懶惰心力衰，念公亦良苦。"]'),
('460c5a62-a83a-4592-86eb-33d4f30a229b','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其六','朱熹','宋','宋诗','song-poetry','','[]','夜吟招隠詩，月落寒泉井。',48,'全唐诗/poet.song.147000.json','["夜吟招隠詩，月落寒泉井。", "自非千載人，誰與共清景。", "散髮心朗寥，凝神味淵永。", "功名恐相期，富貴非所幸。"]'),
('6d5faab8-32f5-4af7-8da9-de0cb4849d87','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其七','朱熹','宋','宋诗','song-poetry','','[]','仙人空山居，道意妙羣物。',48,'全唐诗/poet.song.147000.json','["仙人空山居，道意妙羣物。", "度世君則然，脩身吾豈不。", "飛行仰雲路，趺坐探理窟。", "獨夜扣星壇，清齋具簪笏。"]'),
('35557053-ab00-4fb8-ab74-ba6f6bb92fd3','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其八','朱熹','宋','宋诗','song-poetry','','[]','青山背夕陽，茲景公所愛。',48,'全唐诗/poet.song.147000.json','["青山背夕陽，茲景公所愛。", "虛堂日落時，遷坐一解带。", "嵐分疑有處，鳥度知無礙。", "須臾暮色來，默默無與會。"]'),
('c8750304-2ad0-4e4f-a87b-89b014f5e99d','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其九','朱熹','宋','宋诗','song-poetry','','[]','端居屏塵慮，萬事付一尊。',48,'全唐诗/poet.song.147000.json','["端居屏塵慮，萬事付一尊。", "客來語世故，舉白當浮君。", "超摇謝衆甫，噂沓從諸孫。", "何以自怡悅，窗中見秋雲。"]'),
('3c767549-b554-4459-b157-064341881568','秀野以喜無多屋宇幸不礙雲山爲韻賦詩熹伏讀佳作率爾攀和韻劇思慳無復律呂笑覽之餘賜以斤斧幸甚  其一○','朱熹','宋','宋诗','song-poetry','','[]','清溪何迢迢，上有千仞山。',48,'全唐诗/poet.song.147000.json','["清溪何迢迢，上有千仞山。", "山中學仙侶，白石爲門關。", "丹經苦吟哦，至道窮躋攀。", "豈知人間世，風塵縈九寰。"]'),
('802f628a-b8c8-4bd0-8753-fb43b4aaab90','次劉秀野蔬食十三詩韻 乳餠','朱熹','宋','宋诗','song-poetry','','[]','清朝薦踈盤，乳鉢有真味。',24,'全唐诗/poet.song.147000.json','["清朝薦踈盤，乳鉢有真味。", "不用精瓊糜，無勞爛羊胃。"]'),
('f4ac414c-aa03-4988-ac7e-13b5dcb6f03e','次劉秀野蔬食十三詩韻 新笋','朱熹','宋','宋诗','song-poetry','','[]','翛翛江上林，白日暗風雨。',24,'全唐诗/poet.song.147000.json','["翛翛江上林，白日暗風雨。", "下有萬玉虯，三冬卧寒土。"]'),
('8f00b307-78cb-4b23-a441-7aa06b2349b5','次劉秀野蔬食十三詩韻 紫蕈','朱熹','宋','宋诗','song-poetry','','[]','誰將紫芝苗，種此槎上土。',24,'全唐诗/poet.song.147000.json','["誰將紫芝苗，種此槎上土。", "便學商山翁，風餐謝肥羜。"]'),
('04c7475c-5338-4e86-b2fe-e794c80c6a2d','次劉秀野蔬食十三詩韻 子薑','朱熹','宋','宋诗','song-poetry','','[]','薑云能損心，此謗誰與雪。',24,'全唐诗/poet.song.147000.json','["薑云能損心，此謗誰與雪。", "請論去穢功，神明看朝徹。"]'),
('e96c3eab-7c06-455d-b8c0-ce63c42d4420','次劉秀野蔬食十三詩韻 茭筍','朱熹','宋','宋诗','song-poetry','','[]','寒茭翳秋塘，風葉自長短。',24,'全唐诗/poet.song.147000.json','["寒茭翳秋塘，風葉自長短。", "刳心一飽餘，并得牀敷軟。"]'),
('7e8430c5-315c-4c62-8ac9-1d1b6ce463b8','次劉秀野蔬食十三詩韻 南芥','朱熹','宋','宋诗','song-poetry','','[]','黄龍記昔遊，園客有佳遺。',24,'全唐诗/poet.song.147000.json','["黄龍記昔遊，園客有佳遺。", "不謂洛生吟，輟餐時擁鼻。"]'),
('e2233b75-986f-48b8-b14b-cb679f07a87b','次劉秀野蔬食十三詩韻 𬊳菜','朱熹','宋','宋诗','song-poetry','','[]','小草有貞性，託根寒澗幽。',24,'全唐诗/poet.song.147000.json','["小草有貞性，託根寒澗幽。", "懦夫曾一嘬，感憤不能休。"]'),
('c916f4c5-5ea5-4643-8fcb-865a9ac56f5e','次劉秀野蔬食十三詩韻 木耳','朱熹','宋','宋诗','song-poetry','','[]','蔬腸久自安，異味非所𧩫。',24,'全唐诗/poet.song.147000.json','["蔬腸久自安，異味非所𧩫。", "樹耳黑垂聃，登盤今亦乍。"]'),
('079fa084-79bf-464d-a59a-2dc16d34fee0','次劉秀野蔬食十三詩韻 蘿蔔','朱熹','宋','宋诗','song-poetry','','[]','紛敷剪翠叢，津潤擢玉本。',24,'全唐诗/poet.song.147000.json','["紛敷剪翠叢，津潤擢玉本。", "寂寞病文園，吟餘得深齦。"]'),
('fdc3a6e1-e461-4db2-837e-5a865e6a3ea2','次劉秀野蔬食十三詩韻 芋魁','朱熹','宋','宋诗','song-poetry','','[]','沃野無凶年，正得蹲鴟力。',24,'全唐诗/poet.song.147000.json','["沃野無凶年，正得蹲鴟力。", "區種萬葉清，深煨奉朝食。"]'),
('544af531-c08d-4e38-a136-b6d58c042b6c','次劉秀野蔬食十三詩韻 筍脯','朱熹','宋','宋诗','song-poetry','','[]','南山春笋多，萬里行枯腊。',24,'全唐诗/poet.song.147000.json','["南山春笋多，萬里行枯腊。", "不落盤餐中，今知綠如簀。"]'),
('c88f1e71-5287-495f-a629-3b1f9536a293','次劉秀野蔬食十三詩韻 豆腐','朱熹','宋','宋诗','song-poetry','','[]','種豆豆苗稀，力竭心已腐。',24,'全唐诗/poet.song.147000.json','["種豆豆苗稀，力竭心已腐。", "早知淮王術，安坐獲泉布。"]'),
('be41e895-13dc-4942-ac1c-e8f388900c38','次劉秀野蔬食十三詩韻 白蕈','朱熹','宋','宋诗','song-poetry','','[]','聞說閬風苑，瓊田産玉芝。',24,'全唐诗/poet.song.147000.json','["聞說閬風苑，瓊田産玉芝。", "不收雲表露，烹瀹詎相宜。"]'),
('131a6dde-a37b-4789-bdea-de8d05e22bf1','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 秀野','朱熹','宋','宋诗','song-poetry','','[]','爲憐蘅芷滿芳洲，特地臨江賦遠遊。',64,'全唐诗/poet.song.147000.json','["爲憐蘅芷滿芳洲，特地臨江賦遠遊。", "十畝何妨自春色，萬緣從此付東流。", "靜看朝市真兒戲，須信田園是老謀。", "出處知公有餘裕，未應辛苦謝靈丘。"]'),
('c371daa8-015d-471b-adfd-7c613159d337','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 積芳圃','朱熹','宋','宋诗','song-poetry','','[]','樂事從茲不易涯，朱門還似野人家。',64,'全唐诗/poet.song.147000.json','["樂事從茲不易涯，朱門還似野人家。", "行看靚艷須携酒，坐對清陰只煮茶。", "曉起蒼凉承墜露，晚來光景亂蒸霞。", "平生結習今餘幾，試數毗那襋上花。"]'),
('a2047bbc-ba52-442b-88a7-f0d24ca63888','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 家山堂','朱熹','宋','宋诗','song-poetry','','[]','負米歸來手自舂，豈知門外有晴峰。',64,'全唐诗/poet.song.147000.json','["負米歸來手自舂，豈知門外有晴峰。", "羨公竟日塵氛遠，拄頰看山幽興濃。", "心鏡懸知不同調，詩壇那敢少爭鋒。", "空餘遠嶽尋師意，箇裏何妨爲指蹤。"]'),
('3ea71c5a-8f3a-4aca-8d7d-7cbb216f307b','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 拙政堂','朱熹','宋','宋诗','song-poetry','','[]','驥足寧同曳尾龜，青山終是費心期。',64,'全唐诗/poet.song.147000.json','["驥足寧同曳尾龜，青山終是費心期。", "陶公歸去有餘樂，潘令閑居不足追。", "自笑十連非所慕，未應三徑苦無資。", "明朝謾擁朱輪去，猿鶴咨嗟政爾爲。"]'),
('9fd136fc-855f-4d24-961b-a5bfac5c4b7f','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 香界','朱熹','宋','宋诗','song-poetry','','[]','幽興年來莫與同，滋蘭聊欲汎光風。',64,'全唐诗/poet.song.147000.json','["幽興年來莫與同，滋蘭聊欲汎光風。", "真成佛國香雲界，不數淮山桂樹叢。", "花氣無邊曛欲醉，靈氛一點靜還通。", "何須楚客紉秋佩，坐卧經行住此中。"]'),
('fdae95c4-dae4-40fe-8272-7fb4e56b610d','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 春谷','朱熹','宋','宋诗','song-poetry','','[]','武夷高處是蓬萊，采得靈根手自栽。',64,'全唐诗/poet.song.147000.json','["武夷高處是蓬萊，采得靈根手自栽。", "地僻芳菲鎮長在，谷寒蜂蝶未全來。", "紅裳似欲留人醉，錦障何妨爲客開。", "飲罷醒心何處所，遠山重疊翠成堆。"]'),
('20c3bb21-ab54-4d9e-84f9-53c2f7eab9e8','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 舫齋','朱熹','宋','宋诗','song-poetry','','[]','扁舟容與小房櫳，摇颺簾旌蜀錦紅。',64,'全唐诗/poet.song.147000.json','["扁舟容與小房櫳，摇颺簾旌蜀錦紅。", "兩岸蒹葭秋色裏，一川煙浪夕陽中。", "不愁灧澦雙蓬鬢，未怯江湖萬里風。", "築室水中聊爾爾，何須極浦望朱宮。"]'),
('11fe5f37-0f58-42ae-880c-bd991d063826','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 藥圃','朱熹','宋','宋诗','song-poetry','','[]','種藥春畦有近功，不辭耘耔謾勞躬。',64,'全唐诗/poet.song.147000.json','["種藥春畦有近功，不辭耘耔謾勞躬。", "漸看杞菊充庖下，即見芝英入籠中。", "病去自知非往日，身輕何必御泠風。", "出門會有兒童笑，不是當年植杖翁。"]'),
('a4cba5e0-5d4f-4f83-92f1-e893e05baf15','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 山人方丈','朱熹','宋','宋诗','song-poetry','','[]','方丈翛然屋數椽，檻前流水自清漣。',64,'全唐诗/poet.song.147000.json','["方丈翛然屋數椽，檻前流水自清漣。", "蒲團竹几通宵坐，掃地焚香白晝眠。", "地窄不容揮麈客，室空那有散花天。", "箇中有句無人薦，不是諸方五味禪。"]'),
('878b46a4-2675-4dc6-a6dd-203fbc4105ba','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 龜峰樓','朱熹','宋','宋诗','song-poetry','','[]','楊柳東邊桂樹西，小樓晴眺極霏微。',64,'全唐诗/poet.song.147000.json','["楊柳東邊桂樹西，小樓晴眺極霏微。", "山川政爾供凝目，塵土何妨略振衣。", "俯瞰桑田悲物化，閑披蘂笈洞玄機。", "却疑欄外連穹石，似厭支牀去不歸。"]'),
('4dd60235-9964-40fc-9456-4365210847f9','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 月波臺','朱熹','宋','宋诗','song-poetry','','[]','潺潺流水注回塘，中作平臺受晚凉。',64,'全唐诗/poet.song.147000.json','["潺潺流水注回塘，中作平臺受晚凉。", "四面不通車馬跡，一尊聊飲芰荷香。", "韓公無復吟花島，楚客何勞賦葯房。", "少待須臾更清絕，月華零露洗匡牀。"]'),
('9c99b2ac-8c49-49de-83d8-a9831858c537','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 挽蔬園','朱熹','宋','宋诗','song-poetry','','[]','未覺閑來歲月頻，荷鉏方喜土膏勻。',64,'全唐诗/poet.song.147000.json','["未覺閑來歲月頻，荷鉏方喜土膏勻。", "連畦已放瑶簪露，覆地行看玉本新。", "小摘登盤先餉客，晚炊當肉更宜人。", "却憐寂寞公儀子，拔盡園蔬不歎貧。"]'),
('ecdfed1c-44a4-4158-9c9a-5cb8ebfa6400','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 秋香徑','朱熹','宋','宋诗','song-poetry','','[]','門外黄塵沒九逵，坊中叢桂長樛枝。',64,'全唐诗/poet.song.147000.json','["門外黄塵沒九逵，坊中叢桂長樛枝。", "三秋冷蕊從開落，終歲清陰不改移。", "幽逕祇愁空翠滴，濃香一任晚風吹。", "攀援却恨王孫遠，惆悵千林□□時。"]'),
('ff929336-77fe-4498-a408-a6e402b7cb54','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 曲池軒','朱熹','宋','宋诗','song-poetry','','[]','去年種竹長新篁，今歲穿渠過野塘。',64,'全唐诗/poet.song.147000.json','["去年種竹長新篁，今歲穿渠過野塘。", "自喜軒窗無俗韻，亦知草木有真香。", "林間急雨生秋思，水面微風度晚凉。", "却厭端居苦無事，凭欄閑理釣絲長。"]'),
('120f5ab6-f728-46d9-8e97-3afcb4ddffdc','伏讀秀野劉丈閒居十五詠謹次高韻率易拜呈伏乞痛加繩削是所願望 前村□','朱熹','宋','宋诗','song-poetry','','[]','玉立寒烟寂寞濱，仙姿瀟灑凈無塵。',64,'全唐诗/poet.song.147000.json','["玉立寒烟寂寞濱，仙姿瀟灑凈無塵。", "千林摇落今如許，一樹橫斜獨可人。", "真與雪霜娛晚景，任從桃柳殿殘春。", "綠陰青子明年事，衆口驚嗟鼎味新。"]'),
('644d6e16-b427-4b4b-a6e3-5642edf1b362','秀野劉丈寄示南昌諸詩和此兩篇  其一','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6ed5\u738b\u9601"]','滕王閣下水初生，聞道登臨復快晴。',64,'全唐诗/poet.song.147000.json','["滕王閣下水初生，聞道登臨復快晴。", "帝子詎知陳迹在，長江肯趁曲池平。", "山楹雨罷珠簾捲，簷鐸風驚玉佩鳴。", "滿眼悲凉今古恨，人生辛苦竟何成。"]'),
('1ab70074-8829-4f9c-9635-850a5178a7df','秀野劉丈寄示南昌諸詩和此兩篇  其二','朱熹','宋','宋诗','song-poetry','','[]','知向潮邊弄碧漪，欄干三撫漾晴輝。',64,'全唐诗/poet.song.147000.json','["知向潮邊弄碧漪，欄干三撫漾晴輝。", "流傳妙語驚離闊，想像清游欲奮飛。", "公去不應停驛騎，我來直欲掛朝衣。", "南州高士何由見，且看新荷出水稀。"]'),
('499f892c-d9ed-48a1-941c-38cc02c2052b','次秀野韻五首  其一','朱熹','宋','宋诗','song-poetry','','[]','史君簾閣對脩筠，起看名園雨後春。',64,'全唐诗/poet.song.147000.json','["史君簾閣對脩筠，起看名園雨後春。", "便賦新詩留野客，更傾芳酒酹花神。", "未酬管樂平生志，且作羲黄向上人。", "祇恐功名相迫逐，不容老子卧漳濱。"]'),
('b37bd69f-c321-4b2d-b1c6-7e95f452e976','次秀野韻五首  其二','朱熹','宋','宋诗','song-poetry','','[]','滿園紅紫已爭新，百囀幽禽亦喚人。',64,'全唐诗/poet.song.147000.json','["滿園紅紫已爭新，百囀幽禽亦喚人。", "蠟屐未妨泥步穩，珍叢終恨雨來頻。", "卧看曉色忻初霽，起約良游醉好春。", "却笑當年金谷燕，相隨僕僕望車塵。"]'),
('9ce3b20d-cf98-4d35-bea8-817d9792d6e7','次秀野韻五首  其三','朱熹','宋','宋诗','song-poetry','','[]','惆悵春餘幾日光，從今風雨莫顛狂。',64,'全唐诗/poet.song.147000.json','["惆悵春餘幾日光，從今風雨莫顛狂。", "急呼我輩穿花去，未覺詩情與道妨。", "蘿带不須吟杜若，角弓聊復賦甘棠。", "淋浪坐客休辭醉，飲罷晞身向九陽。"]'),
('4017e363-ef91-4204-97e2-06ce5ba77388','次秀野韻五首  其四','朱熹','宋','宋诗','song-poetry','','[]','知君久矣厭喧卑，造物尊前喚小兒。',64,'全唐诗/poet.song.147000.json','["知君久矣厭喧卑，造物尊前喚小兒。", "一釂未應峨側弁，十分聊爾快翻巵。", "治中寂寂凝塵日，令尹憂勞退食時。", "正好相尋發孤笑，莫教牢落負心期。"]'),
('21ac86b3-6281-4bfe-9490-3cd58bcd089f','次秀野韻五首  其五','朱熹','宋','宋诗','song-poetry','','[]','當年共剪北山萊，脩竹成陰手自栽。',64,'全唐诗/poet.song.147000.json','["當年共剪北山萊，脩竹成陰手自栽。", "書卷莫教春色老，柴荆肯爲俗人開。", "公能顧我傳新句，我欲留公撥舊醅。", "悵望南園芳樹底，明年應放小車來。"]'),
('c1e94228-fd37-45aa-9442-e4cec086c704','留秀野劉丈二首  其一','朱熹','宋','宋诗','song-poetry','','[]','好雨當春過一犁，我公遠憶故園西。',64,'全唐诗/poet.song.147000.json','["好雨當春過一犁，我公遠憶故園西。", "孤篷穩轉清灘急，十里行穿綠樹齊。", "路熟已欣經霧市，身輕未怕躡雲梯。", "諸孫剩欲留公住，細和新詩丐指迷。"]'),
('8f8aa116-f4ce-4172-a7e3-3987d5dee6af','留秀野劉丈二首  其二','朱熹','宋','宋诗','song-poetry','','[]','一去屏山今幾春，歸來三逕但荒榛。',64,'全唐诗/poet.song.147000.json','["一去屏山今幾春，歸來三逕但荒榛。", "剪除便覺風煙好，徙倚還驚物色新。", "樓外千林遮去路，階前一水戀行塵。", "勸君更作留連計，同社追遊苦未頻。"]'),
('8df75359-473d-493a-9cc5-95ebd5a7d313','次秀野滄波館刈麥二詩  其一','朱熹','宋','宋诗','song-poetry','','[]','傳聞泛宅賀新成，破月衝煙取次撐。',64,'全唐诗/poet.song.147000.json','["傳聞泛宅賀新成，破月衝煙取次撐。", "鷁首斜飛寒浪急，篷窗側轉好山橫。", "知公興有江湖迥，顧我詩無玉雪清。", "欲跨船舷還未敢，幾時得伴鏡中行。"]'),
('6fd602dc-a98a-4226-a06f-09b2ffc2e1b2','次秀野滄波館刈麥二詩  其二','朱熹','宋','宋诗','song-poetry','','[]','貽牟夙昔但聲歌，今見郊園樂事多。',64,'全唐诗/poet.song.147000.json','["貽牟夙昔但聲歌，今見郊園樂事多。", "且喜甌窶符善禱，未須蘆菔顰妖娥。", "霞觴政自誇真一，香鉢何煩問畢羅。", "我欲賣刀來學稼，不知還許受廛麽。"]'),
('62aa1296-66a6-474c-8a24-375fdeb90339','次秀野躬耕桑陌舊園之韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','郊園旱久只多蹊，昨夜欣沾雨一犁。',64,'全唐诗/poet.song.147000.json','["郊園旱久只多蹊，昨夜欣沾雨一犁。", "已辦青鞋隨老圃，便驅黄犢過深溪。", "農談剩喜鄉隣近，饁具仍教婦子携。", "指點竹寒沙碧處，不知何似錦城西。"]'),
('84ef810b-daf4-471e-b788-6a215a3f81f5','次秀野躬耕桑陌舊園之韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','丈人高致邈難干，雲夢何如胸次寬。',64,'全唐诗/poet.song.147000.json','["丈人高致邈難干，雲夢何如胸次寬。", "老去未妨詩律在，人來只怕酒盃乾。", "故開麥隴供家釀，更有蘭章付客看。", "下走才慳慙囑和，願公物色稍留殘。"]'),
('d84d664f-f839-4684-a0d9-86c9a943bdfd','又和秀野二首  其一','朱熹','宋','宋诗','song-poetry','','[]','愁陰一夜轉和風，曉看花枝露彩濃。',64,'全唐诗/poet.song.147000.json','["愁陰一夜轉和風，曉看花枝露彩濃。", "覓句休教長閉戶，出門聊得試扶筇。", "物華始信如詩好，春色方知似酒濃。", "多謝隣翁笑相迓，爲言晴暖更過從。"]'),
('af33da51-d67a-4ab7-9803-23385659a219','又和秀野二首  其二','朱熹','宋','宋诗','song-poetry','','[]','江臯晴日麗芳華，翠竹踈踈映白沙。',64,'全唐诗/poet.song.147000.json','["江臯晴日麗芳華，翠竹踈踈映白沙。", "路轉忽逢沽酒客，眼明惟見滿園花。", "望中景助詩人趣，物外春歸釋子家。", "向晚却尋芳草逕，夕陽流水遶村斜。"]'),
('7cb10bb0-e038-42e0-810b-4ea5a00c7743','次秀野詠雪韻三首  其一','朱熹','宋','宋诗','song-poetry','','[]','閉門高卧客來稀，起看天花滿院飛。',64,'全唐诗/poet.song.147000.json','["閉門高卧客來稀，起看天花滿院飛。", "地迥杉篁增勝概，庭虛鳥雀噪空饑。", "酒腸凍澀成新恨，病骨侵凌減舊肥。", "頼有袁生清興在，忍寒應未泣牛衣。"]'),
('c877c09f-f9d2-4b31-949d-37255f49565b','次秀野詠雪韻三首  其二','朱熹','宋','宋诗','song-poetry','','[]','一夜同雲匝四山，曉來千里共漫漫。',64,'全唐诗/poet.song.147000.json','["一夜同雲匝四山，曉來千里共漫漫。", "不應琪樹猶含凍，翻笑楊花許耐寒。", "乘興正須披鶴氅，瀹甘猶喜破龍團。", "無端酒思催吟筆，却恐長鯨吸海乾。"]'),
('326bbb4f-1504-4ec5-a325-5b863d7f3d1c','次秀野詠雪韻三首  其三','朱熹','宋','宋诗','song-poetry','','[]','開門驚怪雪交加，亂落橫飛詎有涯。',64,'全唐诗/poet.song.147000.json','["開門驚怪雪交加，亂落橫飛詎有涯。", "密竹不妨呈勁節，早梅何處覓殘花。", "山陰客子須乘興，洛下先生想卧家。", "病廢盃觴寒至骨，哦詩無復更豪誇。"]'),
('a7b1da05-3a72-4103-a0ea-52b793999c03','次韻雪後書事二首  其一','朱熹','宋','宋诗','song-poetry','','[]','晴煙裊裊弄晨炊，雪屋流澌未覺遲。',64,'全唐诗/poet.song.147000.json','["晴煙裊裊弄晨炊，雪屋流澌未覺遲。", "擬挈凍醪追勝踐，聊穿蠟屐過踈籬。", "掃開折竹仍三逕，認得殘梅祇數枝。", "不耐歲寒心事苦，滔滔欲說定從誰。"]'),
('e6e5275e-e908-40f5-9eca-d67269c04151','次韻雪後書事二首  其二','朱熹','宋','宋诗','song-poetry','','[]','未覺春光到柳條，誰教飛絮倚風摇。',64,'全唐诗/poet.song.147000.json','["未覺春光到柳條，誰教飛絮倚風摇。", "眼驚銀色迷千界，夢斷彤庭散百寮。", "梅塢任從長笛弄，竹窗閑把短檠挑。", "何人剝啄傳清唱，更喜殘年樂事饒。"]'),
('a3158290-0d02-4f7e-b2f5-f07aebcf0c70','次韻秀野早梅','朱熹','宋','宋诗','song-poetry','','[]','可愛紅芳愛素芳，多情珍重老劉郎。',64,'全唐诗/poet.song.147000.json','["可愛紅芳愛素芳，多情珍重老劉郎。", "踈英的皪尊中影，微月黄昏句裏香。", "胸次自憐真玉雪，人間何處有冰霜。", "巡簷說盡心期事，肯醉佳人錦瑟傍。"]'),
('61bb1109-6644-474c-842a-fb9bc54e8894','次秀野極目亭韻  其一','朱熹','宋','宋诗','song-poetry','','[]','偶向新亭一破顔，高情直寄有無間。',64,'全唐诗/poet.song.147000.json','["偶向新亭一破顔，高情直寄有無間。", "地偏已隔東西路，天闊長圍遠近山。", "浩蕩只愁春霧合，輪囷却喜暮雲還。", "不堪景物撩人甚，倒盡詩囊未許慳。"]'),
('9bfc6bd5-bfd8-430b-9cb6-1962395d5c9e','次秀野極目亭韻  其二','朱熹','宋','宋诗','song-poetry','','[]','坐看山花落幔顔，不知身在翠雲間。',64,'全唐诗/poet.song.147000.json','["坐看山花落幔顔，不知身在翠雲間。", "食寒到處雨復雨，客裏歸來山又山。", "□□孤燈閑□□，無心棲鳥暮忘還。", "世情分逐流年去，只有詩情老更慳。"]'),
('6ac38d5a-1ad8-4ad0-b545-66a335ef954b','次秀野春晴山行紀物之句','朱熹','宋','宋诗','song-poetry','','[]','祇憑詩律作生涯，到處山林總是家。',64,'全唐诗/poet.song.147000.json','["祇憑詩律作生涯，到處山林總是家。", "便與清尊卧芳草，不妨皂蓋拂殘花。", "側聞溫詔詢耆艾，好趁春風入殿衙。", "回首能忘舊猿鶴，一篇聊爾記年華。"]'),
('619ce96e-55c7-4715-8033-00a1596e87a0','再用韻題翠壁','朱熹','宋','宋诗','song-poetry','','[]','孤亭一目盡天涯，俯瞰烟村八九家。',64,'全唐诗/poet.song.147000.json','["孤亭一目盡天涯，俯瞰烟村八九家。", "翠壁何年懸布水，綠陰經雨墮危花。", "杖藜徙倚凝春望，覓句淹留到晚衙。", "珍重詩翁莫相惱，枯腸攪斷鬢絲華。"]'),
('ce6a472a-1f05-4bdd-b987-9387ed565960','次亭字韻詩呈秀野丈兼簡王宰三首  其一','朱熹','宋','宋诗','song-poetry','','[]','不駕朝車叩九扃，獨携靈壽向新亭。',64,'全唐诗/poet.song.147000.json','["不駕朝車叩九扃，獨携靈壽向新亭。", "人言洞裏春長在，自慶樽前老復丁。", "魚樂波閑詩欲就，鴻冥天闊酒初醒。", "晚來却向南堂坐，珍重家山數點青。"]'),
('c897ec78-e393-4879-8d3c-52bf33e9b336','次亭字韻詩呈秀野丈兼簡王宰三首  其二','朱熹','宋','宋诗','song-poetry','','[]','吏散庭空晝掩扃，行春只到柳邊亭。',64,'全唐诗/poet.song.147000.json','["吏散庭空晝掩扃，行春只到柳邊亭。", "唱酬共喜摛鴻藻，來往何勞笑白丁。", "一笑歌呼從自醉，幾年燠暍爲誰醒。", "定知細札褒揚後，名入麟臺汗簡青。"]'),
('48e22700-97f7-451c-bc73-f7425a59b751','次亭字韻詩呈秀野丈兼簡王宰三首  其三','朱熹','宋','宋诗','song-poetry','','[]','幾年寂寞掩柴扃，抱膝長吟竹下亭。',64,'全唐诗/poet.song.147000.json','["幾年寂寞掩柴扃，抱膝長吟竹下亭。", "不向參同論納甲，且將耘耔付添丁。", "思玄賦罷驚遥舉，止酒詩成恨獨醒。", "却笑春風兩蓬鬢，飄蕭無復舊時青。"]'),
('691c3e1d-eb36-4e36-895a-d0bf716f373d','次山行佳句呈秀野丈三首  其一','朱熹','宋','宋诗','song-poetry','','[]','幾日春陰鎖翠巖，忽驚飛蓋度晴嵐。',64,'全唐诗/poet.song.147000.json','["幾日春陰鎖翠巖，忽驚飛蓋度晴嵐。", "身輕似起煙霞痼，意適寧論祿位貪。", "句法舊超常語六，年華今富達尊三。", "從容笑語無餘事，興在南山更向南。"]'),
('f8671eda-0411-4f98-850e-036e2e62175a','次山行佳句呈秀野丈三首  其二','朱熹','宋','宋诗','song-poetry','','[]','几杖歸來覓故巖，眼中猶記舊煙嵐。',64,'全唐诗/poet.song.147000.json','["几杖歸來覓故巖，眼中猶記舊煙嵐。", "詩情自昔元無敵，世味而今更不貪。", "默數流年欣望八，閑尋隠訣話存三。", "小生自愧衰頹早，箇裏憑公爲指南。"]'),
('c49327c0-db07-4449-8959-48c9be9467f4','次山行佳句呈秀野丈三首  其三','朱熹','宋','宋诗','song-poetry','','[]','曈曈朝日出高巖，簌簌征衣曳曉嵐。',64,'全唐诗/poet.song.147000.json','["曈曈朝日出高巖，簌簌征衣曳曉嵐。", "□□向來孤舊意，林泉老去覺真貪。", "凄凉烟火一百五，零落交遊十二三。", "歎□□□□世事，卧吹橫笛過溪南。"]'),
('1ce71838-e797-4b42-9ad2-283ff0117448','次秀野泛滄波館至赤石觀刈早稻韻','朱熹','宋','宋诗','song-poetry','','[]','綠雲黄半武夷鄉，碧水縈紆一带長。',64,'全唐诗/poet.song.147000.json','["綠雲黄半武夷鄉，碧水縈紆一带長。", "聞道放船飛皂蓋，定知行酒載紅裳。", "櫂謳如賀豐年信，樂飲閑酬此日凉。", "禾忝誰言不陽豔，晚炊流詠有餘香。"]'),
('97d77453-c108-467c-9f71-c14908c42d25','次秀野韻題卧雲菴','朱熹','宋','宋诗','song-poetry','','[]','君家丘壑本圓成，何意尋荒入翠屏。',64,'全唐诗/poet.song.147000.json','["君家丘壑本圓成，何意尋荒入翠屏。", "爲愛晴雲薦孤枕，故將閑日付新亭。", "夢魂寂寂衣裳冷，心事悠悠簡策青。", "更把枯桐寫奇趣，鵾絃寒夜獨泠泠。"]'),
('b07a577f-042d-4033-aa2a-ab44f8823eea','奉和秀野見留之句','朱熹','宋','宋诗','song-poetry','','[]','閑卧秋山塵事稀，西風催喚出巖扉。',64,'全唐诗/poet.song.147000.json','["閑卧秋山塵事稀，西風催喚出巖扉。", "來看甲第清泉好，更喜仙翁丹頰肥。", "捫虱坐談端未厭，連環入夢却思歸。", "明朝振策千峯頂，滿袖瓊琚背夕暉。"]'),
('bd34bcc1-e426-46c1-b646-8f2b4ebac261','次秀野種粟韻','朱熹','宋','宋诗','song-poetry','','[]','阿香一笑走豐隆，雨遍平疇萬頃中。',64,'全唐诗/poet.song.147000.json','["阿香一笑走豐隆，雨遍平疇萬頃中。", "舊喜樊遲知學圃，今看許子快論功。", "遥憐鬰鬰翻秋隴，預想垂垂弄晚風。", "珍重詩翁且彊健，東阡南陌興無窮。"]'),
('ce880ad7-cef3-4c0b-aed5-6a1303d7809f','和秀野蘄簟之句','朱熹','宋','宋诗','song-poetry','','[]','史君兩鬢尚青青，學道仍拋後院笙。',64,'全唐诗/poet.song.147000.json','["史君兩鬢尚青青，學道仍拋後院笙。", "溽暑快眠知簟好，晚凉徐覺喜詩成。", "人從蘄水當年寄，詩比韓公此日清。", "坐對更深誰是伴，唯應闕月共長庚。"]'),
('81cd6b0c-8a6a-4e5f-922c-2d4dfb9a2345','次韻寄題芙蕖館三首  其一','朱熹','宋','宋诗','song-poetry','','[]','亂山叢裏有江鄉，華館清波引興長。',64,'全唐诗/poet.song.147000.json','["亂山叢裏有江鄉，華館清波引興長。", "正喜白鷗輕易狎，忽驚紅妓儼分行。", "臨流更好揮椽筆，俯檻何妨接羽觴。", "共說仙翁閑日月，不因春草夢池塘。"]'),
('02d8021d-c9de-48d6-8fed-80b0ce191c4b','次韻寄題芙蕖館三首  其二','朱熹','宋','宋诗','song-poetry','','[]','幻成飛閣笑談餘，便有新荷水面鋪。',64,'全唐诗/poet.song.147000.json','["幻成飛閣笑談餘，便有新荷水面鋪。", "指點清波浮菡萏，驚呼紅影碎陬隅。", "且將伴侶同盃酒，不用君王予鏡湖。", "多少故交臺閣上，問渠落拓更能無。"]'),
('19c947a3-119e-4e69-afb9-da97032c2b69','次韻寄題芙蕖館三首  其三','朱熹','宋','宋诗','song-poetry','','[]','不須艇子棹歌來，且看芙蓉面面開。',64,'全唐诗/poet.song.147000.json','["不須艇子棹歌來，且看芙蓉面面開。", "卷裏有詩都錦繡，席間無地可塵埃。", "風清月白琴三弄，綠暗紅深酒一盃。", "明日仲宣樓上去，越吟應是首頻回。"]'),
('18f10446-005b-4e4d-8b30-d3a0bac03e78','次韻雪後書事二首  其一','朱熹','宋','宋诗','song-poetry','','[]','惆悵江頭幾樹梅，杖藜行遶去還來。',64,'全唐诗/poet.song.147000.json','["惆悵江頭幾樹梅，杖藜行遶去還來。", "前時雪壓無尋處，昨夜月明依舊開。", "折寄遥憐人似玉，相思應恨劫成灰。", "沈吟日落寒鴉起，却望柴荆獨自回。"]'),
('dcc145bf-66b7-4b9b-b320-f6cba92332f5','次韻雪後書事二首  其二','朱熹','宋','宋诗','song-poetry','','[]','滿山殘雪對虛堂，想似當年輞口莊。',64,'全唐诗/poet.song.147000.json','["滿山殘雪對虛堂，想似當年輞口莊。", "門掩不須垂鐵鎖，客來聊復共藜牀。", "故人聞道歌圍暖，妙語空傳醉墨香。", "莫爲姬姜厭憔悴，論文把酒話偏長。"]'),
('cce32a16-6aeb-4612-ab2e-7d18b2ca52c2','和秀野韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','聞道無餘事，翛然百慮空。',48,'全唐诗/poet.song.147000.json','["聞道無餘事，翛然百慮空。", "何心分彼我，無地著窮通。", "昨日青衿子，明朝白髮翁。", "天機元自爾，不是故匆匆。"]'),
('230709ce-8344-4fe3-8379-ebf09e5f24c1','和秀野韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','久矣安岑寂，山棲恨不深。',48,'全唐诗/poet.song.147000.json','["久矣安岑寂，山棲恨不深。", "謾將門自掩，那有客相尋。", "炙背迎朝景，加趺度夕陰。", "感君傳秀句，把卷獨呻吟。"]'),
('3db2410c-f725-4a96-89e9-466b1fea7439','次秀野暑中二首  其一','朱熹','宋','宋诗','song-poetry','','[]','劇暑悲難度，清秋喜却回。',48,'全唐诗/poet.song.147000.json','["劇暑悲難度，清秋喜却回。", "病隨庚伏盡，尊向晚凉開。", "臨水看雲去，鈎簾待月來。", "勝遊驚昨夢，曾上鬰蕭臺。"]'),
('1af22c1c-a018-4732-a9d3-a4cc20c0fdd6','次秀野暑中二首  其二','朱熹','宋','宋诗','song-poetry','','[]','絕境人難到，唯堪樂此身。',48,'全唐诗/poet.song.147000.json','["絕境人難到，唯堪樂此身。", "泉吟青玉峽，風度白綸巾。", "獨往寧無意，長閑未有因。", "雲山天賜履，吾道豈全貧。"]'),
('fdfd4931-5386-4ec9-a19f-837b2a121516','次秀野雜詩韻 葺居二首 其一','朱熹','宋','宋诗','song-poetry','','[]','丈人高卧碧江頭，門掩西風萬木秋。',64,'全唐诗/poet.song.147000.json','["丈人高卧碧江頭，門掩西風萬木秋。", "重喜青山還遶屋，却嫌黄葉漸平溝。", "開軒且放浮嵐入，决水徐通廢圃流。", "便覺園林頓蕭爽，不妨隨境味玄幽。"]'),
('d043545e-30e8-4cc1-bb3e-27af079f87cf','次秀野雜詩韻 葺居二首 其二','朱熹','宋','宋诗','song-poetry','','[]','向來鞅掌元非病，此日徜徉詎有妨。',64,'全唐诗/poet.song.147000.json','["向來鞅掌元非病，此日徜徉詎有妨。", "自喜登臺閑瘦竹，人驚步屧響空廊。", "高齋雨過新山色，曲沼風來舊水光。", "千里壯心殊未已，不應踈懶興能長。"]'),
('ddb9861c-ebcb-417f-8f8b-49f58bceed4e','次秀野雜詩韻 刻漏','朱熹','宋','宋诗','song-poetry','','[]','無疑莫詣君平肆，任運休尋季主家。',64,'全唐诗/poet.song.147000.json','["無疑莫詣君平肆，任運休尋季主家。", "謾設銅壺候尺咫，閑參玉表驗分差。", "不妨啟處知時節，那更榮枯紀歲華。", "却羨昇平好官府，日高三丈放朝衙。"]'),
('b21eceba-097a-4f5e-909e-2b6b7c7d61ea','次秀野雜詩韻 栗熟','朱熹','宋','宋诗','song-poetry','','[]','樹雜椅桐繼國風，莫教林下長蒿蓬。',64,'全唐诗/poet.song.148000.json','["樹雜椅桐繼國風，莫教林下長蒿蓬。", "共期秋實充腸飽，不羨春華轉眼空。", "病起數升傳藥錄，晨興三嚥學仙翁。", "櫻桃浪得銀絲薦，一笑纔堪發面紅。"]'),
('5f4a780d-0fe5-4bfd-8050-8275108fae3d','次秀野雜詩韻 山藥','朱熹','宋','宋诗','song-poetry','','[]','怪來朽壤耀瓊英，小斸傾筐可代耕。',64,'全唐诗/poet.song.148000.json','["怪來朽壤耀瓊英，小斸傾筐可代耕。", "豢豹於人儘無分，蹲鴟從此不須生。", "雪鑱但使身長健，石鼎何妨手自烹。", "欲賦玉延無好語，羞論蜂蜜與羊羹。"]'),
('62e72f21-76cb-4ece-a19d-b5f9aa2ea2e9','次秀野雜詩韻 食梨','朱熹','宋','宋诗','song-poetry','','[]','珍實渾疑露結成，香葩况是雪儲精。',64,'全唐诗/poet.song.148000.json','["珍實渾疑露結成，香葩况是雪儲精。", "乍驚磊落堆盤出，旋剖輕盈照骨明。", "盧橘謾勞誇夏熟，柘漿未許析朝酲。", "啖餘更檢桐君錄，快果知非浪得名。"]'),
('e78d5ed2-1ba9-405f-b434-cb3a68efa0e5','次秀野雜詩韻 導引','朱熹','宋','宋诗','song-poetry','','[]','聞說牛刀久不更，閑中應接羨門生。',64,'全唐诗/poet.song.148000.json','["聞說牛刀久不更，閑中應接羨門生。", "向來已悟藏千界，今日何勞倒五行。", "按蹻有時聊戲劇，居心無物轉虛明。", "舉觴試問同亭侶，九轉工夫早晚成。"]'),
('140e80fd-bee5-4afe-b425-1cecc0c442d6','次秀野雜詩韻 假山焚香作煙雲掬水爲瀑布二首 其一','朱熹','宋','宋诗','song-poetry','','[]','平地俄驚紫翠堆，便應題作小飛來。',64,'全唐诗/poet.song.148000.json','["平地俄驚紫翠堆，便應題作小飛來。", "爐熏細度巖姿出，綫溜遥分壁色開。", "獨往但憑南郭几，遠游休剪北山萊。", "人言造化無私力，珍重仙翁挽得回。"]'),
('e21ffeec-0bfe-4b2d-8d37-468b939b9abe','次秀野雜詩韻 假山焚香作煙雲掬水爲瀑布二首 其二','朱熹','宋','宋诗','song-poetry','','[]','一簣工夫莫坐談，便教庭際湧千巖。',64,'全唐诗/poet.song.148000.json','["一簣工夫莫坐談，便教庭際湧千巖。", "眼中水石今成趣，物外烟霞舊所耽。", "泉細寒聲生夜壑，香銷暝靄變晴嵐。", "兒童也識幽棲地，共指南山更近南。"]'),
('3b363117-ff04-42cf-ab1b-b5067bcd20ce','次秀野雜詩韻 家釀二首 其一','朱熹','宋','宋诗','song-poetry','','[]','銍艾無中熟，歡謠闕屢豐。',48,'全唐诗/poet.song.148000.json','["銍艾無中熟，歡謠闕屢豐。", "但知愁鬢白，那復醉顔紅。", "田舍寒如此，侯家事不同。", "新醅撥浮蟻，春滿夜堂中。"]'),
('824437a8-3717-4222-817e-677c97e658a6','次秀野雜詩韻 家釀二首 其二','朱熹','宋','宋诗','song-poetry','','[]','聞道兵厨盛，春泉響臈篘。',48,'全唐诗/poet.song.148000.json','["聞道兵厨盛，春泉響臈篘。", "定知盈榼送，不待扣門求。", "沆瀣應難比，茅柴祇自羞。", "病身從法縛，好客爲公留。"]'),
('768c21a4-58a4-4560-bbcd-dafbd9c61db1','次秀野雜詩韻 酒市二首 其一','朱熹','宋','宋诗','song-poetry','','[]','聞說崇安市，家家麴米春。',48,'全唐诗/poet.song.148000.json','["聞說崇安市，家家麴米春。", "樓頭邀上客，花底覓南隣。", "詎有當壚子，應無折券人。", "勸君渾莫問，一酌便還醇。"]'),
('1901fcca-63d1-49e6-b405-c3e6a99992ec','次秀野雜詩韻 酒市二首 其二','朱熹','宋','宋诗','song-poetry','','[]','麗藻摛雲錦，新章寫陟釐。',48,'全唐诗/poet.song.148000.json','["麗藻摛雲錦，新章寫陟釐。", "詩傳國風體，興發酒家旗。", "見說難中聖，遥知但啜醨。", "盤餐雜鮭菜，那有蟹螯持。"]'),
('47114c7d-33c9-4b17-a162-1847077dbebc','次秀野雜詩韻 黄雀鮓','朱熹','宋','宋诗','song-poetry','','[]','黄雀飛鳴處，交交異竊脂。',48,'全唐诗/poet.song.148000.json','["黄雀飛鳴處，交交異竊脂。", "稻粱求易足，羅網去何遲。", "味厚資偏嗜，謀踈闕自爲。", "韓彭尚葅醢，么麽爾誠宜。"]'),
('406eb326-8673-40fb-a20a-80d469cc4cac','次秀野雜詩韻 檳榔','朱熹','宋','宋诗','song-poetry','','[]','憶昔南遊日，初嘗面發紅。',48,'全唐诗/poet.song.148000.json','["憶昔南遊日，初嘗面發紅。", "藥囊知有用，茗盌詎能同。", "蠲疾收殊效，修真錄異功。", "三彭如不避，糜爛七非中。"]'),
('42a3b631-a12e-48fd-99b7-0a78132511d5','次秀野雜詩韻 又五絕卒章戲簡及之主簿 其一','朱熹','宋','宋诗','song-poetry','','[]','暮年藥裹關身切，此外翛然百不貪。',32,'全唐诗/poet.song.148000.json','["暮年藥裹關身切，此外翛然百不貪。", "薏苡載來緣下氣，檳榔收得爲祛痰。"]'),
('306f31d6-e464-424b-8eed-55e03a910cf4','次秀野雜詩韻 又五絕卒章戲簡及之主簿 其二','朱熹','宋','宋诗','song-poetry','','[]','錦文縷切勸加餐，蜃炭扶留共一柈。',32,'全唐诗/poet.song.148000.json','["錦文縷切勸加餐，蜃炭扶留共一柈。", "食罷有時求不得，英雄邂逅亦饑寒。"]'),
('9866c1ab-5a45-4791-a3d4-66f6d01108fc','次秀野雜詩韻 又五絕卒章戲簡及之主簿 其三','朱熹','宋','宋诗','song-poetry','','[]','向來試吏著南冠，馬甲蠔山得飫餐。',32,'全唐诗/poet.song.148000.json','["向來試吏著南冠，馬甲蠔山得飫餐。", "却藉芳辛來解穢，雞心磊落看堆柈。"]'),
('9b85f3eb-fc4b-4050-b68a-0b1a7bb29c40','次秀野雜詩韻 又五絕卒章戲簡及之主簿 其四','朱熹','宋','宋诗','song-poetry','','[]','箇中有味要君參，螫吻舂喉久不甘。',32,'全唐诗/poet.song.148000.json','["箇中有味要君參，螫吻舂喉久不甘。", "珍重人心亦如此，莫將寒苦換春酣。"]'),
('ea47152b-72da-4194-b79c-181dbe9ff419','次秀野雜詩韻 又五絕卒章戲簡及之主簿 其五','朱熹','宋','宋诗','song-poetry','','[]','高士沉迷簿領書，有時紅糝綴玄須。',32,'全唐诗/poet.song.148000.json','["高士沉迷簿領書，有時紅糝綴玄須。", "定知不著金柈貯，兒女心情本自無。"]'),
('66286721-6eed-479c-9d7c-154f1e0bf54e','答王無功在京思故園見鄉人問','朱熹','宋','宋诗','song-poetry','','[]','我從銅川來，見子上京客。',144,'全唐诗/poet.song.148000.json','["我從銅川來，見子上京客。", "問我故鄉事，慰子覊旅色。", "子問我所知，我對子應識。", "朋遊總彊𡏖，童稚各長成。", "華宗盛文史，連牆富池亭。", "獨子園最古，舊林間新坰。", "柳行隨堤勢，茅齋看地形。", "竹從去年移，梅是今年榮。", "渠水經夏響，石苔終歲青。", "院果早晚熟，林花先後明。", "語罷相歎息，浩然起深情。", "歸哉且五斗，餉子東臯耕。"]'),
('b5b8502f-4d40-4700-a3b9-9aa7f3e39505','送吳茂實','朱熹','宋','宋诗','song-poetry','','[]','朝市令人昏，山林使人傲。',28,'全唐诗/poet.song.148000.json','["朝市令人昏，山林使人傲。", "誰知昏傲兩俱非，但說山林是高蹈。"]'),
('5798ff29-b3a7-43a6-80f5-85cbbac8c73e','短句奉迎荆南幕府二首  其一','朱熹','宋','宋诗','song-poetry','','[]','雄藩荆楚地，自古國西門。',48,'全唐诗/poet.song.148000.json','["雄藩荆楚地，自古國西門。", "客有籌邊略，人知幕府尊。", "時平烽燧冷，事省笑談溫。", "宛洛何年向，奇功要一論。"]'),
('35545438-91a4-4abe-bf04-08c932519347','短句奉迎荆南幕府二首  其二','朱熹','宋','宋诗','song-poetry','','[]','軍府資長算，家山輟勝遊。',48,'全唐诗/poet.song.148000.json','["軍府資長算，家山輟勝遊。", "故人千里別，歸騎兩年秋。", "弔古寧忘恨，開尊且破愁。", "相思欲回首，但上曲江樓。"]'),
('7c221fb2-3b9e-464d-9698-5a30acbe6e36','趙君澤携琴載酒見訪分韻得琴字','朱熹','宋','宋诗','song-poetry','','[]','山城夜寥閴，虛堂杳沉沉。',72,'全唐诗/poet.song.148000.json','["山城夜寥閴，虛堂杳沉沉。", "王孫有高趣，挈榼來相尋。", "喜茲煩抱舒，未覺杯酒深。", "一爲塵外想，再撫丘中琴。", "餘音殷雷動，爽籟悲龍吟。", "寄謝箏笛耳，寧知山水音。"]'),
('4cba9302-2f1a-4842-9966-91af5397620e','寄題瀏陽李氏遺經閣二首  其一','朱熹','宋','宋诗','song-poetry','','[]','老翁無物與孫兒，樓上牙籤滿架垂。',32,'全唐诗/poet.song.148000.json','["老翁無物與孫兒，樓上牙籤滿架垂。", "更得南湖親囑付，歸來端的有餘師。"]'),
('3cb58072-f1b8-47d7-a586-5c7e9716d943','寄題瀏陽李氏遺經閣二首  其二','朱熹','宋','宋诗','song-poetry','','[]','讀書不見行間墨，始識當年教外心。',32,'全唐诗/poet.song.148000.json','["讀書不見行間墨，始識當年教外心。", "箇是儂家真寶藏，不應猶羨滿籝金。"]'),
('9f13948b-39e2-40b7-990e-6a07df1d2fc1','題鄭德輝悠然堂','朱熹','宋','宋诗','song-poetry','','[]','高人結屋亂雲邊，直面羣峰勢接連。',64,'全唐诗/poet.song.148000.json','["高人結屋亂雲邊，直面羣峰勢接連。", "車馬不來真避俗，簞瓢可樂便忘年。", "移筇綠幄成三徑，回首黄塵自一川。", "認得淵明千古意，南山經雨更蒼然。"]'),
('f35841c8-b951-482a-ae24-02ddea900ae9','長溪林一鶚秀才有落髮之願示及諸賢詩卷因題其後二首  其一','朱熹','宋','宋诗','song-poetry','','[]','聞說當機百念休，區區何更苦營求。',32,'全唐诗/poet.song.148000.json','["聞說當機百念休，區區何更苦營求。", "早知名教無窮樂，陋巷簞瓢也自由。"]'),
('985a42e8-6d12-4a81-8aaf-f25b2ab97128','長溪林一鶚秀才有落髮之願示及諸賢詩卷因題其後二首  其二','朱熹','宋','宋诗','song-poetry','','[]','貧里煩君特地過，金襴誰與換魚簑。',32,'全唐诗/poet.song.148000.json','["貧里煩君特地過，金襴誰與換魚簑。", "它年雲水經行遍，佛法元來本不多。"]'),
('550356db-b7dc-4a5c-abbd-d782a28121e2','送德和弟歸婺源二首  其一','朱熹','宋','宋诗','song-poetry','','[]','十舍辛勤觸熱來，琴書曾未拂塵埃。',32,'全唐诗/poet.song.148000.json','["十舍辛勤觸熱來，琴書曾未拂塵埃。", "秋風何事催歸興，步出閩山黄葉堆。"]'),
('a32d2c8f-770a-4484-8f93-3b64dbdbeaf2','送德和弟歸婺源二首  其二','朱熹','宋','宋诗','song-poetry','','[]','十年寂寞抱遺經，聖路悠悠不計程。',32,'全唐诗/poet.song.148000.json','["十年寂寞抱遺經，聖路悠悠不計程。", "悞子南來却空去，但將迂闊話平生。"]'),
('3d8c507d-5242-48dc-ad39-c5172d4ae52b','仲縝尊兄對策南宮相顧田舍輒賦小詩攀餞行李','朱熹','宋','宋诗','song-poetry','','[]','三徑荒凉獨掩門，故人車馬過相存。',64,'全唐诗/poet.song.148000.json','["三徑荒凉獨掩門，故人車馬過相存。", "長安此去無千里，濁酒何妨盡一尊。", "共說淵源非曩日，好披肝膽奉明恩。", "不辭妄竊仁人號，執手臨岐敢贈言。"]'),
('e8c2c1c8-fcb2-499d-9d7e-0936939e8e0e','分水鋪壁間讀趙仲縝留題二十字戲續其後','朱熹','宋','宋诗','song-poetry','','[]','水流無彼此，地勢有西東。',24,'全唐诗/poet.song.148000.json','["水流無彼此，地勢有西東。", "若識分時異，方知合處同。"]'),
('43a523f2-0f55-4c6d-9acc-50a520ad0862','次劉明遠宋子飛反招隠韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','先生留落歲時多，氣湧如山不易磨。',32,'全唐诗/poet.song.148000.json','["先生留落歲時多，氣湧如山不易磨。", "却學幽人陶靖節，正緣三徑起絃歌。"]'),
('d9c55515-26e7-4ed1-a4fe-4024172cf561','次劉明遠宋子飛反招隠韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','榮醜窮通祇偶然，未妨閑共聳吟肩。',32,'全唐诗/poet.song.148000.json','["榮醜窮通祇偶然，未妨閑共聳吟肩。", "君能觸處真齊物，我亦平生不怨天。"]'),
('fb3cf6f9-3be9-4689-b673-f79e1baeb352','送謝周輔入廣','朱熹','宋','宋诗','song-poetry','','[]','夫君壯節與奇謀，屈首微官世所羞。',64,'全唐诗/poet.song.148000.json','["夫君壯節與奇謀，屈首微官世所羞。", "攬轡未妨聊矍鑠，賦詩直爲寫離憂。", "蒼茫嶺海三年別，珍重親朋幾日留。", "滿意分携一盃酒，登山臨水不能休。"]'),
('272ad4f1-1eb0-4800-b6dd-33d96d8f4ef0','和亦樂園韻','朱熹','宋','宋诗','song-poetry','','[]','莫笑君家五畝園，要須胸次亦平寬。',64,'全唐诗/poet.song.148000.json','["莫笑君家五畝園，要須胸次亦平寬。", "坐間花柳陰初合，望外山河勢若蟠。", "把酒儘誇雙鬢綠，擊鮮爭見兩輪丹。", "鄰翁未到心先識，更喜詩筒得細觀。"]'),
('2a00ad08-2214-490f-9ef6-0ac42dec19bd','次韻謝劉仲行惠筍二首  其一','朱熹','宋','宋诗','song-poetry','','[]','誰寄寒林新斸筍，開奩喜見白差差。',32,'全唐诗/poet.song.148000.json','["誰寄寒林新斸筍，開奩喜見白差差。", "知君調我酸寒甚，不是封侯食肉姿。"]'),
('0b563d5b-2663-480a-b8b7-b894a04892e7','次韻謝劉仲行惠筍二首  其二','朱熹','宋','宋诗','song-poetry','','[]','君詩高處古無師，島瘦郊寒詎足差。',32,'全唐诗/poet.song.148000.json','["君詩高處古無師，島瘦郊寒詎足差。", "縛得獰龍并寄我，句中仍喜見雄姿。"]'),
('2e8185ec-338a-4ea6-a093-2bece9aa1e49','次季通韻贈范康侯','朱熹','宋','宋诗','song-poetry','','[]','朝霜逼凋梅，夕露忽團菊。',120,'全唐诗/poet.song.148000.json','["朝霜逼凋梅，夕露忽團菊。", "百年風雨過，宜笑不宜哭。", "口川失自防，心兵幾回觸。", "年來身老大，甘此胯下辱。", "永謝五鼎烹，聊寄一瓢足。", "雖慙龍蟠泥，肯羨鶑出谷。", "適意超混茫，放情遺結束。", "俯仰天壤間，靜勝惟我獨。", "蒼蒼有心柏，落落無瑕玉。", "年紀尚無聞，頭顱豈須卜。"]'),
('5be3e27f-bb5f-421d-96cf-c66e32e2b1b5','同張明府登凌風亭懷韓無咎','朱熹','宋','宋诗','song-poetry','','[]','日夕和風至，西山淡無姿。',120,'全唐诗/poet.song.148000.json','["日夕和風至，西山淡無姿。", "危亭極遠眺，勝處良在茲。", "憶昔韓令尹，青雲乃心期。", "鞿覊不得騁，發此胸中奇。", "前瞻千仞岡，俯視萬頃陂。", "神襟一以曠，我志浩渺瀰。", "飛車越滄浪，天風振裳衣。", "懷哉此焉薄，問訊無邊辭。", "今公豈不佳，宮商似前徽。", "相携岸晚幘，共此長相思。"]'),
('baaf1e4e-9154-4d0a-946b-2ef50ab99fc9','次王宰立春日大雪韻','朱熹','宋','宋诗','song-poetry','','[]','是身已分老菟裘，肯爲春回作許愁。',64,'全唐诗/poet.song.148000.json','["是身已分老菟裘，肯爲春回作許愁。", "偶去尋芳朝信馬，却來踏雪夜驅牛。", "鋪筵不見小垂手，聯句空慙高結喉。", "更約桃花紅浪暖，却陪履舄上蘭舟。"]'),
('a8974386-3f69-4ba1-8d95-cfadabd22cc7','再次王宰韻','朱熹','宋','宋诗','song-poetry','','[]','相隨到處一羊裘，况有澄江散客愁。',64,'全唐诗/poet.song.148000.json','["相隨到處一羊裘，况有澄江散客愁。", "且看跳魚并集鳥，莫思去馬與來牛。", "歡情往日空回首，酒味今年不下喉。", "只待兩公高宴罷，却携茶鼎上漁舟。"]'),
('32bd4c9d-f617-478f-bff9-c91b8a3488f1','送張彥輔赴闕','朱熹','宋','宋诗','song-poetry','','[]','執手何草草，送君千里道。',120,'全唐诗/poet.song.148000.json','["執手何草草，送君千里道。", "君行入脩門，披膽謁至尊。", "問君此去談何事，袖有諫書三萬字。", "明堂封禪不要論，智名勇功非所敦。", "願言中興聖天子，脩政攘夷從此始。", "深仁大義天與通，農桑萬里長春風。", "朝綱清夷軍律舉，邊屯不驚卧哮虎。", "一朝决策向中原，著鞭寧許他人先。"]'),
('e3235aee-d632-421b-a7fd-6d071d6dd83b','天湖四乙丈坐間賞梅作送劉充甫平甫如豫章','朱熹','宋','宋诗','song-poetry','','[]','竹外橫枝老屈盤，冰壺遥夜玉窗寒。',32,'全唐诗/poet.song.148000.json','["竹外橫枝老屈盤，冰壺遥夜玉窗寒。", "兩公明日江南路，雪後園林子細看。"]'),
('4a62eb48-a917-485a-b52b-acfb406720c5','哭羅宗約二首  其一','朱熹','宋','宋诗','song-poetry','','[]','江閣論心地，重來感慨多。',48,'全唐诗/poet.song.148000.json','["江閣論心地，重來感慨多。", "故人今已矣，此道竟如何。", "但使窮新得，終當訂舊訛。", "話言雖永隔，吾欲問滄波。"]'),
('7d22090b-a19d-48f2-a811-5a3c1ec220fe','哭羅宗約二首  其二','朱熹','宋','宋诗','song-poetry','','[]','行義追前輩，孤風凜一生。',48,'全唐诗/poet.song.148000.json','["行義追前輩，孤風凜一生。", "子平婚嫁了，元亮去留輕。", "涪萬無歸棹，嚴楊有舊盟。", "空令同社客，生死痛交情。"]'),
('91f1e381-b2b3-4dca-ac92-0851da2bbffe','題米元暉畫','朱熹','宋','宋诗','song-poetry','','[]','楚山直叢叢，木落秋雲起。',24,'全唐诗/poet.song.148000.json','["楚山直叢叢，木落秋雲起。", "向曉一登臺，滄江日千里。"]'),
('434a0a41-00b8-423f-9b33-fb0b1b8623ea','觀劉氏山館壁間所畫四時景物各有深趣因爲六言一絕復以其句爲題作五言四詠  其一','朱熹','宋','宋诗','song-poetry','','[]','絕壑雲浮冉冉，層巖日隠重重。',28,'全唐诗/poet.song.148000.json','["絕壑雲浮冉冉，層巖日隠重重。", "釋子巖中宴坐，行人雪裏迷蹤。"]'),
('c8898331-9a16-42a1-b199-d94a5ae3b8b9','觀劉氏山館壁間所畫四時景物各有深趣因爲六言一絕復以其句爲題作五言四詠  其二','朱熹','宋','宋诗','song-poetry','','[]','頭上山洩雲，脚下雲迷樹。',24,'全唐诗/poet.song.148000.json','["頭上山洩雲，脚下雲迷樹。", "不知春淺深，但見雲來去。"]'),
('4575b99e-b2eb-4f88-b687-66384f67bd13','觀劉氏山館壁間所畫四時景物各有深趣因爲六言一絕復以其句爲題作五言四詠  其三','朱熹','宋','宋诗','song-poetry','','[]','夕陽在西峯，晚谷背南嶺。',24,'全唐诗/poet.song.148000.json','["夕陽在西峯，晚谷背南嶺。", "煩鬰未渠央，佇茲清夜景。"]'),
('229a18f9-ee4c-455f-9526-9e0141d233df','觀劉氏山館壁間所畫四時景物各有深趣因爲六言一絕復以其句爲題作五言四詠  其四','朱熹','宋','宋诗','song-poetry','','[]','清秋氣蕭瑟，遥夜水崩奔。',24,'全唐诗/poet.song.148000.json','["清秋氣蕭瑟，遥夜水崩奔。", "自了巖中趣，無人可共論。"]'),
('7ed2fdfa-3b10-4d66-a121-22d1c985b4aa','觀劉氏山館壁間所畫四時景物各有深趣因爲六言一絕復以其句爲題作五言四詠  其五','朱熹','宋','宋诗','song-poetry','','[]','悲風號萬竅，密雪變千林。',24,'全唐诗/poet.song.148000.json','["悲風號萬竅，密雪變千林。", "匹馬關山路，誰知客子心。"]'),
('5a63d8e1-ed36-49a5-a102-48620781d111','觀祝孝友畫卷爲賦六言一絕復以其句爲題作五言四詠  其一','朱熹','宋','宋诗','song-poetry','','[]','春曉雲山烟樹，炎天雨壑風林。',28,'全唐诗/poet.song.148000.json','["春曉雲山烟樹，炎天雨壑風林。", "江閣月臨靜夜，溪橋雪擁寒襟。"]'),
('cd9def66-3cc0-4579-9f54-d98e12f07bcc','觀祝孝友畫卷爲賦六言一絕復以其句爲題作五言四詠  其二','朱熹','宋','宋诗','song-poetry','','[]','天邊雲繞山，江上烟迷樹。',24,'全唐诗/poet.song.148000.json','["天邊雲繞山，江上烟迷樹。", "不向曉來看，詎知重疊數。"]'),
('2227b35e-677d-4d1f-b061-6af687793802','觀祝孝友畫卷爲賦六言一絕復以其句爲題作五言四詠  其三','朱熹','宋','宋诗','song-poetry','','[]','炎蒸無處逃，亭午轉歊赩。',24,'全唐诗/poet.song.148000.json','["炎蒸無處逃，亭午轉歊赩。", "萬壑一奔傾，千林共蕭瑟。"]'),
('b20a8185-3ce9-4582-9ac8-ceada6b365aa','觀祝孝友畫卷爲賦六言一絕復以其句爲題作五言四詠  其四','朱熹','宋','宋诗','song-poetry','','[]','草閣臨無地，江空秋月寒。',24,'全唐诗/poet.song.148000.json','["草閣臨無地，江空秋月寒。", "亦知奇絕景，未必要人看。"]'),
('b7679ba6-e296-43f3-af6d-0bb60ef9886b','觀祝孝友畫卷爲賦六言一絕復以其句爲題作五言四詠  其五','朱熹','宋','宋诗','song-poetry','','[]','茅屋無烟火，溪橋絕往還。',24,'全唐诗/poet.song.148000.json','["茅屋無烟火，溪橋絕往還。", "山翁獨乘興，飄灑一襟寒。"]'),
('42e5130f-d1af-460e-b5aa-4baa82edfe82','祝孝友作枕屏小景以霜餘茂樹名之因題此詩','朱熹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','山寒夕飆急，木落洞庭波。',24,'全唐诗/poet.song.148000.json','["山寒夕飆急，木落洞庭波。", "幾疊雲屏好，一生秋夢多。"]'),
('c01e50e2-9671-4a43-83f8-2ec0d3f5f04b','傅安道楊儀之二漕勸農有詩次韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','並峙雙臺峻，分馳四牡閑。',48,'全唐诗/poet.song.148000.json','["並峙雙臺峻，分馳四牡閑。", "共欣膏脈潤，未要粉泥乾。", "詩律何妨細，歡情豈遂闌。", "新畬行可問，載酒想同看。"]'),
('abd10331-71c7-441d-9391-3f50b6368d8e','傅安道楊儀之二漕勸農有詩次韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','世味今如許，吾生本自閑。',48,'全唐诗/poet.song.148000.json','["世味今如許，吾生本自閑。", "心期雖好在，欲習未全乾。", "錯莫塵編暗，棲遲壯節闌。", "不因勳業晚，清鏡亦頻看。"]'),
('0904b63d-33df-449d-a0f2-a2885580d66c','感懷','朱熹','宋','宋诗','song-poetry','','[]','經濟夙所尚，隠淪非素期。',48,'全唐诗/poet.song.148000.json','["經濟夙所尚，隠淪非素期。", "幾年霜露感，白髮忽已垂。", "鑿井北山阯，耕田南澗湄。", "乾坤極浩蕩，歲晚將何之。"]'),
('e2cb7918-8fff-4807-beb1-2fe85de89b30','墨莊五詠 墨莊','朱熹','宋','宋诗','song-poetry','','[]','詩書啟山林，德義久儲積。',24,'全唐诗/poet.song.148000.json','["詩書啟山林，德義久儲積。", "嗣世知有人，新畬更開闢。"]'),
('f40a4c81-f6a6-41f9-8845-d042150b2d17','墨莊五詠 冽軒','朱熹','宋','宋诗','song-poetry','','[]','窗開深井泉，窈窕千丈碧。',24,'全唐诗/poet.song.148000.json','["窗開深井泉，窈窕千丈碧。", "何幸且淵澄，無勞遽心惻。"]'),
('be58dcec-2089-4284-8553-82011178696e','墨莊五詠 靜春堂','朱熹','宋','宋诗','song-poetry','','[]','幽人本何心，偶此翳環堵。',24,'全唐诗/poet.song.148000.json','["幽人本何心，偶此翳環堵。", "隠几亦無言，光風遍寰宇。"]'),
('2a524ee1-a7a0-4220-a79b-ca1b3a909f14','墨莊五詠 玩易齋','朱熹','宋','宋诗','song-poetry','','[]','竹几橫陳處，韋編半掩時。',24,'全唐诗/poet.song.148000.json','["竹几橫陳處，韋編半掩時。", "寥寥三古意，此地有深期。"]'),
('2a903688-a540-444b-9731-f09a8130ed1c','墨莊五詠 君子亭','朱熹','宋','宋诗','song-poetry','','[]','倚杖臨寒水，披襟立晚風。',24,'全唐诗/poet.song.148000.json','["倚杖臨寒水，披襟立晚風。", "相逢數君子，爲我說濂翁。"]'),
('a60e8f6f-8079-4645-8932-bc82f116298a','齋居感興二十首  其一','朱熹','宋','宋诗','song-poetry','','[]','昆侖大無外，旁薄下深廣。',72,'全唐诗/poet.song.148000.json','["昆侖大無外，旁薄下深廣。", "陰陽無停機，寒暑互來往。", "皇犧古神聖，妙契一俯仰。", "不待窺馬圖，人文已宣朗。", "渾然一理貫，昭晰非象罔。", "珍重無極翁，爲我重指掌。"]'),
('07320fac-2e87-448a-b6e7-9fc9696214c4','齋居感興二十首  其二','朱熹','宋','宋诗','song-poetry','','[]','吾觀陰陽化，升降八紘中。',48,'全唐诗/poet.song.148000.json','["吾觀陰陽化，升降八紘中。", "前瞻既無始，後際那有終。", "至理諒斯存，萬世與今同。", "誰言混沌死，幻語驚盲聾。"]'),
('e5999172-d282-4252-b021-49a6d91e2af8','齋居感興二十首  其三','朱熹','宋','宋诗','song-poetry','','[]','人心妙不測，出入乘氣機。',72,'全唐诗/poet.song.148000.json','["人心妙不測，出入乘氣機。", "凝冰亦焦火，淵淪復天飛。", "至人乘元化，動靜體無違。", "珠藏澤自媚，玉韞山含暉。", "神光燭九垓，玄思徹萬微。", "塵編今寥落，歎息將安歸。"]'),
('481ed141-f39b-42be-bdef-9a9c7d60ae18','齋居感興二十首  其四','朱熹','宋','宋诗','song-poetry','','[]','靜觀靈臺妙，萬化此從出。',72,'全唐诗/poet.song.148000.json','["靜觀靈臺妙，萬化此從出。", "云胡自蕪穢，反受衆形役。", "厚味紛朶頤，妍姿坐傾國。", "崩奔不自悟，馳騖靡終畢。", "君看穆天子，萬里窮轍迹。", "不有祈招詩，徐方御宸極。"]'),
('ce0f1ab0-0a4b-48b0-a68e-ff7b3c994ddd','齋居感興二十首  其五','朱熹','宋','宋诗','song-poetry','','[]','涇舟膠楚澤，周綱已陵夷。',96,'全唐诗/poet.song.148000.json','["涇舟膠楚澤，周綱已陵夷。", "况復王風降，故宮黍離離。", "玄聖作春秋，哀傷實在茲。", "祥麟一以踣，反袂空漣洏。", "漂淪又百年，僭侯荷爵珪。", "王章久已喪，何復嗟歎爲。", "馬公述孔業，託始有餘悲。", "拳拳信忠厚，無乃迷先幾。"]'),
('267d4659-84cf-4a8b-ad5b-0f53437a75be','齋居感興二十首  其六','朱熹','宋','宋诗','song-poetry','','[]','東京失其御，刑臣弄天綱。',120,'全唐诗/poet.song.148000.json','["東京失其御，刑臣弄天綱。", "西園植姦穢，五族沉忠良。", "青青千里草，乘時起陸梁。", "當塗轉凶悖，炎精遂無光。", "桓桓左將軍，仗鉞西南疆。", "伏龍一奮躍，鳳雛亦飛翔。", "祀漢配彼天，出師驚四方。", "天意竟莫回，王圖不偏昌。", "晉史自帝魏，後賢盍更張。", "世無魯連子，千載徒悲傷。"]'),
('a5c94cae-899a-4964-a6d6-36edde8b47af','齋居感興二十首  其七','朱熹','宋','宋诗','song-poetry','','[]','晉陽啟唐祚，王明紹巢封。',120,'全唐诗/poet.song.148000.json','["晉陽啟唐祚，王明紹巢封。", "垂統已如此，繼體宜昏風。", "麀聚瀆天倫，牝晨司禍凶。", "乾綱一以墜，天樞遂崇崇。", "淫毒穢宸極，虐熖燔蒼穹。", "向非狄張徒，誰辦取日功。", "云何歐陽子，秉筆迷至公。", "唐經亂周紀，凡例孰此容。", "侃侃范太史，受說伊川翁。", "春秋二三策，萬古開羣蒙。"]'),
('0913319e-40cd-4b42-93c0-c037170972b3','齋居感興二十首  其八','朱熹','宋','宋诗','song-poetry','','[]','朱光徧炎宇，微陰眇重淵。',72,'全唐诗/poet.song.148000.json','["朱光徧炎宇，微陰眇重淵。", "寒威閉九野，陽德昭窮泉。", "文明昧謹獨，昏迷有開先。", "幾微諒難忽，善端本綿綿。", "掩身事齋戒，及此防未然。", "閉關息商旅，絕彼柔道牽。"]'),
('f03b21cd-874f-4484-b1b7-b6aa3b04d2ae','齋居感興二十首  其九','朱熹','宋','宋诗','song-poetry','','[]','微月墮西嶺，爛然衆星光。',72,'全唐诗/poet.song.148000.json','["微月墮西嶺，爛然衆星光。", "明河斜未落，斗柄低復昂。", "感此南北極，樞軸遥相當。", "太一有常居，仰瞻獨煌煌。", "中天照四國，三辰環侍旁。", "人心要如此，寂感無邊方。"]'),
('9d7bdaa2-0746-4028-a709-bfc5d7afae74','齋居感興二十首  其一○','朱熹','宋','宋诗','song-poetry','','[]','放勳始欽明，南面亦恭己。',72,'全唐诗/poet.song.148000.json','["放勳始欽明，南面亦恭己。", "大哉精一傳，萬世立人紀。", "猗歟歎日躋，穆穆歌敬止。", "戒獒光武烈，待旦起周禮。", "恭惟千載心，秋月照寒水。", "魯叟何常師，刪述存聖軌。"]'),
('3d26e495-c954-43e0-91c7-78353babd332','齋居感興二十首  其一一','朱熹','宋','宋诗','song-poetry','','[]','吾聞包犧氏，爰初闢乾坤。',72,'全唐诗/poet.song.148000.json','["吾聞包犧氏，爰初闢乾坤。", "乾行配天德，坤布協地文。", "仰觀玄渾周，一息萬里奔。", "俯察方儀靜，隤然千古存。", "悟彼立象意，契此入德門。", "勤行當不息，敬守思彌敦。"]'),
('aa638c83-6fed-4fca-9ae6-c3060f9bd0b5','齋居感興二十首  其一二','朱熹','宋','宋诗','song-poetry','','[]','大易圖象隠，詩書簡編訛。',48,'全唐诗/poet.song.148000.json','["大易圖象隠，詩書簡編訛。", "禮樂矧交喪，春秋魚魯多。", "瑶琴空寶匣，絃絕將如何。", "興言理餘韻，龍門有遺歌。"]'),
('c02445b5-edef-472f-8bb8-83b5bd1308bd','齋居感興二十首  其一三','朱熹','宋','宋诗','song-poetry','','[]','顔生躬四勿，曾子日三省。',72,'全唐诗/poet.song.148000.json','["顔生躬四勿，曾子日三省。", "中庸首謹獨，衣錦思尚絅。", "偉哉鄒孟氏，雄辨極馳騁。", "操存一言要，爲爾挈裘領。", "丹青著明法，今古垂煥炳。", "何事千載餘，無人踐斯境。"]'),
('04223660-2f15-4d63-ba43-c5e1502312cc','齋居感興二十首  其一四','朱熹','宋','宋诗','song-poetry','','[]','元亨播羣品，利真固靈根。',48,'全唐诗/poet.song.148000.json','["元亨播羣品，利真固靈根。", "非誠諒無有，五性實斯存。", "世人逞私見，鑿智道彌昏。", "豈若林居子，幽探萬化原。"]'),
('bcf6c7e9-5928-4812-9b5c-fa892f6605af','齋居感興二十首  其一五','朱熹','宋','宋诗','song-poetry','','[]','飄颻學仙侶，遺世在雲山。',72,'全唐诗/poet.song.148000.json','["飄颻學仙侶，遺世在雲山。", "盜啟元命秘，竊當生死關。", "金鼎蟠龍虎，三年養神丹。", "刀圭一入口，白日生羽翰。", "我欲往從之，脫屣諒非難。", "但恐逆天道，偷生詎能安。"]'),
('25eb9eff-dbb3-40e6-bb0b-83b389eec356','齋居感興二十首  其一六','朱熹','宋','宋诗','song-poetry','','[]','西方論緣業，卑卑喻羣愚。',72,'全唐诗/poet.song.148000.json','["西方論緣業，卑卑喻羣愚。", "流傳世代久，梯接凌空虛。", "顧盻指心性，名言超有無。", "捷徑一以開，靡然世爭趨。", "號空不踐實，躓彼榛棘途。", "誰哉繼三聖，爲我焚其書。"]'),
('b6ce679b-e90a-442d-b9fc-161becf25dcb','齋居感興二十首  其一七','朱熹','宋','宋诗','song-poetry','','[]','聖人司教化，黌序育群材。',72,'全唐诗/poet.song.148000.json','["聖人司教化，黌序育群材。", "因心有明訓，善端得深培。", "天敘既昭陳，人文亦褰開。", "云何百代下，學絕教養乖。", "羣居競葩藻，爭先冠倫魁。", "淳風反淪喪，擾擾胡爲哉。"]'),
('c94a816f-dbbb-4773-91c7-1f4e7645dfde','齋居感興二十首  其一八','朱熹','宋','宋诗','song-poetry','','[]','童蒙貴養正，孫弟乃其方。',96,'全唐诗/poet.song.148000.json','["童蒙貴養正，孫弟乃其方。", "雞鳴咸盥櫛，問訊謹暄凉。", "奉水勤播灑，擁篲周室堂。", "進趨極虔恭，退息常端莊。", "劬書劇嗜炙，見惡逾探湯。", "庸言戒麤誕，時行必安詳。", "聖途雖云遠，發軔且勿忙。", "十五志于學，及時起高翔。"]'),
('a8802c3f-3178-4ec9-b314-c13935cff68a','齋居感興二十首  其一九','朱熹','宋','宋诗','song-poetry','','[]','哀哉牛山木，斤斧日相尋。',72,'全唐诗/poet.song.148000.json','["哀哉牛山木，斤斧日相尋。", "豈無萌蘗在，牛羊復來侵。", "恭惟皇上帝，降此仁義心。", "物欲互攻奪，孤根孰能任。", "反躬艮其背，肅容正冠襟。", "保養方自此，何年秀穹林。"]'),
('2273b6b0-7c90-4c4c-a894-f33cd42c8ebf','齋居感興二十首  其二○','朱熹','宋','宋诗','song-poetry','','[]','玄天幽且默，仲尼欲無言。',72,'全唐诗/poet.song.148000.json','["玄天幽且默，仲尼欲無言。", "動植各生遂，德容自清溫。", "彼哉夸毗子，呫囁徒啾喧。", "但逞言辭好，豈知神監昏。", "曰余昧前訓，坐此枝葉繁。", "發憤永刊落，奇功收一原。"]'),
('3286f658-9d77-4b17-99ad-f674d42ca7e6','卜居','朱熹','宋','宋诗','song-poetry','','[]','卜居屏山下，俯仰三十秋。',144,'全唐诗/poet.song.148000.json','["卜居屏山下，俯仰三十秋。", "終然村墟近，未愜心期幽。", "近聞西山西，深谷開平疇。", "茅茨十數家，清川可行舟。", "風俗頗淳朴，曠土非難求。", "誓捐三徑資，往遂一壑謀。", "伐木南山巔，結廬北山頭。", "耕田東溪岸，濯足西溪流。", "朋來即共歡，客去成孤遊。", "靜有山水樂，而無身世憂。", "著書俟來哲，補過希前脩。", "茲焉畢暮景，何必營菟裘。"]'),
('93c81f16-4db8-41f4-b236-99055057c73f','游武夷以相期拾瑶草分韻賦詩得瑶字','朱熹','宋','宋诗','song-poetry','','[]','秋聲入庭戶，殘暑不敢驕。',120,'全唐诗/poet.song.148000.json','["秋聲入庭戶，殘暑不敢驕。", "起趁汗漫期，兩袂天風飄。", "眷焉此家山，名號列九霄。", "相與一來集，曠然心朗寥。", "棲息共雲屋，追尋喚漁舠。", "一水屢縈回，千峯鬰岧嶢。", "蒼然大隠屏，林端聳孤標。", "下有雲一壑，仙人久相招。", "授我黄素書，贈我英瓊瑶。", "茅茨幾時見，自此遺紛囂。"]'),
('0b07acd4-8f46-467d-a92b-ee148478e068','石子重兄示詩留別次韻爲謝三首  其一','朱熹','宋','宋诗','song-poetry','','[]','此道知君著意深，不嫌枯淡苦難禁。',32,'全唐诗/poet.song.148000.json','["此道知君著意深，不嫌枯淡苦難禁。", "更須涵養鑽研力，彊矯無忘此日心。"]'),
('b849c0b1-bd2b-4fdc-8e54-4cb45db07a20','石子重兄示詩留別次韻爲謝三首  其二','朱熹','宋','宋诗','song-poetry','','[]','克己工夫日用間，知君此意久晞顔。',32,'全唐诗/poet.song.148000.json','["克己工夫日用間，知君此意久晞顔。", "摛文妄意輸朋益，何似書紳有訂頑。"]'),
('724861d6-5e8c-443f-b4e0-42b7b3156236','石子重兄示詩留別次韻爲謝三首  其三','朱熹','宋','宋诗','song-poetry','','[]','喜見薰成百里春，更慙謙誨極諄諄。',32,'全唐诗/poet.song.148000.json','["喜見薰成百里春，更慙謙誨極諄諄。", "願言勉盡精微藴，風俗期君使再醇。"]'),
('f1d4f2e4-8f6e-49a5-ac58-f8b41cf104ed','鵝湖寺和陸子壽','朱熹','宋','宋诗','song-poetry','','[]','德義風流夙所欽，別離三載更關心。',64,'全唐诗/poet.song.148000.json','["德義風流夙所欽，別離三載更關心。", "偶扶藜杖出寒谷，又枉籃輿度遠岑。", "舊學商量加邃密，新知培養轉深沉。", "却愁說到無言處，不信人間有古今。"]'),
('291b6ce3-0cb6-401f-ac35-a6c2652a6c29','奉陪機仲宗正景仁太史期會武夷而文叔茂實二友適自昭武來集相與泛舟九曲周覽巖壑之勝而還機仲景仁唱酬迭作謂僕亦不可以無言也衰病懶廢那復有此勉出數語以塞嘉貺不足爲外人道也','朱熹','宋','宋诗','song-poetry','','[]','此山名自西京傳，丹臺紫府天中天。',160,'全唐诗/poet.song.148000.json','["此山名自西京傳，丹臺紫府天中天。", "似聞雲鶴時降集，應笑磨螘空回旋。", "我來適此秋景晏，青楓葉赤摇寒烟。", "九還七返不易得，千巖萬壑渠能專。", "同遊幸有二三子，天畀此段非徒然。", "梁郎季子山澤臞，傅伯爰盎瀛洲仙。", "相逢相得要彊附，却恨馬腹勞長鞭。", "黄華未和白雪句，畫舸且共清泠川。", "回船罷酒三太息，百歲誰復來通泉。", "盈虛有數豈終極，爲君出此窮愁篇。"]'),
('09782773-7204-44db-9be5-735cd4fc5e47','奉答景仁老兄贈別之句','朱熹','宋','宋诗','song-poetry','','[]','古人一去心不傳，舉世誰復知其天。',162,'全唐诗/poet.song.148000.json','["古人一去心不傳，舉世誰復知其天。", "奔趨嗜欲名利境，浩蕩勢若飄風旋。", "嗟予慨此其已久，矧復痼疾霾雲烟。", "禪關夜扣手剝啄，丹經晝誦心精專。", "十年齊楚得失裏，醉醒夢覺今超然。", "迷心昧性哂竺學，貪生惜死悲方仙。", "如何懶惰行不力，日月逝矣羲和鞭。", "祇今已□遠玄象，羨子正似方來川。", "何憂功名與事業，但要溥博而淵泉。", "不見君家鼻祖開聖學，照耀今古書三篇。"]'),
('4900e5dd-f9af-4698-8474-1e37ee9eb883','復用前韻敬別機仲','朱熹','宋','宋诗','song-poetry','','[]','君家道素幾葉傳，只今用舍懸諸天。',160,'全唐诗/poet.song.148000.json','["君家道素幾葉傳，只今用舍懸諸天。", "屹然砥柱戰河曲，肯似落葉隨風旋。", "奮髯忽作蝟毛磔，浩氣勃若霄中烟。", "隠憂尚喜遺直在，壯烈未許前人專。", "武夷連日聽奇語，令我兩腋風泠然。", "初如茫茫出太極，稍似冉冉隨群仙。", "安能局促夜起舞，下與祖逖爭雄鞭。", "終憐賢屈惜往日，亦念聖孔悲徂川。", "願君盡此一杯酒，預澆舌本如懸泉。", "沃心澤物吾有望，勒移忍繼鍾山篇。"]'),
('bd281cac-d4e9-40a4-bfa5-5469b7663ef8','讀機仲景仁別後詩語因及詩傳綱目復用前韻','朱熹','宋','宋诗','song-poetry','','[]','道有默識無言傳，向來誤矣空談天。',160,'全唐诗/poet.song.148000.json','["道有默識無言傳，向來誤矣空談天。", "只今斷簡窺蠹蝕，似向追蠡看蟲旋。", "始知古人有妙處，未遽秦谷隨飛煙。", "終然世累苦妨奪，下帷發憤那容專。", "一心正爾思鵠至，兩手欲救驚頭然。", "書空且復罷咄咄，屢舞豈暇陪仙仙。", "功名况乃身外事，我馬硉兀甘回鞭。", "解頤果值得水井，鑒古亦會朝宗川。", "兩公知我不罪我，便可築室分林泉。", "十年燈下一夜語，閑日共賦舂容篇。"]'),
('b9228ed5-1b52-4f57-b1f8-08568247465c','讀通鑑紀事本末用武夷唱和元韻寄機仲','朱熹','宋','宋诗','song-poetry','','[]','先生諫疏莫與傳，忠憤激烈號旻天。',160,'全唐诗/poet.song.148000.json','["先生諫疏莫與傳，忠憤激烈號旻天。", "却憐廣文官舍冷，只與文字相周旋。", "上書乞得聊自屏，清坐日對銅爐烟。", "功名馳騖往莫悔，鉛槧職業今當專。", "要將報答陛下聖，矯首北闕還潸然。", "屬詞比事有深意，憑愚護短驚群仙。", "□言未秉太史筆，自幸已執留臺鞭。", "果然敕遣六丁取，香羅漆匣浮桐川。", "陰凝有戒竦皇鑒，陽剝欲盡生玄泉。", "明年定對白虎殿，更誦大學中庸篇。"]'),
('64cb381c-1c9c-44c9-9e5f-34a90772d5a1','拜張魏公墓下','朱熹','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山何巍巍，湘流亦湯湯。',288,'全唐诗/poet.song.148000.json','["衡山何巍巍，湘流亦湯湯。", "我公獨何往，劒履在此堂。", "念昔中興初，孽豎倒冠裳。", "公時首建義，自此扶三綱。", "精忠貫宸極，孤憤摩穹蒼。", "元戎二十萬，一旦先啟行。", "西征奠梁益，南轅撫江湘。", "士心既豫附，國威亦張皇。", "縞素哭新宮，哀聲連萬方。", "黠虜聞褫魄，經營久徬徨。", "玉帛驟往來，士馬且伏藏。", "公謀適不用，拱手遷南荒。", "白首復來歸，髮短丹心長。", "拳拳冀感格，汲汲勤修攘。", "天命竟難諶，人事亦靡常。", "悠然謝台鼎，騎龍白雲鄉。", "坐令此空山，名與日月彰。", "千秋定軍壘，岋嶪遥相望。", "賤子來歲陰，烈風振高岡。", "下馬九頓首，撫膺淚淋浪。", "山頹今幾年，志士日慘傷。", "中原尚腥羶，人類幾豺狼。", "公還浩無期，嗣德煒有光。", "恭惟宋社稷，永永垂無疆。"]'),
('682ea970-7121-4b2e-b145-c1f438afa055','敬簡堂分韻得月字','朱熹','宋','宋诗','song-poetry','','[]','煌煌定方中，農隙孟冬月。',168,'全唐诗/poet.song.148000.json','["煌煌定方中，農隙孟冬月。", "君侯敞齋扉，華榜新未揭。", "我來適茲時，亦有大夫茇。", "清觴不留行，晤語得超越。", "更看雷雨勢，翻動龍蛇窟。", "襟懷頓能輸，肝膽亦已竭。", "老仙來何方，湖海氣硉矹。", "君侯歛袂起，顛越承屨襪。", "坐人驚創見，引去殊卒卒。", "伊余不忍逝，頓首願有謁。", "人生均秉彜，天造豈停歇。", "云何利害判，所較無一髮。", "茲焉辨不早，大本將恐蹷。", "吾言實自箴，君聽未宜忽。"]'),
('4e6dd6f1-7c69-488c-bf21-4f93aa029767','登嶽麓赫曦臺聯句','朱熹','宋','宋诗','song-poetry','','[]','泛舟長沙渚，振策湘山岑。',48,'全唐诗/poet.song.148000.json','["泛舟長沙渚，振策湘山岑。", "煙雲眇變化，宇宙窮高深。", "懷古壯士志，憂時君子心。", "寄言塵中客，莽蒼誰能尋。"]'),
('b6d56c86-68bf-4f98-88ca-56b7025e0868','登定王臺','朱熹','宋','宋诗','song-poetry','','[]','寂寞番君後，光華帝子來。',48,'全唐诗/poet.song.148000.json','["寂寞番君後，光華帝子來。", "千年餘故國，萬事只空臺。", "日月東西見，湖山表裏開。", "從知爽鳩樂，莫作雍門哀。"]'),
('71aed7ac-aa1a-4013-8305-a78520b2ad51','次敬夫登定王臺韻','朱熹','宋','宋诗','song-poetry','','[]','今朝風日好，抱病起登臺。',48,'全唐诗/poet.song.148000.json','["今朝風日好，抱病起登臺。", "山色愁無盡，江波去不回。", "客懷元老草，節物又踈梅。", "且莫催歸騎，憑欄更一杯。"]'),
('006a3ab4-2fa1-4e40-8a5b-5c6b79eeefb3','七日發嶽麓道中尋梅不獲至十日遇雪作此','朱熹','宋','宋诗','song-poetry','','[]','三日山行風繞林，天寒歲暮客愁深。',32,'全唐诗/poet.song.148000.json','["三日山行風繞林，天寒歲暮客愁深。", "心期已悞梅花笑，急雪無端更滿襟。"]'),
('b0430d67-2473-463b-87c8-db737b381bd6','大雪馬上次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','仙人喬嶽頂，散髮吹參差。',144,'全唐诗/poet.song.148000.json','["仙人喬嶽頂，散髮吹參差。", "喚我二三友，集此西南垂。", "列筵命洛公，侑坐迎江妃。", "導之千羽旄，投以萬璧璣。", "繽紛一何麗，晻靄難具知。", "衆真亦來翔，恍覺叢霄低。", "茫茫雲霧合，一一瓊瑶姿。", "回首謝世人，千載空相思。", "吾衰怯雄觀，未敢探此奇。", "短衣一匹馬，幸甚得所隨。", "天寒飲我酒，酒罷賡君詩。", "人生易南北，復此知何時。"]'),
('5ff7a0fd-1ad9-43a2-842d-c60f243f379c','風雪未已决策登山用敬夫春風樓韻','朱熹','宋','宋诗','song-poetry','','[]','披風蘭臺宮，看雨百常觀。',96,'全唐诗/poet.song.148000.json','["披風蘭臺宮，看雨百常觀。", "安知此山雲，對面隔霄漢。", "群陰匝寰區，密雪渺天畔。", "峨峨雪中山，心眼悽欲斷。", "吾人愛奇賞，遽發臨河嘆。", "我知沍寒極，見晛今當泮。", "不須疑吾言，第請視明旦。", "蠟屐得鴈行，籃輿或魚貫。"]'),
('9f66a258-d9e8-4b37-93cd-96e80a4b181d','十三日晨起霜晴前言果驗再用敬夫定王臺韻賦詩','朱熹','宋','宋诗','song-poetry','','[]','北渚無新夢，南山有舊臺。',48,'全唐诗/poet.song.148000.json','["北渚無新夢，南山有舊臺。", "端能成獨往，未肯遽空回。", "磴滑新經雪，林深不見梅。", "急須乘霽色，何必散銀杯。"]'),
('69266c46-46bf-4e81-965c-a54435e6b35a','敬夫用熹定王臺韻賦詩因復次韻','朱熹','宋','宋诗','song-poetry','','[]','新詩通造化，催出火輪來。',48,'全唐诗/poet.song.148000.json','["新詩通造化，催出火輪來。", "雲物低南極，江山接漢臺。", "心期千古迥，懷抱一生開。", "回首狂馳子，紛紛政可哀。"]'),
('17ba1b25-1b48-4b60-8152-3ceee043fb9c','馬上口占次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','幾日城中歌酒昏，今朝匹馬向烟村。',32,'全唐诗/poet.song.148000.json','["幾日城中歌酒昏，今朝匹馬向烟村。", "迎人况有南山色，勝處何妨倒一尊。"]'),
('ce1a6f10-a26a-4a05-be01-d71d2772ac24','馬上舉韓退之話口占','朱熹','宋','宋诗','song-poetry','','[]','昨日風煙接混茫，今朝紫翠插青蒼。',32,'全唐诗/poet.song.148000.json','["昨日風煙接混茫，今朝紫翠插青蒼。", "此心元自通天地，可笑靈宮枉炷香。"]'),
('6338bfd6-6ed1-43ca-b771-bafeb788c36f','雪消溪漲山色尤可喜口占','朱熹','宋','宋诗','song-poetry','','[]','頭上瓊岡出舊青，馬邊流水漲寒汀。',32,'全唐诗/poet.song.148000.json','["頭上瓊岡出舊青，馬邊流水漲寒汀。", "若爲留得晶瑩住，突兀長看素錦屏。"]'),
('f4d59d42-19b2-49e6-9814-c40e5cc52ad9','馬跡橋','朱熹','宋','宋诗','song-poetry','','[]','下馬驅車過野橋，橋西一路上雲霄。',32,'全唐诗/poet.song.148000.json','["下馬驅車過野橋，橋西一路上雲霄。", "我來自有平生志，不用移文遠見招。"]'),
('dc6885ed-0776-4341-8039-aff594ffc6f2','登山有作次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','晚峯雲散碧千尋，落日衝飆霜氣深。',32,'全唐诗/poet.song.148000.json','["晚峯雲散碧千尋，落日衝飆霜氣深。", "霽色登臨寒夜月，行藏只此驗天心。"]'),
('c0ebc546-5d2c-4894-b9ae-7fcb5a37a46b','方廣道中半嶺小憩次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','不用洪崖遠拍肩，相將一笑俯寒烟。',32,'全唐诗/poet.song.148000.json','["不用洪崖遠拍肩，相將一笑俯寒烟。", "向來活計蓬蒿底，浪說江湖極目天。"]'),
('57addce8-88f6-4d57-9b92-8bc0ce9054b1','道中景物甚勝吟賞不暇敬夫有詩因次其韻','朱熹','宋','宋诗','song-poetry','','[]','穿林踏雪覓鍾聲，景物逢迎步步新。',32,'全唐诗/poet.song.148000.json','["穿林踏雪覓鍾聲，景物逢迎步步新。", "隨處留情隨處樂，未妨聊作苦吟人。"]'),
('06baef88-4066-4dad-a178-453f2600ce29','崖邊積雪取食甚清次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','落葉踈林射日光，誰分殘雪許同嘗。',32,'全唐诗/poet.song.148000.json','["落葉踈林射日光，誰分殘雪許同嘗。", "平生願學程夫子，恍憶當年洗俗腸。"]'),
('d89cbd5a-0bce-4b96-af67-aae2ed7f20b7','後洞山口晚賦','朱熹','宋','宋诗','song-poetry','','[]','日落千林外，烟飛紫翠深。',48,'全唐诗/poet.song.148000.json','["日落千林外，烟飛紫翠深。", "寒泉添壑底，積雪尚崖陰。", "景要吾人共，詩留永夜吟。", "從教廣長舌，莫盡此時心。"]'),
('ee2edcd9-0be4-4751-ac12-e580e7503a8b','後洞雪壓竹枝橫道','朱熹','宋','宋诗','song-poetry','','[]','石灘聯騎雪垂垂，已把南山入小詩。',32,'全唐诗/poet.song.148000.json','["石灘聯騎雪垂垂，已把南山入小詩。", "後洞今朝逢折竹，却思聯騎石灘時。"]'),
('1d7e8335-6ed6-40ae-ac49-9b9593cb6df0','方廣奉懷定叟','朱熹','宋','宋诗','song-poetry','','[]','偶來石廩峯頭寺，忽憶畫船齋裏人。',32,'全唐诗/poet.song.148000.json','["偶來石廩峯頭寺，忽憶畫船齋裏人。", "城市山林雖一致，不知何處是真身。"]'),
('cb457ca2-b509-48af-b46a-66e284597b18','方廣聖燈次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','神燈照夜惟聞說，皓月當空不用尋。',32,'全唐诗/poet.song.148000.json','["神燈照夜惟聞說，皓月當空不用尋。", "箇裏忘言真所得，便應從此正人心。"]'),
('430418d4-b962-416e-84ec-a1f06cc3b566','羅漢果次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','目勞足倦登喬嶽，吻燥腸枯到上方。',32,'全唐诗/poet.song.148000.json','["目勞足倦登喬嶽，吻燥腸枯到上方。", "從遣山僧煮羅漢，未妨分我一盃湯。"]'),
('25c96ea3-7e28-460d-abbf-b52ad1121bea','壁間古畫精絕未聞有賞音者','朱熹','宋','宋诗','song-poetry','','[]','老木樛枝入太陰，蒼崖寒水斷追尋。',32,'全唐诗/poet.song.148000.json','["老木樛枝入太陰，蒼崖寒水斷追尋。", "千年粉壁塵埃底，誰識良工獨苦心。"]'),
('6813b82a-48e2-4396-be92-dffd70a07de3','方廣版屋','朱熹','宋','宋诗','song-poetry','','[]','秀木千章倒，層甍萬瓦差。',24,'全唐诗/poet.song.148000.json','["秀木千章倒，層甍萬瓦差。", "悄無人似玉，空詠小戎詩。"]'),
('cc74c7a4-ac08-4cd4-a59e-4f9750a6b531','泉聲次林擇之韻','朱熹','宋','宋诗','song-poetry','','[]','空巖寒水自悲吟，遥夜何人爲賞音。',32,'全唐诗/poet.song.148000.json','["空巖寒水自悲吟，遥夜何人爲賞音。", "此日團欒都聽得，他時離索試追尋。"]'),
('1ae3385e-7131-41d5-a322-e81a65386765','霜月次擇之韻','朱熹','宋','宋诗','song-poetry','','[]','蓮花峯頂雪晴天，虛閣霜清絕縷烟。',32,'全唐诗/poet.song.148000.json','["蓮花峯頂雪晴天，虛閣霜清絕縷烟。", "明發定知花䔩䔩，如今且看竹娟娟。"]'),
('353deb9a-717b-462e-84c1-194deee0ae96','枯木次擇之韻','朱熹','宋','宋诗','song-poetry','','[]','百年蟠木老聱牙，偃蹇春風不肯花。',32,'全唐诗/poet.song.148000.json','["百年蟠木老聱牙，偃蹇春風不肯花。", "人道心情頑似汝，不須持向我儂誇。"]'),
('6c0aa7ff-debb-42c9-b81c-5a1295d2663b','夜宿方廣聞長老守榮化去敬夫感而賦詩因次其韻','朱熹','宋','宋诗','song-poetry','','[]','拈椎豎拂事非真，用力端須日日新。',32,'全唐诗/poet.song.148000.json','["拈椎豎拂事非真，用力端須日日新。", "只麽虛空打筋斗，思君辜負百年身。"]'),
('cf456ab8-5bab-42ae-975d-35eb5a9894a3','蓮花峰次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','月曉風清墮白蓮，世間無物敢爭妍。',32,'全唐诗/poet.song.148000.json','["月曉風清墮白蓮，世間無物敢爭妍。", "如何今夜峯頭雪，撩得新詩續舊篇。"]'),
('3d5104d8-90ac-4e2e-8dcc-e8c27e1e37a6','方廣睡覺次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','風簷雪屋澹無情，巧作寒窗靜夜聲。',32,'全唐诗/poet.song.148000.json','["風簷雪屋澹無情，巧作寒窗靜夜聲。", "倦枕覺來聽不斷，相看渾欲不勝清。"]'),
('935dfba6-a84f-4f35-8806-9f957e5e4062','感尚子平事','朱熹','宋','宋诗','song-poetry','','[]','翩然遠嶽恣遊行，慨想當年尚子平。',32,'全唐诗/poet.song.148000.json','["翩然遠嶽恣遊行，慨想當年尚子平。", "我亦近來知損益，只將懲窒度餘生。"]'),
('c444d533-118d-47b7-ac94-913bb965e799','殘雪未消次擇之韻','朱熹','宋','宋诗','song-poetry','','[]','脚底悲風舞凍鴉，此行真是躡蒼霞。',32,'全唐诗/poet.song.148000.json','["脚底悲風舞凍鴉，此行真是躡蒼霞。", "仰頭若木敷瓊蘂，不是人間玉樹花。"]'),
('4ae0a770-572e-4e1a-a36a-e050838506f2','自方廣過高臺次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','素雪留清壁，蒼霞對赤城。',48,'全唐诗/poet.song.148000.json','["素雪留清壁，蒼霞對赤城。", "我來陰壑晚，人說夜燈明。", "貝葉無新得，蒲人有舊盟。", "咄哉寧負汝，安敢負吾生。"]'),
('324441f4-e9a3-45f9-98a2-d33f06b8e274','石廩峰次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','七十二峰都插天，一峰石廩舊名傳。',32,'全唐诗/poet.song.148000.json','["七十二峰都插天，一峰石廩舊名傳。", "家家有廩高如許，大好人間快活年。"]'),
('004e257d-f4bb-4d8e-979d-7c7a5e1f1d02','行林間幾三十里寒甚道傍有殘火溫酒舉白方覺有暖意次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','千林一路雪毰堆，吟斷饑腸第幾回。',32,'全唐诗/poet.song.148000.json','["千林一路雪毰堆，吟斷饑腸第幾回。", "溫酒正思敲石火，偶逢寒燼得傾杯。"]'),
('27cb6cf6-d161-4a58-b4dd-aa98beb51874','林間殘雪時落鏘然有聲','朱熹','宋','宋诗','song-poetry','','[]','青鞋布襪踏瓊瑶，十里晴林未覺遥。',32,'全唐诗/poet.song.148000.json','["青鞋布襪踏瓊瑶，十里晴林未覺遥。", "忽復空枝墮殘雪，恍疑鳴璬落叢霄。"]'),
('27eab543-625b-4116-b601-070cd5c267e8','至上封用擇之韻','朱熹','宋','宋诗','song-poetry','','[]','疇昔朱陵洞，如今白帝城。',48,'全唐诗/poet.song.148000.json','["疇昔朱陵洞，如今白帝城。", "天高雲共色，夜永月同明。", "萬象爭回巧，千峰盡乞盟。", "登臨須我輩，更約羨門生。"]'),
('32aef181-812a-44d7-9d09-b2f479634e37','福嚴寺回望嶽市','朱熹','宋','宋诗','song-poetry','','[]','昨夜相携看霜月，今朝誰料起寒烟。',32,'全唐诗/poet.song.148000.json','["昨夜相携看霜月，今朝誰料起寒烟。", "安知明日千峰頂，不見人間萬里天。"]'),
('68a5eb31-a6fe-46e7-8390-51f797ec4fbc','福嚴讀張湖南舊詩','朱熹','宋','宋诗','song-poetry','','[]','樓上低回摻別袖，山中磊落見英姿。',32,'全唐诗/poet.song.148000.json','["樓上低回摻別袖，山中磊落見英姿。", "白雲未屬分符客，已有經行到處詩。"]'),
('8c6b549f-48cd-4f80-82b3-b52cf2e46abf','登祝融峰用擇之韻','朱熹','宋','宋诗','song-poetry','','[]','今年緣底事，浪走太無端。',48,'全唐诗/poet.song.148000.json','["今年緣底事，浪走太無端。", "直以心期遠，非貪眼界寬。", "雲山於此盡，風袂不勝寒。", "孤鳥知人意，茫茫去不還。"]'),
('94b46622-a7aa-428c-bba7-3cfaaf572827','穹林閣讀張湖南七月十五夜詩詠歎久之因次其韻','朱熹','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽天下鎮，祝融最高峰。',72,'全唐诗/poet.song.148000.json','["南嶽天下鎮，祝融最高峰。", "仰干幾千仞，俯入一萬重。", "開闢知何年，上有釋梵宮。", "白日照雪屋，清宵響霜鏞。", "極知瓌特觀，仙聖情所鍾。", "雲根有隠訣，讀罷凌長風。"]'),
('deb93560-59a3-44fc-8fa8-b6c1e4e90727','晚霞','朱熹','宋','宋诗','song-poetry','','[]','日落西南第幾峰，斷霞千里抹殘紅。',32,'全唐诗/poet.song.148000.json','["日落西南第幾峰，斷霞千里抹殘紅。", "上方傑閣憑欄處，欲盡餘暉怯晚風。"]'),
('4f12d467-75b8-449f-ae74-0e8326e48c9c','過高臺携信老詩集夜讀上封方丈次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','十年聞說信無言，草草相逢又黯然。',32,'全唐诗/poet.song.148000.json','["十年聞說信無言，草草相逢又黯然。", "借得新詩連夜讀，要從苦淡識清妍。"]'),
('c86641ab-48d6-4614-a22d-d5d26bfa7d81','贈上封諸老','朱熹','宋','宋诗','song-poetry','','[]','夜宿上封寺，翛然塵慮清。',48,'全唐诗/poet.song.148000.json','["夜宿上封寺，翛然塵慮清。", "月明殘雪裏，泉溜隔窗聲。", "楮衲今如許，綈袍那復情。", "爐紅虛室暖，聊得話平生。"]'),
('5a39013c-3bcf-4b7d-8737-83d70875eac2','自上封登祝融峰絕頂次敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','衡嶽千仞起，祝融一峰高。',144,'全唐诗/poet.song.148000.json','["衡嶽千仞起，祝融一峰高。", "群山畏突兀，奔走如曹逃。", "我來雪月中，歷覽快所遭。", "捫天滑青壁，俯壑崩銀濤。", "所恨無十犗，一掣了六鼇。", "遄歸青蓮宮，坐對白玉毫。", "重閣一徙倚，霜風利如刀。", "平生山水心，真作貨食饕。", "明朝更清澈，再往豈憚勞。", "中宵撫世故，劇如千蝟毛。", "嬉遊亦何益，歲月今滔滔。", "起望東北雲，茫然首空搔。"]'),
('378f7b37-c74b-47f8-98d3-bf33d6d1ea10','十五日再登祝融用臺字韻','朱熹','宋','宋诗','song-poetry','','[]','江流圍玉界，天影抱瓊臺。',48,'全唐诗/poet.song.148000.json','["江流圍玉界，天影抱瓊臺。", "拄杖烟霄外，中巖日月回。", "箕山藏遁許，吳市隠仙梅。", "一笑今何在，相期再舉杯。"]'),
('fd0fc3b1-8f04-41ee-b4b8-d43a64710a43','胡丈廣仲與范伯崇自嶽市來同登絕頂舉酒極談得聞比日講論之樂','朱熹','宋','宋诗','song-poetry','','[]','我已中峰住，君從何處來。',48,'全唐诗/poet.song.148000.json','["我已中峰住，君從何處來。", "莫留巖底寺，徑上月邊臺。", "濁酒團欒坐，高談次第開。", "前賢渺安在，清酹寄餘哀。"]'),
('d50a4643-4e3a-4771-9886-bb38af63cc51','醉下祝融峰作','朱熹','宋','宋诗','song-poetry','','[]','我來萬里駕長風，絕壑層雲許盪胸。',32,'全唐诗/poet.song.148000.json','["我來萬里駕長風，絕壑層雲許盪胸。", "濁酒三杯豪氣發，朗吟飛下祝融峰。"]'),
('6990a0dc-ed12-449c-81da-3688a7f7f4fe','十六日下山各賦一篇仍迭和韻','朱熹','宋','宋诗','song-poetry','','[]','絕頂來還晚，寒窗睡達明。',48,'全唐诗/poet.song.148000.json','["絕頂來還晚，寒窗睡達明。", "連床眇歸思，三宿悵餘情。", "雲合山無路，風回雪有聲。", "嶽祇珍重意，只此是將迎。"]'),
('5f934f96-2d55-4fcf-b289-9e823336c66e','和敬夫韻','朱熹','宋','宋诗','song-poetry','','[]','蠟屐風煙隨處別，下山人事一番新。',32,'全唐诗/poet.song.148000.json','["蠟屐風煙隨處別，下山人事一番新。", "世間不但山中好，今日方知此意真。"]'),
('6c1119f5-c384-4dc9-8bf9-ab07cf487fcb','和擇之韻','朱熹','宋','宋诗','song-poetry','','[]','仰止平生舊，今年得得來。',48,'全唐诗/poet.song.148000.json','["仰止平生舊，今年得得來。", "舉頭天一握，倚杖雪千堆。", "講道心如渴，哦詩思湧雷。", "出山遺語在，歸騎莫徘徊。"]'),
('43170c5e-c29d-4f7c-a9b6-bfe4ef6beca9','二詩奉酬敬夫贈言并以爲別  其一','朱熹','宋','宋诗','song-poetry','','[]','我行二千里，訪子南山陰。',120,'全唐诗/poet.song.148000.json','["我行二千里，訪子南山陰。", "不憂天風寒，况憚湘水深。", "辭家仲秋旦，稅駕九月初。", "問此爲何時，嚴冬歲云徂。", "勞君步玉趾，送我登南山。", "南山高不極，雪深路漫漫。", "泥行復幾程，今夕宿櫧洲。", "明當分背去，惆悵不得留。", "誦君贈我詩，三歎增綢繆。", "厚意不敢忘，爲君商聲謳。"]'),
('351f44c8-21f9-46a7-8ac4-5b880c0ac28f','二詩奉酬敬夫贈言并以爲別  其二','朱熹','宋','宋诗','song-poetry','','[]','昔我抱冰炭，從君識乾坤。',120,'全唐诗/poet.song.148000.json','["昔我抱冰炭，從君識乾坤。", "始知太極藴，要眇難名論。", "謂有寧有跡，謂無復何存。", "惟應酬酢處，特達見本根。", "萬化自此流，千聖同茲源。", "曠然遠莫禦，惕若初不煩。", "云何學力微，未勝物欲昏。", "涓涓始欲達，已被黄流吞。", "豈知一寸膠，救此千丈渾。", "勉哉共無斁，此語期相敦。"]'),
('d1948e38-7164-47d2-bfcf-e523425293eb','讀林擇之二詩有感  其一','朱熹','宋','宋诗','song-poetry','','[]','筍輿隨望入寒烟，每誦君詩輒黯然。',32,'全唐诗/poet.song.148000.json','["筍輿隨望入寒烟，每誦君詩輒黯然。", "今夜定知連榻夢，一時飛墮錫山前。"]'),
('8b447d4d-6645-451b-889d-29b905567482','讀林擇之二詩有感  其二','朱熹','宋','宋诗','song-poetry','','[]','竹輿傲兀聽嘔啞，合眼歸心已到家。',32,'全唐诗/poet.song.148000.json','["竹輿傲兀聽嘔啞，合眼歸心已到家。", "遊子上堂慈母笑，豈知行李尚天涯。"]'),
('d4b303dd-857b-446f-96b9-cbb72eb57feb','馬上贈林擇之','朱熹','宋','宋诗','song-poetry','','[]','與君歸思渺悠哉，馬上看山首共回。',32,'全唐诗/poet.song.148000.json','["與君歸思渺悠哉，馬上看山首共回。", "認取山中奇絕處，他年無事要重來。"]'),
('219c3609-a9cb-4ad1-8919-ae4271150641','梅溪陂下作','朱熹','宋','宋诗','song-poetry','','[]','野牛浮鼻過寒溪，落木萷椮水下陂。',32,'全唐诗/poet.song.148000.json','["野牛浮鼻過寒溪，落木萷椮水下陂。", "俗手定應摹不得，無人說與范牛知。"]'),
('5541c391-4706-48e5-af5a-8a73dfc7ecc6','寄題李東老淵乎齋','朱熹','宋','宋诗','song-poetry','','[]','東老幽棲地，淵乎亦妙哉。',72,'全唐诗/poet.song.148000.json','["東老幽棲地，淵乎亦妙哉。", "空山無客到，流水有花開。", "句律今誰敵，詩仙舊所陪。", "朱絃悄餘韻，綺席澹浮埃。", "竟日門多掩，長沙歲一來。", "端能負猿鶴，歸計莫徘徊。"]'),
('8be13ee4-7d32-4768-9ca6-163f06515479','宿梅溪胡氏客館觀壁間題詩自警二絕  其一','朱熹','宋','宋诗','song-poetry','','[]','貪生莝豆不知羞，靦面重來躡俊遊。',32,'全唐诗/poet.song.148000.json','["貪生莝豆不知羞，靦面重來躡俊遊。", "莫向清流浣衣袂，恐君衣袂涴清流。"]'),
('1e5b2e34-5a64-489c-a5cb-50bf69679250','宿梅溪胡氏客館觀壁間題詩自警二絕  其二','朱熹','宋','宋诗','song-poetry','','[]','十年湖海一身輕，歸對黎渦却有情。',32,'全唐诗/poet.song.148000.json','["十年湖海一身輕，歸對黎渦却有情。", "世路無如人欲險，幾人到此誤平生。"]'),
('ff301a75-bd35-44d4-bde5-a5a423823161','擇之所和生字韻語極警切次韻謝之兼呈伯崇','朱熹','宋','宋诗','song-poetry','','[]','不是譏訶語太輕，題詩只要警流情。',32,'全唐诗/poet.song.148000.json','["不是譏訶語太輕，題詩只要警流情。", "煩君屬和增危惕，虎尾春冰寄此生。"]'),
('776979d5-3cbe-476c-8659-48894d587aad','再答擇之','朱熹','宋','宋诗','song-poetry','','[]','兢惕如君不自輕，世紛何處得關情。',32,'全唐诗/poet.song.148000.json','["兢惕如君不自輕，世紛何處得關情。", "也應妙敬無窮意，雪未消時草已生。"]'),
('1a4ec85f-6e2f-4bc8-83c8-0974bf207b65','十一月二十六日宿萍鄉西三十餘里黄花渡口客舍稍明潔有宋亨伯題詩亦頗不俗因錄而和之','朱熹','宋','宋诗','song-poetry','','[]','鼎足爐邊坐，陶然共一樽。',48,'全唐诗/poet.song.148000.json','["鼎足爐邊坐，陶然共一樽。", "道心元自勝，世味不須論。", "安穩三更睡，清明一氣存。", "雖無康樂句，聊爾慰營魂。"]'),
('c503a2e6-d49a-4830-a3bf-5c6b0edd052a','二十七日過毛山鋪壁間題詩者皆言有毛女洞在山絕頂問之驛吏云狐魅所爲耳因作此詩','朱熹','宋','宋诗','song-poetry','','[]','人言毛女住青冥，散髮吹簫夜夜聲。',32,'全唐诗/poet.song.148000.json','["人言毛女住青冥，散髮吹簫夜夜聲。", "却是郵童解端的，向儂說是野狐精。"]'),
('7d1bd26c-5b7b-4065-b7ce-08ddcccf1e66','次擇之韻聊紀秦事','朱熹','宋','宋诗','song-poetry','','[]','不知四海已揚湯，舞殿歌臺樂未央。',64,'全唐诗/poet.song.148000.json','["不知四海已揚湯，舞殿歌臺樂未央。", "五帝威神等牛馬，六王子女盡嬪嬙。", "仙心久已攀姑射，辨口從教泣華陽。", "行客詎明千古意，虛疑霞佩響琳琅。"]'),
('e7df5326-7b05-43a0-bafa-fb3fd96dc60f','雪梅二闋奉懷敬夫  其一','朱熹','宋','宋诗','song-poetry','','[]','雲垂幕陰風，慘淡天花落。',56,'全唐诗/poet.song.148000.json','["雲垂幕陰風，慘淡天花落。", "天花落，千林瓊玖，一空鸞鶴。", "征車渺渺穿華薄，路迷迷路增離索。", "增離索，剡溪山水，碧湘樓閣。"]'),
('3529c3e5-8ccb-4251-b918-b47f8e101851','雪梅二闋奉懷敬夫  其二','朱熹','宋','宋诗','song-poetry','','[]','梅花發寒梢，掛著瑶臺月。',56,'全唐诗/poet.song.148000.json','["梅花發寒梢，掛著瑶臺月。", "瑶臺月，和羹心事，履霜時節。", "野橋流水聲嗚咽，行人立馬空愁絕。", "空愁絕，爲誰凝佇，爲誰攀折。"]'),
('dad45751-d4de-46ce-9b01-3c8165e0c48c','題二闋後自是不復作矣','朱熹','宋','宋诗','song-poetry','','[]','久惡繁哇混太和，云何今日自吟哦。',32,'全唐诗/poet.song.148000.json','["久惡繁哇混太和，云何今日自吟哦。", "世間萬事皆如此，兩葉行將用斧柯。"]'),
('2da91f36-1f78-4d9a-b976-56ca0e796fb2','次韻擇之聽話','朱熹','宋','宋诗','song-poetry','','[]','語道深慙話一場，感君親切爲宣揚。',32,'全唐诗/poet.song.148000.json','["語道深慙話一場，感君親切爲宣揚。", "更將充擴隨鈎索，意味從今積漸長。"]'),
('32090d12-b452-4bb3-9e1c-bd5044dcce3c','次韻伯崇自警二首  其一','朱熹','宋','宋诗','song-poetry','','[]','十載相期事業新，云何猶歎未成身。',32,'全唐诗/poet.song.148000.json','["十載相期事業新，云何猶歎未成身。", "流光易失如翻水，莫是因循誤得人。"]'),
('961b3a8f-ce70-4db7-9fc4-1adfba0f7ccf','次韻伯崇自警二首  其二','朱熹','宋','宋诗','song-poetry','','[]','誦君佳句極優柔，未得明彊是所憂。',32,'全唐诗/poet.song.148000.json','["誦君佳句極優柔，未得明彊是所憂。", "若悟本來非木石，保君弘毅不能休。"]'),
('18fc63ac-481e-44cd-bb0d-1225eee84345','奉答擇之四詩意到即書不及次韻  其一','朱熹','宋','宋诗','song-poetry','','[]','爲閔人疲上馬行，此時消息儘分明。',32,'全唐诗/poet.song.148000.json','["爲閔人疲上馬行，此時消息儘分明。", "更憐跣足無衣苦，充此直教天下平。"]'),
('2d98e2cd-cc9f-45ed-8765-cd6eca6ea7f7','奉答擇之四詩意到即書不及次韻  其二','朱熹','宋','宋诗','song-poetry','','[]','君看灞橋風雪中，南來北去莽何窮。',32,'全唐诗/poet.song.148000.json','["君看灞橋風雪中，南來北去莽何窮。", "想應亦有還家客，便爾譏訶恐未公。"]'),
('371eb37b-e5ce-436d-b644-7b9d6b1724d4','奉答擇之四詩意到即書不及次韻  其三','朱熹','宋','宋诗','song-poetry','','[]','東頭不見西頭是，南畔唯嫌北畔非。',32,'全唐诗/poet.song.148000.json','["東頭不見西頭是，南畔唯嫌北畔非。", "多謝聖門傳大學，直將絜矩露天機。"]'),
('4a067f88-36d7-41ad-8f4f-6bddc42b8abe','奉答擇之四詩意到即書不及次韻  其四','朱熹','宋','宋诗','song-poetry','','[]','安肆真同鴆毒科，君言雖苦未傷和。',32,'全唐诗/poet.song.148000.json','["安肆真同鴆毒科，君言雖苦未傷和。", "解嘲却是生回互，政恐紛紛事轉多。"]'),
('46018c2c-b179-487e-98fa-3ae9886b3d1d','答擇之','朱熹','宋','宋诗','song-poetry','','[]','長言三復儘溫純，妙處知君又日新。',32,'全唐诗/poet.song.148000.json','["長言三復儘溫純，妙處知君又日新。", "我亦平生傷褊迫，期君苦口却諄諄。"]'),
('6b1ff288-4435-4e87-9b1f-7295e82ae46f','次韻擇之見路傍亂草有感','朱熹','宋','宋诗','song-poetry','','[]','世間無處不陽春，道路何曾困得人。',32,'全唐诗/poet.song.148000.json','["世間無處不陽春，道路何曾困得人。", "若向此中生厭斁，不知何處可安身。"]'),
('1af5fcd1-20b9-4948-89ec-7f451587ebe6','到袁州二首  其一','朱熹','宋','宋诗','song-poetry','','[]','馬蹄今日到袁州，山木蕭椮四面愁。',32,'全唐诗/poet.song.148000.json','["馬蹄今日到袁州，山木蕭椮四面愁。", "多謝晚來風力勁，朔雲寒日共悠悠。"]'),
('efd4aa60-448e-40b8-a6e5-359f537e963c','到袁州二首  其二','朱熹','宋','宋诗','song-poetry','','[]','袁州刺史幾何人，韓李流芳獨未泯。',32,'全唐诗/poet.song.148000.json','["袁州刺史幾何人，韓李流芳獨未泯。", "道喪時危今日意，九原遺恨一時新。"]'),
('d048d1b0-a806-482b-9649-2dd46a44f6b8','十二月旦袁州道中作','朱熹','宋','宋诗','song-poetry','','[]','今朝已是臘嘉平，我獨胡爲在遠行。',32,'全唐诗/poet.song.148000.json','["今朝已是臘嘉平，我獨胡爲在遠行。", "白髮倚閭應注想，青山聯騎若爲情。"]'),
('c7fb0e2f-79c3-411c-92b2-dc0ded4e4d2b','同林擇之范伯崇歸自湖南袁州道中多奇峰秀木怪石清泉請人賦一篇','朱熹','宋','宋诗','song-poetry','','[]','我行宜春野，四顧多奇山。',72,'全唐诗/poet.song.148000.json','["我行宜春野，四顧多奇山。", "攢巒不可數，峭絕誰能攀。", "上有青葱木，下有清泠灣。", "更憐灣頭石，一一神所剜。", "衆目共遺棄，千秋保堅頑。", "我獨抱孤賞，喟然起長嘆。"]'),
('69bea22f-0edc-4b86-8e10-e10f5da7f32e','賦歸雲洞','朱熹','宋','宋诗','song-poetry','','[]','人生信多患，吾道初不窮。',120,'全唐诗/poet.song.148000.json','["人生信多患，吾道初不窮。", "云何感慨士，伏死嵁巖中。", "宜陽古道周，竅石何嵌空。", "窮幽歷肺腑，履坦開房櫳。", "頗疑有畸人，往昔寄此宮。", "歲月詎云幾，井竈無遺蹤。", "我來記清秋，歸塗渺窮冬。", "興懷重幽討，永嘯回長風。", "風回雲氣歸，洞口春濛濛。", "信美非人境，出門吾欲東。"]'),
('35857bd1-6e37-4090-a060-365cea88da71','人言石乳洪羊之勝不及往遊作此','朱熹','宋','宋诗','song-poetry','','[]','人道歸雲未足誇，洪羊石乳更谽谺。',32,'全唐诗/poet.song.148000.json','["人道歸雲未足誇，洪羊石乳更谽谺。", "連環入夢難紆軫，回首西風又日斜。"]'),
('92c3efa4-5aad-4e7b-aef6-35c6c81b1745','分宜晚泊江亭望南山之勝絕江往遊將還而舟子不至擇之刺船徑渡呼之予與伯崇佇立以俟因得二絕  其一','朱熹','宋','宋诗','song-poetry','','[]','寒水粼粼受晚風，輕舠來往思無窮。',32,'全唐诗/poet.song.148000.json','["寒水粼粼受晚風，輕舠來往思無窮。", "何妨也向溪南去，徙倚空林暮藹中。"]'),
('ac9ce78d-97b8-4132-8e59-2495319a74c0','分宜晚泊江亭望南山之勝絕江往遊將還而舟子不至擇之刺船徑渡呼之予與伯崇佇立以俟因得二絕  其二','朱熹','宋','宋诗','song-poetry','','[]','一棹翩然喚不回，兩筇江畔久徘徊。',32,'全唐诗/poet.song.148000.json','["一棹翩然喚不回，兩筇江畔久徘徊。", "早知君有如神技，同下中流亦快哉。"]'),
('29b782b0-1035-42aa-9bce-0b1348b95c8b','新喻西境','朱熹','宋','宋诗','song-poetry','','[]','北嶺蒼茫雨欲來，南山騰躑翠成堆。',64,'全唐诗/poet.song.148000.json','["北嶺蒼茫雨欲來，南山騰躑翠成堆。", "穉杉繞麓千旗卷，野水涵空一鑑開。", "客路情懷元倥傯，今晨遊眺却徘徊。", "自然觸目成佳句，雲錦無勞更剪裁。"]'),
('128c39c3-876a-43d9-8aac-47692fe6337d','道間厭苦泥淖思亟還家安坐講習用擇之韻呈二賢友','朱熹','宋','宋诗','song-poetry','','[]','客路泥塗正所憂，可堪雲物更油油。',64,'全唐诗/poet.song.148000.json','["客路泥塗正所憂，可堪雲物更油油。", "向來結友輕千里，此去還家且一丘。", "妙處自應從我得，躬行肯使歎吾猶。", "兩賢定許相提挈，厚意何勝雜珮酬。"]'),
('afbfac6d-48cf-4267-bd2c-db77d8a8a999','再和油字韻','朱熹','宋','宋诗','song-poetry','','[]','楚山黄落正離憂，喜見寒杉卷碧油。',64,'全唐诗/poet.song.148000.json','["楚山黄落正離憂，喜見寒杉卷碧油。", "倦客今年真白髮，羽人何日定丹丘。", "奇兵捷出吾當避，狹路爭先子不猶。", "箇裏竟能無一語，應慙二鳥起相酬。"]'),
('cd940788-65b7-4e1f-99dc-aa3e0aab36f7','次韻擇之懷張敬夫','朱熹','宋','宋诗','song-poetry','','["\u8861\u5c71"]','往時聯騎向衡山，同賦新詩各據鞍。',32,'全唐诗/poet.song.148000.json','["往時聯騎向衡山，同賦新詩各據鞍。", "此夜相思一杯酒，回頭猶記雪漫漫。"]'),
('7e9480eb-61d5-4620-aee8-c273264a8469','別韻賦一篇','朱熹','宋','宋诗','song-poetry','','[]','踏雪凌霜眼界新，舉鞭遥指玉嶙峋。',32,'全唐诗/poet.song.148000.json','["踏雪凌霜眼界新，舉鞭遥指玉嶙峋。", "回頭此日成千里，橫槊思君少一人。"]'),
('e83d48a9-e111-44df-8b05-2242447abdd4','宿新喻驛夜聞風鐸','朱熹','宋','宋诗','song-poetry','','[]','倦枕欹眠到五更，却嫌風鐸久悲鳴。',32,'全唐诗/poet.song.148000.json','["倦枕欹眠到五更，却嫌風鐸久悲鳴。", "恍疑絺綌南鄰夜，寒鐵丁東客夢驚。"]'),
('d8e52cb3-c872-4f0c-9b20-3ed7e86da9a4','題野人家','朱熹','宋','宋诗','song-poetry','','[]','茅簷竹落野人家，只麽悠悠閲歲華。',32,'全唐诗/poet.song.148000.json','["茅簷竹落野人家，只麽悠悠閲歲華。", "田父把犁寒雨足，牧兒吹笛晚風斜。"]'),
('d7e00ba7-5d20-44b2-8d58-d48967f17c9e','題萬安野館','朱熹','宋','宋诗','song-poetry','','[]','身似孤雲去復還，投裝猶記此窗間。',32,'全唐诗/poet.song.148000.json','["身似孤雲去復還，投裝猶記此窗間。", "只應烟雨蒼茫外，即是當時萬疊山。"]'),
('52479c19-d5af-4a7a-91ec-0e60e1efa108','萬安遇長沙便欲附書不果','朱熹','宋','宋诗','song-poetry','','[]','長沙一別兩悠悠，夢想清湘带橘洲。',32,'全唐诗/poet.song.148000.json','["長沙一別兩悠悠，夢想清湘带橘洲。", "欲寄行人數行字，行人不作置書郵。"]'),
('dd919f98-fcab-4a44-9bd7-1a976392d03e','不見梅再用來字韻','朱熹','宋','宋诗','song-poetry','','[]','舊歲將除新歲來，梅花長是雪毰堆。',64,'全唐诗/poet.song.148000.json','["舊歲將除新歲來，梅花長是雪毰堆。", "如何此日三州路，不見寒葩一樹開。", "野水風烟迷慘澹，故園霜月想徘徊。", "夜窗却恐勞幽夢，速把新詩取次栽。"]'),
('1fa4b0ff-c196-4009-a9f1-105d9174f508','賦水仙花','朱熹','宋','宋诗','song-poetry','','[]','隆冬凋百卉，江梅厲孤芳。',120,'全唐诗/poet.song.148000.json','["隆冬凋百卉，江梅厲孤芳。", "如何蓬艾底，亦有春風香。", "紛敷翠羽帔，溫靘白玉相。", "黄冠表獨立，淡然水仙裝。", "弱植愧蘭蓀，高操摧冰霜。", "湘君謝遺楪，漢水羞捐璫。", "嗟彼世俗人，欲火焚衷腸。", "徒知慕佳冶，詎識懷貞剛。", "凄凉柏舟誓，惻愴終風章。", "卓哉有遺烈，千載不可忘。"]'),
('1a7f4081-ed59-4f79-b9c6-372b53f73cec','清江道中見梅','朱熹','宋','宋诗','song-poetry','','[]','今日清江路，寒梅第一枝。',48,'全唐诗/poet.song.148000.json','["今日清江路，寒梅第一枝。", "不愁風嫋嫋，正奈雪垂垂。", "煖熱惟須酒，平章却要詩。", "他年千里夢，誰與寄相思。"]'),
('47cbda51-17ee-4097-b327-d9e69afc6ec0','臨江買舟','朱熹','宋','宋诗','song-poetry','','[]','征驂聊駐近江樓，南市津頭問買舟。',32,'全唐诗/poet.song.148000.json','["征驂聊駐近江樓，南市津頭問買舟。", "共說明朝乘雪水，長歌一日到洪州。"]'),
('fb28484d-e259-4c40-89d1-3075b8fe6057','薌林','朱熹','宋','宋诗','song-poetry','','[]','東臯濺寒水，西崦饒清陰。',168,'全唐诗/poet.song.148000.json','["東臯濺寒水，西崦饒清陰。", "南埭奎壁麗，北垞靜且深。", "入門流綠波，竹樹何箾椮。", "積石象雲壑，高堂杳沉沉。", "左通雲水區，右徑梅杏林。", "沼沚共回薄，觀臺鬰差參。", "紛吾千里遊，發軔南山岑。", "過門得佳賞，慰此夙昔心。", "緬懷企疏翁，歲晚投冠籫。", "婆娑此澗谷，俯仰成古今。", "嗣德世有人，聞道我所欽。", "相見無雜語，晤言寫胸襟。", "懷舊復惆悵，命酒聊同斟。", "飲罷我當去，握手清江潯。"]');
